-- main.bi_db.gold_bi_db_bi_db_positionpnl (TABLE, 26 columns)
ALTER TABLE main.bi_db.gold_bi_db_bi_db_positionpnl ALTER COLUMN `CID` COMMENT 'Customer identifier for the position. (Tier 2 -- SP_PositionPnL, DWH_dbo.Dim_Position.CID)';
ALTER TABLE main.bi_db.gold_bi_db_bi_db_positionpnl ALTER COLUMN `PositionID` COMMENT 'Unique position key; Synapse distribution key. (Tier 2 -- SP_PositionPnL, DWH_dbo.Dim_Position.PositionID)';
ALTER TABLE main.bi_db.gold_bi_db_bi_db_positionpnl ALTER COLUMN `InstrumentID` COMMENT 'Traded instrument. (Tier 2 -- SP_PositionPnL, DWH_dbo.Dim_Position.InstrumentID)';
ALTER TABLE main.bi_db.gold_bi_db_bi_db_positionpnl ALTER COLUMN `MirrorID` COMMENT 'Copy-trading mirror link when applicable. (Tier 2 -- SP_PositionPnL, DWH_dbo.Dim_Position.MirrorID)';
ALTER TABLE main.bi_db.gold_bi_db_bi_db_positionpnl ALTER COLUMN `Commission` COMMENT 'Opening commission in dollars. (Tier 2 -- SP_PositionPnL, DWH_dbo.Dim_Position.Commission)';
ALTER TABLE main.bi_db.gold_bi_db_bi_db_positionpnl ALTER COLUMN `InitForexRate` COMMENT 'Open rate; split-adjusted in SP when position spans a split. (Tier 2 -- SP_PositionPnL, DWH_dbo.Dim_Position.InitForexRate / split logic)';
ALTER TABLE main.bi_db.gold_bi_db_bi_db_positionpnl ALTER COLUMN `SpreadedPipBid` COMMENT 'Bid with spread at open. (Tier 2 -- SP_PositionPnL, DWH_dbo.Dim_Position.SpreadedPipBid)';
ALTER TABLE main.bi_db.gold_bi_db_bi_db_positionpnl ALTER COLUMN `SpreadedPipAsk` COMMENT 'Ask with spread at open. (Tier 2 -- SP_PositionPnL, DWH_dbo.Dim_Position.SpreadedPipAsk)';
ALTER TABLE main.bi_db.gold_bi_db_bi_db_positionpnl ALTER COLUMN `PositionPnL` COMMENT 'Unrealized P&L in USD; from `PnLInDollars` (replaces legacy formula). (Tier 2 -- SP_PositionPnL, DWH_dbo.Dim_Position.PnLInDollars)';
ALTER TABLE main.bi_db.gold_bi_db_bi_db_positionpnl ALTER COLUMN `Price` COMMENT 'Per-unit price-move expression × USD conversion factor from `#Pre_UnrealizedPnL` (bid/ask vs InitForexRate and instrument FX chain). (Tier 2 -- SP_PositionPnL, computed from #OpenPositions + Dim_Instrument + #Prices)';
ALTER TABLE main.bi_db.gold_bi_db_bi_db_positionpnl ALTER COLUMN `HedgeServerID` COMMENT 'Hedge server for the position. (Tier 2 -- SP_PositionPnL, DWH_dbo.Dim_Position.HedgeServerID)';
ALTER TABLE main.bi_db.gold_bi_db_bi_db_positionpnl ALTER COLUMN `Amount` COMMENT 'Position amount in USD; rewound via `Dim_PositionChangeLog` when SL/partial-close edits after `@dt`. (Tier 2 -- SP_PositionPnL, DWH_dbo.Dim_Position.Amount / PositionChangeLog.PreviousAmount)';
ALTER TABLE main.bi_db.gold_bi_db_bi_db_positionpnl ALTER COLUMN `AmountInUnitsDecimal` COMMENT 'Size in instrument units; split-adjusted and rewound from partial-close log when applicable. (Tier 2 -- SP_PositionPnL, DWH_dbo.Dim_Position.AmountInUnitsDecimal / split + PositionChangeLog)';
ALTER TABLE main.bi_db.gold_bi_db_bi_db_positionpnl ALTER COLUMN `LimitRate` COMMENT 'Take-profit rate. (Tier 2 -- SP_PositionPnL, DWH_dbo.Dim_Position.LimitRate)';
ALTER TABLE main.bi_db.gold_bi_db_bi_db_positionpnl ALTER COLUMN `StopRate` COMMENT 'Stop-loss rate; rewound to `PreviousStopRate` when edited after `@dt`. (Tier 2 -- SP_PositionPnL, DWH_dbo.Dim_Position.StopRate / PositionChangeLog)';
ALTER TABLE main.bi_db.gold_bi_db_bi_db_positionpnl ALTER COLUMN `IsBuy` COMMENT 'Long (1) vs short (0). (Tier 2 -- SP_PositionPnL, DWH_dbo.Dim_Position.IsBuy)';
ALTER TABLE main.bi_db.gold_bi_db_bi_db_positionpnl ALTER COLUMN `Occurred` COMMENT 'Position open timestamp (`OpenOccurred`). (Tier 2 -- SP_PositionPnL, DWH_dbo.Dim_Position.OpenOccurred)';
ALTER TABLE main.bi_db.gold_bi_db_bi_db_positionpnl ALTER COLUMN `Date` COMMENT 'Snapshot calendar date `@dt`. (Tier 3 -- SP_PositionPnL, parameter @dt)';
ALTER TABLE main.bi_db.gold_bi_db_bi_db_positionpnl ALTER COLUMN `DateID` COMMENT 'Snapshot date as YYYYMMDD; partition key. (Tier 3 -- SP_PositionPnL, CAST(CONVERT(CHAR(8),@dt,112) AS INT))';
ALTER TABLE main.bi_db.gold_bi_db_bi_db_positionpnl ALTER COLUMN `IsSettled` COMMENT '1 = real asset, 0 = CFD asset. Rewound via PositionChangeLog (`ChangeTypeID = 13`) when applicable. (Tier 5 - Expert Review)';
ALTER TABLE main.bi_db.gold_bi_db_bi_db_positionpnl ALTER COLUMN `NOP` COMMENT 'Net open position in USD from units × pair rate × direction × conversion (see `#Pre_UnrealizedPnL`). (Tier 2 -- SP_PositionPnL, computed)';
ALTER TABLE main.bi_db.gold_bi_db_bi_db_positionpnl ALTER COLUMN `DailyPnL` COMMENT 'Day-over-day change: `PositionPnL - prior day PositionPnL` (NULL until post-switch UPDATE). (Tier 3 -- SP_PositionPnL, UPDATE vs prior DateID)';
ALTER TABLE main.bi_db.gold_bi_db_bi_db_positionpnl ALTER COLUMN `Leverage` COMMENT 'Position leverage. (Tier 2 -- SP_PositionPnL, DWH_dbo.Dim_Position.Leverage)';
ALTER TABLE main.bi_db.gold_bi_db_bi_db_positionpnl ALTER COLUMN `RateBid` COMMENT 'EOD bid from latest `Fact_CurrencyPriceWithSplit` row before `@ReportDate`, split-adjusted; uses `BidLastWithoutSpread` when discounted. (Tier 2 -- SP_PositionPnL, DWH_dbo.Fact_CurrencyPriceWithSplit + split)';
ALTER TABLE main.bi_db.gold_bi_db_bi_db_positionpnl ALTER COLUMN `RateAsk` COMMENT 'EOD ask from same price row, split-adjusted. (Tier 2 -- SP_PositionPnL, DWH_dbo.Fact_CurrencyPriceWithSplit + split)';
ALTER TABLE main.bi_db.gold_bi_db_bi_db_positionpnl ALTER COLUMN `USD_CR` COMMENT 'End-of-day conversion rate used with PnL context; from Dim_Position `CurrentConversionRate`. (Tier 2 -- SP_PositionPnL, DWH_dbo.Dim_Position.CurrentConversionRate)';

-- main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_aml_sar_report_fca (TABLE, 18 columns)
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_aml_sar_report_fca ALTER COLUMN `GCID` COMMENT 'Global Customer ID. Distribution key and clustered index column. Maps to Dim_Customer.GCID. (Tier 1 - Account.Customer)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_aml_sar_report_fca ALTER COLUMN `BirthDate` COMMENT 'Customer date of birth. Used in LinkedAccountHash1 for duplicate detection and in KYC age verification. (Tier 1 - Customer.CustomerStatic)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_aml_sar_report_fca ALTER COLUMN `FirstName` COMMENT 'Legal first name in Unicode. nvarchar supports non-Latin scripts (Cyrillic, Arabic, etc.). Used in LinkedAccountHash1. (Tier 1 - Customer.CustomerStatic)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_aml_sar_report_fca ALTER COLUMN `LastName` COMMENT 'Legal last name in Unicode. Used in LinkedAccountHash1. (Tier 1 - Customer.CustomerStatic)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_aml_sar_report_fca ALTER COLUMN `MiddleName` COMMENT 'Middle name in Unicode. Added 2018. Included in CustomerVersionUpdate history tracking. (Tier 1 - Customer.CustomerStatic)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_aml_sar_report_fca ALTER COLUMN `Gender` COMMENT 'Gender: M, F, or U (Unknown). CHECK constraint CCST_GENDER enforces these three values only. Used in LinkedAccountHash1. (Tier 1 - Customer.CustomerStatic)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_aml_sar_report_fca ALTER COLUMN `Zip` COMMENT 'Postal code. Used in LinkedAccountHash1. (Tier 1 - Customer.CustomerStatic)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_aml_sar_report_fca ALTER COLUMN `Address` COMMENT 'Street address in Unicode. (Tier 1 - Customer.CustomerStatic)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_aml_sar_report_fca ALTER COLUMN `BuildingNumber` COMMENT 'Building/apartment number. Separate from Address for structured address storage. (Tier 1 - Customer.CustomerStatic)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_aml_sar_report_fca ALTER COLUMN `City` COMMENT 'City in Unicode. (Tier 1 - Customer.CustomerStatic)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_aml_sar_report_fca ALTER COLUMN `IsIDProof` COMMENT 'Whether ID proof document is on file (1/0). (Tier 2 - SP_Dim_Customer)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_aml_sar_report_fca ALTER COLUMN `IsAddressProof` COMMENT 'Whether address proof document is on file (1/0). Updated from BackOffice.CustomerDocument. (Tier 2 - SP_Dim_Customer)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_aml_sar_report_fca ALTER COLUMN `RegisteredReal` COMMENT 'Account registration date (renamed from Registered). Default=getdate(). (Tier 1 - Customer.CustomerStatic)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_aml_sar_report_fca ALTER COLUMN `FirstDepositDate` COMMENT 'Date of first deposit. DEFAULT=''19000101''. Updated from CustomerFinanceDB FTD data with FTDRecoveryDate logic. (Tier 2 - SP_Dim_Customer)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_aml_sar_report_fca ALTER COLUMN `FirstDepositAmount` COMMENT 'Amount of first deposit (in USD). Updated from FTDAmountInUsd. (Tier 2 - SP_Dim_Customer)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_aml_sar_report_fca ALTER COLUMN `Phone` COMMENT 'Phone number from production Customer.CustomerStatic. (Tier 1 - Customer.CustomerStatic)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_aml_sar_report_fca ALTER COLUMN `Email` COMMENT 'Customer email address. Unique (case-insensitive via LowerEmail computed column). Email changes trigger Customer.LastChanges update via trigger. (Tier 1 - Customer.CustomerStatic)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_aml_sar_report_fca ALTER COLUMN `CID` COMMENT 'Customer ID. Identifies the eToro customer who made this deposit. References DWH_dbo.Dim_Customer. (Tier 1 - upstream wiki, Billing.Deposit)';

-- main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_aml_singapore_risk_classification (TABLE, 6 columns)
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_aml_singapore_risk_classification ALTER COLUMN `GCID` COMMENT 'Global Customer ID. Distribution key and clustered index column. Maps to Dim_Customer.GCID. (Tier 1 - Account.Customer)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_aml_singapore_risk_classification ALTER COLUMN `RegisteredReal` COMMENT 'Account registration date (renamed from Registered). Default=getdate(). (Tier 1 - Customer.CustomerStatic)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_aml_singapore_risk_classification ALTER COLUMN `FirstDepositDate` COMMENT 'Date of first deposit. DEFAULT=''19000101''. Updated from CustomerFinanceDB FTD data with FTDRecoveryDate logic. (Tier 2 - SP_Dim_Customer)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_aml_singapore_risk_classification ALTER COLUMN `CountryIDByIP` COMMENT 'Country detected from the customer IP address at registration. Used for fraud detection and geo-comparison (CountryID vs CountryIDByIP mismatch flagging). (Tier 1 - Customer.CustomerStatic)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_aml_singapore_risk_classification ALTER COLUMN `VerificationLevelID` COMMENT 'KYC verification level. FK to Dictionary.VerificationLevel. Values: 0=unverified (34.2%), 1=partial (12.4%), 2=intermediate (6.2%), 3=fully verified (47.1%). Default=0. (Tier 1 - BackOffice.Customer)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_aml_singapore_risk_classification ALTER COLUMN `CID` COMMENT 'Copier customer ID. The user who allocates money to follow the leader. Trade.ValidateNumOfActiveMirrors counts mirrors per CID. (Tier 1 - Trade.Mirror)';

