ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_cross_selling_monthly ALTER COLUMN `Region` COMMENT 'Marketing region label for this country. Loaded from etoro.Dictionary.MarketingRegion.Name via JOIN on MarketingRegionID. NOT the geographic region from Dictionary.Region. 22 distinct values (e.g., "ROW", "Africa", "French", "Arabic Other"). Used for marketing campaign grouping. (Tier 2 - SP_Dictionaries_Country_DL_To_Synapse)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_cross_selling_monthly ALTER COLUMN `DateKey` COMMENT 'Calendar date key from Dim_Date (YYYYMMDD). One row per CID per day for each day in [Dim_Range.FromDateID, Dim_Range.ToDateID]; view filters DateKey < today. (Tier 2 - V_Fact_SnapshotEquity)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_cross_selling_monthly ALTER COLUMN `FullDate` COMMENT 'Calendar date (datetime). From the date dimension via V_M2M_Date_DateRange. (Tier 1 - V_M2M_Date_DateRange.FullDate)';

