ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_crypto_nop ALTER COLUMN `Date` COMMENT 'Snapshot calendar date `@dt`. (Tier 3 -- SP_PositionPnL, parameter @dt)';
