ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_crypto_nop ALTER COLUMN `IsBuy` COMMENT 'Long (1) vs short (0). (Tier 2 -- SP_PositionPnL, DWH_dbo.Dim_Position.IsBuy)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_crypto_nop ALTER COLUMN `AccountTypeID` COMMENT 'Primary key identifying the account classification. 0=N/A (DWH placeholder), 1=Private, 2=Corporate, 3=IB Account, 4=Joint Account, 5=White Label, 6=Affiliate Private, 7=Employee, 8=Custodian, 9=Fund, 10=eToro Group, 11=News, 12=White List, 13=Analyst, 14=SMSF, 15=Affiliate Corporate, 16=Administrated, 17=Funded Employee, 18=Trust. Controls feature access, regulatory treatment, fee structures, and compliance monitoring level. Referenced by Dim_Customer.AccountTypeID. (Tier 1 - upstream wiki, Dictionary.AccountType)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_crypto_nop ALTER COLUMN `MifidCategorizationID` COMMENT 'MiFID II investor classification. FK to Dictionary.MifidCategorization. Values: 1=Retail (97.3%), 4=Eligible Counterparty (2.6%), 5=Professional (0.03%). Default=1. (Tier 1 - BackOffice.Customer)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_crypto_nop ALTER COLUMN `PlayerLevelID` COMMENT 'Customer experience/permission level. FK to Dictionary.PlayerLevel. 1=Standard (94%); 4=Popular Investor; 7=VIP. Determines available features and risk limits. Default=0. (Tier 1 - Customer.CustomerStatic)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_crypto_nop ALTER COLUMN `PlayerStatusID` COMMENT 'Compliance and trading account status. FK to Dictionary.PlayerStatus. 1=Active/Registered (97.5% of accounts); other values indicate restricted, closed, banned, or special states. Default=0. (Tier 1 - Customer.CustomerStatic)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_crypto_nop ALTER COLUMN `IsCreditReportValidCB` COMMENT 'DWH-computed: similar to IsValidCustomer but with additional AccountTypeID != 2 exclusion and specific CID exceptions for CountryID=250. (Tier 2 - SP_Dim_Customer)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_crypto_nop ALTER COLUMN `BuyCurrency` COMMENT 'Text abbreviation of BuyCurrencyID -- denormalized from Dictionary.Currency.Abbreviation via SP JOIN. Example: EUR, AAPL, BTC. DWH-added for query convenience. (Tier 2 -- SP_Dim_Instrument)';

-- main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_crypto_nop_cid (TABLE, 31 columns)
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_crypto_nop_cid ALTER COLUMN `Date` COMMENT 'As-of business date for the load; equals SP parameter `@Date`. Live samples show daily loads through **2026-03-19**. (Tier 2 -- SP_Crypto_NOP, @Date)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_crypto_nop_cid ALTER COLUMN `Regulation` COMMENT 'Regulation name from `Dim_Regulation.Name` via `Fact_SnapshotCustomer.RegulationID` in `#fsc`. Live 7-day data: highest row counts **CySEC**, **FCA**, **FSA Seychelles**, **ASIC & GAML**, **FSRA**, **FinCEN+FINRA**, **BVI**, **ASIC**, **FinCEN**, **eToroUS**. (Tier 2 -- SP_Crypto_NOP, Dim_Regulation.Name)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_crypto_nop_cid ALTER COLUMN `Label` COMMENT 'Broker / entity label from `Dim_Label.Name` via `Fact_SnapshotCustomer.LabelID`. Live 7-day: **eToro** dominates; smaller volumes include **eToroRussia**, **ILQ**, **Royal-CM**, **JCLyons**, **eToroUSA**, **Dealing**, **ICMarkets**, **eToroChina**, **RetailFX**. (Tier 2 -- SP_Crypto_NOP, Dim_Label.Name)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_crypto_nop_cid ALTER COLUMN `Real_NOP` COMMENT 'Sum of NOP on settled real positions (`IsSettled = 1`) from `#pos_new`. (Tier 2 -- SP_Crypto_NOP, BI_DB_PositionPnL.NOP)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_crypto_nop_cid ALTER COLUMN `CFD_NOP` COMMENT 'Sum of NOP on CFD positions (`IsSettled = 0`). (Tier 2 -- SP_Crypto_NOP, BI_DB_PositionPnL.NOP)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_crypto_nop_cid ALTER COLUMN `Total_NOP` COMMENT '`SUM(NOP_CFD) + SUM(NOP_Real)` at instrument grain; does not add TRS into this field. (Tier 2 -- SP_Crypto_NOP, computed)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_crypto_nop_cid ALTER COLUMN `Real_Units` COMMENT 'Sum of `AmountInUnitsDecimal` where `IsSettled = 1`. (Tier 2 -- SP_Crypto_NOP, BI_DB_PositionPnL.AmountInUnitsDecimal)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_crypto_nop_cid ALTER COLUMN `IsBuy` COMMENT 'Position direction from open snapshot (`Dim_Position` / `#pos`). Live 7-day: rows with **IsBuy** = 1 greatly exceed **IsBuy** = 0. (Tier 2 -- SP_Crypto_NOP, Dim_Position.IsBuy)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_crypto_nop_cid ALTER COLUMN `EquityReal` COMMENT 'Rounded sum of real equity (`Amount + PositionPnL` when `IsSettled = 1`). (Tier 2 -- SP_Crypto_NOP, computed)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_crypto_nop_cid ALTER COLUMN `EquityCFD` COMMENT 'Rounded sum of CFD equity (`Amount + PositionPnL` when `IsSettled = 0`). (Tier 2 -- SP_Crypto_NOP, computed)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_crypto_nop_cid ALTER COLUMN `InstrumentName` COMMENT 'Instrument display name from `BI_DB_PositionPnL` / `Dim_Instrument.Name`. Live 7-day row counts top instruments include **BTC/USD**, **ETH/USD**, **XRP/USD**, **ADA/USD**, **SOL/USD**, **DOGE/USD**, **XLM/USD**, **TRX/USD**, **SHIBxM/USD**, **LINK/USD**. (Tier 2 -- SP_Crypto_NOP, Dim_Instrument.Name)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_crypto_nop_cid ALTER COLUMN `MifidCategorizationID` COMMENT 'MiFID categorization key from `Fact_SnapshotCustomer`. (Tier 2 -- SP_Crypto_NOP, Fact_SnapshotCustomer.MifidCategorizationID)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_crypto_nop_cid ALTER COLUMN `MifidCategorization` COMMENT 'MiFID categorization name from `Dim_MifidCategorization.Name`. (Tier 2 -- SP_Crypto_NOP, Dim_MifidCategorization.Name)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_crypto_nop_cid ALTER COLUMN `AccountTypeID` COMMENT 'Account type key from `Fact_SnapshotCustomer`. (Tier 2 -- SP_Crypto_NOP, Fact_SnapshotCustomer.AccountTypeID)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_crypto_nop_cid ALTER COLUMN `AccountType` COMMENT 'Account type name from `Dim_AccountType.Name`. (Tier 2 -- SP_Crypto_NOP, Dim_AccountType.Name)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_crypto_nop_cid ALTER COLUMN `PlayerLevelID` COMMENT 'Player level key from `Fact_SnapshotCustomer`. (Tier 2 -- SP_Crypto_NOP, Fact_SnapshotCustomer.PlayerLevelID)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_crypto_nop_cid ALTER COLUMN `Club` COMMENT 'Club name from `Dim_PlayerLevel.Name`. (Tier 2 -- SP_Crypto_NOP, Dim_PlayerLevel.Name)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_crypto_nop_cid ALTER COLUMN `PlayerStatusID` COMMENT 'Player status key from `Fact_SnapshotCustomer`. (Tier 2 -- SP_Crypto_NOP, Fact_SnapshotCustomer.PlayerStatusID)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_crypto_nop_cid ALTER COLUMN `PlayerStatus` COMMENT 'Player status name from `Dim_PlayerStatus.Name`. (Tier 2 -- SP_Crypto_NOP, Dim_PlayerStatus.Name)';
