ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_crypto_nop_cid ALTER COLUMN `Total_Units` COMMENT 'Sum of all `AmountInUnitsDecimal` for the grain. (Tier 2 -- SP_Crypto_NOP, BI_DB_PositionPnL.AmountInUnitsDecimal)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_crypto_nop_cid ALTER COLUMN `TanganyStatus` COMMENT 'Custodian status label from `External_UserApiDB_Dictionary_TanganyStatus.Name` via `Dim_Customer.TanganyStatusID`. Live 7-day: mostly **NULL**; non-null top values **Inactive**, **MicaCustomer**, **Customer**, **Internal**, **ConsentCustomer**. (Tier 2 -- SP_Crypto_NOP, External_UserApiDB_Dictionary_TanganyStatus.Name)';
