ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_crypto_nop_cid ALTER COLUMN `Real_Units_Staking_OptOut` COMMENT 'Complement slice of real units for staking opt-in/out logic. (Tier 2 -- SP_Crypto_NOP, computed)';
