ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_ddr_customer_daily_status ALTER COLUMN `IsCreditReportValidCB` COMMENT 'Credit Bureau reporting eligibility flag. 1 = eligible for credit reporting. Inherited from Fact_SnapshotCustomer. Excludes demo non-real accounts, internal labels (26,30), and blocked countries (250). Used by finance for regulatory balance reconciliation. (Tier 2 - SP_Client_Balance_New, from DWH_dbo.Fact_SnapshotCustomer)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_ddr_customer_daily_status ALTER COLUMN `IsValidCustomer` COMMENT 'Segment flag from Fact_SnapshotCustomer. 1 = valid retail customer (not demo, not internal label, not blocked country). Use `WHERE IsValidCustomer = 1` for most analytics. (Tier 2 - SP_Client_Balance_New, from DWH_dbo.Fact_SnapshotCustomer)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_ddr_customer_daily_status ALTER COLUMN `RealCID` COMMENT 'Customer identifier. Distribution key. Passthrough from sub-platform tables. (Tier 2 - SP_DDR_Fact_Fact_MIMO_AllPlatforms)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_ddr_customer_daily_status ALTER COLUMN `RegulationID` COMMENT 'Regulation key from customer snapshot. (Tier 2 -- SP_DepositWithdrawFee, Fact_SnapshotCustomer.RegulationID)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_ddr_customer_daily_status ALTER COLUMN `PlayerLevelID` COMMENT 'Player level id from snapshot. (Tier 2 -- SP_DepositWithdrawFee, Fact_SnapshotCustomer.PlayerLevelID)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_ddr_customer_daily_status ALTER COLUMN `AccountTypeID` COMMENT 'Primary key identifying the account classification. 0=N/A (DWH placeholder), 1=Private, 2=Corporate, 3=IB Account, 4=Joint Account, 5=White Label, 6=Affiliate Private, 7=Employee, 8=Custodian, 9=Fund, 10=eToro Group, 11=News, 12=White List, 13=Analyst, 14=SMSF, 15=Affiliate Corporate, 16=Administrated, 17=Funded Employee, 18=Trust. Controls feature access, regulatory treatment, fee structures, and compliance monitoring level. Referenced by Dim_Customer.AccountTypeID. (Tier 1 - upstream wiki, Dictionary.AccountType)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_ddr_customer_daily_status ALTER COLUMN `CountryID` COMMENT 'Primary key. 0=Not available (fallback/placeholder for users whose country cannot be determined), 1-250=countries ordered roughly alphabetically by ISO code. Referenced by Dim_Customer, Fact_BillingDeposit, Dim_CountryBin, V_Dim_Customer. (Tier 1 - Dictionary.Country upstream wiki)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_ddr_customer_daily_status ALTER COLUMN `DesignatedRegulationID` COMMENT 'Secondary/override regulation for accounts subject to multiple jurisdictions. FK to Dictionary.Regulation. (Tier 1 - BackOffice.Customer)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_ddr_customer_daily_status ALTER COLUMN `PlayerStatusID` COMMENT 'Compliance and trading account status. FK to Dictionary.PlayerStatus. 1=Active/Registered (97.5% of accounts); other values indicate restricted, closed, banned, or special states. Default=0. (Tier 1 - Customer.CustomerStatic)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_ddr_customer_daily_status ALTER COLUMN `MifidCategorizationID` COMMENT 'MiFID II investor classification. FK to Dictionary.MifidCategorization. Values: 1=Retail (97.3%), 4=Eligible Counterparty (2.6%), 5=Professional (0.03%). Default=1. (Tier 1 - BackOffice.Customer)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_ddr_customer_daily_status ALTER COLUMN `IsDepositor` COMMENT 'Whether the customer has ever deposited. DEFAULT=0. Updated post-load from FTD data. (Tier 2 - SP_Dim_Customer)';

