ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_ddr_fact_aum ALTER COLUMN `NOPStocks` COMMENT 'Net Open Position for stock instruments. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_ddr_fact_aum ALTER COLUMN `NOPStocksCFD` COMMENT 'NOP for stock CFDs specifically. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_ddr_fact_aum ALTER COLUMN `TotalRealCryptoLoan` COMMENT 'Total leveraged real crypto loan amount. InitialAmount where IsSettled=1 AND InstrumentTypeID=10 AND Leverage=2. Represents the initial investment in 2x leveraged crypto. (Tier 2 - SP_Client_Balance_New, from DWH_dbo.Fact_SnapshotEquity)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_ddr_fact_aum ALTER COLUMN `Bonus` COMMENT 'Bonus credits. SUM(Amount) from Fact_CustomerAction WHERE ActionTypeID=9. Credit bonus amounts applied to account. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_ddr_fact_aum ALTER COLUMN `CashInCopy` COMMENT 'Cash allocated to copy-trading relationships. From V_Liabilities.CashInCopy. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_ddr_fact_aum ALTER COLUMN `StockOrders` COMMENT 'Stock order amount. Legacy column - hardcoded to 0 in Fact_SnapshotEquity since 2019-03-03. Kept for schema compatibility. (Tier 2 - SP_Client_Balance_New, from DWH_dbo.Fact_SnapshotEquity)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_ddr_fact_aum ALTER COLUMN `TotalRealCrypto` COMMENT 'Total real crypto position value. Sum of position amounts where IsSettled=1 AND InstrumentTypeID=10. Customer owns the underlying crypto asset. (Tier 2 - SP_Client_Balance_New, from DWH_dbo.Fact_SnapshotEquity)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_ddr_fact_aum ALTER COLUMN `TotalRealStocks` COMMENT 'Total real stock position value. Sum of position amounts where IsSettled=1 AND InstrumentTypeID IN (5,6) AND NOT futures. Customer owns the underlying shares. (Tier 2 - SP_Client_Balance_New, from DWH_dbo.Fact_SnapshotEquity)';
