ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_depositwithdrawfee ALTER COLUMN `Amount` COMMENT 'Deposit amount in the deposit currency (CurrencyID). As of 2025-04-17, capped via CASE expression in ETL to prevent extreme outlier values from distorting aggregations. (Tier 1 - upstream wiki, Billing.Deposit)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_depositwithdrawfee ALTER COLUMN `ExchangeRate` COMMENT 'Exchange rate from deposit currency to USD at processing time. Cannot be 0 in production. (Tier 1 - upstream wiki, Billing.Deposit)';
