ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_depositwithdrawfee ALTER COLUMN `BaseExchangeRate` COMMENT 'Reference exchange rate before fee markup. Fee spread = ExchangeRate - BaseExchangeRate. Added by Adi (19/09/2019). (Tier 1 - upstream wiki, Billing.Deposit)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_depositwithdrawfee ALTER COLUMN `ExchangeFee` COMMENT 'Exchange fee in provider-specific integer encoding (basis points). Added by Adi (19/02/2019). (Tier 1 - upstream wiki, Billing.Deposit)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_depositwithdrawfee ALTER COLUMN `DepositID` COMMENT 'Primary distribution key (HASH). Uniquely identifies each deposit attempt. PK in production (Billing.Deposit.DepositID IDENTITY). Clustered index key in DWH. (Tier 1 - upstream wiki, Billing.Deposit)';
