ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_kyc_panel ALTER COLUMN `RealCID` COMMENT 'Customer Real account ID. Maps to Dim_Customer.RealCID. (Tier 1 - etoro.Account.Customer.RealCID)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_kyc_panel ALTER COLUMN `GCID` COMMENT 'Global Customer ID. Distribution key and clustered index column. Maps to Dim_Customer.GCID. (Tier 1 - Account.Customer)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_kyc_panel ALTER COLUMN `FTD_Date` COMMENT 'First Time Deposit date. Renamed from Dim_Customer.FirstDepositDate. (Tier 1 - Fact_BillingDeposit.MIN(DateTimeUTC))';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_kyc_panel ALTER COLUMN `CountryID` COMMENT 'Country of residence ID. From Dim_Customer.CountryID. JOINs to Dim_Country.CountryID. (Tier 1 - Dictionary.Country)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_kyc_panel ALTER COLUMN `CountryName` COMMENT 'Country name. Decoded from Dim_Country.Name via CountryID. (Tier 1 - Dictionary.Country, join-enriched)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_kyc_panel ALTER COLUMN `RegulationID` COMMENT 'Current regulation ID. From Dim_Customer.RegulationID. JOINs to Dim_Regulation.DWHRegulationID. (Tier 1 - Dictionary.Regulation)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_kyc_panel ALTER COLUMN `CFD_Status` COMMENT 'Derived CFD trading status. `CASE WHEN CFDRestrictionStatusID=1 THEN ''CFD_Blocked'' ELSE ''CFD_Allowed''`. 2-value enum: "CFD_Blocked" (20%, 3.6M), "CFD_Allowed" (80%, 14.3M). (Tier 2 - SP_BI_DB_Scored_Appropriateness_Negative_Market, ETL-computed)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_kyc_panel ALTER COLUMN `DateDiffBlockRelease` COMMENT 'Days between block and release. `DATEDIFF(d, BlockDate, ReleaseDate)`. NULL if not yet released or never blocked. Useful for measuring restriction duration. (Tier 2 - SP_BI_DB_Scored_Appropriateness_Negative_Market, ETL-computed)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_kyc_panel ALTER COLUMN `Region` COMMENT 'Marketing region label for this country. Loaded from etoro.Dictionary.MarketingRegion.Name via JOIN on MarketingRegionID. NOT the geographic region from Dictionary.Region. 22 distinct values (e.g., "ROW", "Africa", "French", "Arabic Other"). Used for marketing campaign grouping. (Tier 2 - SP_Dictionaries_Country_DL_To_Synapse)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_kyc_panel ALTER COLUMN `EU` COMMENT 'Whether this country is a full EU member state. 1=EU member (27 countries), 0=non-EU. Source: Ext_Dim_Country manual extension table (left join - NULL if not in Ext_Dim_Country). Always 0 or 1 in practice. Distinct from IsEuropeanCountry. (Tier 3 - Ext_Dim_Country live data)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_kyc_panel ALTER COLUMN `VerificationLevelID` COMMENT 'KYC verification level. FK to Dictionary.VerificationLevel. Values: 0=unverified (34.2%), 1=partial (12.4%), 2=intermediate (6.2%), 3=fully verified (47.1%). Default=0. (Tier 1 - BackOffice.Customer)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_kyc_panel ALTER COLUMN `Gender` COMMENT 'Gender: M, F, or U (Unknown). CHECK constraint CCST_GENDER enforces these three values only. Used in LinkedAccountHash1. (Tier 1 - Customer.CustomerStatic)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_kyc_panel ALTER COLUMN `FirstDepositAmount` COMMENT 'Amount of first deposit (in USD). Updated from FTDAmountInUsd. (Tier 2 - SP_Dim_Customer)';

