ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_money_in_new_management_dashboard ALTER COLUMN `AmountUSD` COMMENT 'Deposit amount converted to USD. DWH-computed: Amount × ExchangeRate. Not from production source - pre-computed in ETL for reporting convenience. (Tier 2 - SP_Fact_BillingDeposit_DL_To_Synapse)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_money_in_new_management_dashboard ALTER COLUMN `CID` COMMENT 'Customer ID. Identifies the eToro customer who made this deposit. References DWH_dbo.Dim_Customer. (Tier 1 - upstream wiki, Billing.Deposit)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_money_in_new_management_dashboard ALTER COLUMN `PaymentDate` COMMENT 'UTC timestamp when the deposit was submitted (set at INSERT in production). Not the approval time. (Tier 1 - upstream wiki, Billing.Deposit)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_money_in_new_management_dashboard ALTER COLUMN `ModificationDate` COMMENT 'UTC timestamp of the most recent modification to this deposit record. Used by ETL for incremental detection. (Tier 1 - upstream wiki, Billing.Deposit)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_money_in_new_management_dashboard ALTER COLUMN `IsFTD` COMMENT 'First Time Deposit flag. 1=this was the customer''s very first approved deposit (drives marketing attribution). 0=repeat deposit or ineligible type. ~60.6% of deposits are FTD=1 in Billing.Deposit. Stored as int in DWH (vs. bit in production). (Tier 1 - upstream wiki, Billing.Deposit)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_money_in_new_management_dashboard ALTER COLUMN `ProcessorValueDate` COMMENT 'Value date from the payment processor. Mandatory for offline/wire deposits. NULL for instant payment methods. (Tier 1 - upstream wiki, Billing.Deposit)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_money_in_new_management_dashboard ALTER COLUMN `ModificationDateID` COMMENT 'ETL key. Integer YYYYMMDD derived from ModificationDate (CONVERT(INT, date)). Used for rolling-window DELETE+INSERT. (Tier 2 - SP_Fact_BillingDeposit_DL_To_Synapse)';

