ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_money_out_new_management_dashboard ALTER COLUMN `CashoutStatusID_Withdraw` COMMENT 'Withdrawal request-level status. FK to Dim_CashoutStatus. 10 distinct values: 1=Pending, 2=InProcess, 3=Processed, 4=Cancelled. Renamed from CashoutStatusID. (Tier 1 - Billing.Withdraw)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_money_out_new_management_dashboard ALTER COLUMN `CashoutStatusID_Funding` COMMENT 'Execution-level status of the payment leg. FK to Dim_CashoutStatus. Values: 3=Processed (31.5%), 4=Canceled (67.7%), 14=Pending Review, 17=Partially Reversed. Renamed from CashoutStatusID. (Tier 1 - Billing.WithdrawToFunding)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_money_out_new_management_dashboard ALTER COLUMN `RequestDate` COMMENT 'Timestamp when the customer submitted the withdrawal request. (Tier 1 - Billing.Withdraw)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_money_out_new_management_dashboard ALTER COLUMN `Fee` COMMENT 'Platform fee charged for this withdrawal. Subtracted from the gross Amount_Withdraw. (Tier 1 - Billing.Withdraw)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_money_out_new_management_dashboard ALTER COLUMN `ModificationDate` COMMENT 'UTC timestamp of the most recent status change or update on the withdrawal request. (Tier 1 - Billing.Withdraw)';

