-- main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_v_bi_db_alldeposits (TABLE, 12 columns)
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_v_bi_db_alldeposits ALTER COLUMN `DepotID` COMMENT 'Primary key. Manually assigned (no IDENTITY). Stable identifier for this payment gateway endpoint. Range 1-174 with gaps; 163 rows. Referenced by fact deposit/cashout tables and MID settings. (Tier 1 - upstream wiki, Billing.Depot)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_v_bi_db_alldeposits ALTER COLUMN `Region` COMMENT 'Marketing region label for this country. Loaded from etoro.Dictionary.MarketingRegion.Name via JOIN on MarketingRegionID. NOT the geographic region from Dictionary.Region. 22 distinct values (e.g., "ROW", "Africa", "French", "Arabic Other"). Used for marketing campaign grouping. (Tier 2 - SP_Dictionaries_Country_DL_To_Synapse)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_v_bi_db_alldeposits ALTER COLUMN `CardSubType` COMMENT 'Sub-classification of the card product within its type (e.g., "CREDIT", "DEBIT", "PREPAID"). NULL when not available. Passthrough from staging. (Tier 2 - SP_Dictionaries_DL_To_Synapse passthrough)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_v_bi_db_alldeposits ALTER COLUMN `BinCode` COMMENT 'Bank Identification Number. First 6 or 8 digits of the card number identifying the issuing bank and card product. Values < 10,000,000 are 6-digit BINs; >= 10,000,000 are 8-digit BINs. Clustered index key for fast lookups. (Tier 1 - Dictionary.CountryBin6 upstream wiki)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_v_bi_db_alldeposits ALTER COLUMN `FirstDepositDate` COMMENT 'Date of first deposit. DEFAULT=''19000101''. Updated from CustomerFinanceDB FTD data with FTDRecoveryDate logic. (Tier 2 - SP_Dim_Customer)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_v_bi_db_alldeposits ALTER COLUMN `CID` COMMENT 'Customer ID. Identifies the eToro customer who made this deposit. References DWH_dbo.Dim_Customer. (Tier 1 - upstream wiki, Billing.Deposit)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_v_bi_db_alldeposits ALTER COLUMN `DepositID` COMMENT 'Primary distribution key (HASH). Uniquely identifies each deposit attempt. PK in production (Billing.Deposit.DepositID IDENTITY). Clustered index key in DWH. (Tier 1 - upstream wiki, Billing.Deposit)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_v_bi_db_alldeposits ALTER COLUMN `ModificationDate` COMMENT 'UTC timestamp of the most recent modification to this deposit record. Used by ETL for incremental detection. (Tier 1 - upstream wiki, Billing.Deposit)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_v_bi_db_alldeposits ALTER COLUMN `IsFTD` COMMENT 'First Time Deposit flag. 1=this was the customer''s very first approved deposit (drives marketing attribution). 0=repeat deposit or ineligible type. ~60.6% of deposits are FTD=1 in Billing.Deposit. Stored as int in DWH (vs. bit in production). (Tier 1 - upstream wiki, Billing.Deposit)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_v_bi_db_alldeposits ALTER COLUMN `ModificationDateID` COMMENT 'ETL key. Integer YYYYMMDD derived from ModificationDate (CONVERT(INT, date)). Used for rolling-window DELETE+INSERT. (Tier 2 - SP_Fact_BillingDeposit_DL_To_Synapse)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_v_bi_db_alldeposits ALTER COLUMN `FundingID` COMMENT 'Payment instrument (credit card, bank account, e-wallet) used for this deposit. References Billing.Funding. (Tier 1 - upstream wiki, Billing.Deposit)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_v_bi_db_alldeposits ALTER COLUMN `BaseExchangeRate` COMMENT 'Reference exchange rate before fee markup. Fee spread = ExchangeRate - BaseExchangeRate. Added by Adi (19/09/2019). (Tier 1 - upstream wiki, Billing.Deposit)';

