ALTER TABLE main.bi_db.gold_sql_dp_prod_we_dealing_dbo_dealing_dealingdashboard_clients ALTER COLUMN `Leverage` COMMENT 'Position leverage. (Tier 2 -- SP_PositionPnL, DWH_dbo.Dim_Position.Leverage)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_dealing_dbo_dealing_dealingdashboard_clients ALTER COLUMN `NOP` COMMENT 'Net open position in USD from units × pair rate × direction × conversion (see `#Pre_UnrealizedPnL`). (Tier 2 -- SP_PositionPnL, computed)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_dealing_dbo_dealing_dealingdashboard_clients ALTER COLUMN `Region` COMMENT 'Marketing region label for this country. Loaded from etoro.Dictionary.MarketingRegion.Name via JOIN on MarketingRegionID. NOT the geographic region from Dictionary.Region. 22 distinct values (e.g., "ROW", "Africa", "French", "Arabic Other"). Used for marketing campaign grouping. (Tier 2 - SP_Dictionaries_Country_DL_To_Synapse)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_dealing_dbo_dealing_dealingdashboard_clients ALTER COLUMN `InstrumentType` COMMENT 'Text label for InstrumentTypeID -- DWH-computed via CASE: 1=Currencies, 2=Commodities, 4=Indices, 5=Stocks, 6=ETF, 10=Crypto Currencies, else=Other. Use InstrumentTypeID for filtering; InstrumentType for display. (Tier 2 -- SP_Dim_Instrument)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_dealing_dbo_dealing_dealingdashboard_clients ALTER COLUMN `InstrumentDisplayName` COMMENT 'User-facing instrument display name from Trade.InstrumentMetaData. More descriptive than Name (e.g., ''Apple Inc.'' vs ''Apple''). NULL for instruments without metadata entries. (Tier 2 -- SP_Dim_Instrument, etoro_Trade_InstrumentMetaData)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_dealing_dbo_dealing_dealingdashboard_clients ALTER COLUMN `Symbol` COMMENT 'Ticker symbol for the instrument (e.g., AAPL, EURUSD, BTCUSD). Used for display, search, and price feed identification. NULL for ID=0 placeholder and some instruments without formal ticker. (Tier 3 -- live data, etoro.Trade.GetInstrument)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_dealing_dbo_dealing_dealingdashboard_clients ALTER COLUMN `SellCurrency` COMMENT 'Text abbreviation of SellCurrencyID -- denormalized from Dictionary.Currency.Abbreviation. Example: USD, EUR, GBX (GBP pence). DWH-added for query convenience. (Tier 2 -- SP_Dim_Instrument)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_dealing_dbo_dealing_dealingdashboard_clients ALTER COLUMN `Exchange` COMMENT 'Stock exchange name from Trade.InstrumentMetaData (e.g., Nasdaq, NYSE, LSE). NULL for non-stock instruments. (Tier 3 -- live data, etoro_Trade_InstrumentMetaData)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_dealing_dbo_dealing_dealingdashboard_clients ALTER COLUMN `IsFuture` COMMENT 'Derived flag indicating if the instrument is a futures contract: 1=futures, 0=not futures. Computed in SP as CASE WHEN InstrumentID IN (SELECT InstrumentID FROM InstrumentGroups WHERE GroupID=25) THEN 1 ELSE 0. NULL for ID=0 placeholder. (Tier 2 -- SP_Dim_Instrument)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_dealing_dbo_dealing_dealingdashboard_clients ALTER COLUMN `FullCommission` COMMENT 'Full commission including spread. PositionOpen stores @FullCommission/100. (Tier 1 - Trade.PositionTbl)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_dealing_dbo_dealing_dealingdashboard_clients ALTER COLUMN `FullCommissionOnClose` COMMENT 'Full commission on close. DWH note: adjusted by SP_Dim_Position when position is reopened; FullCommissionOnCloseOrig stores the pre-adjustment value. (Tier 1 - Trade.PositionTbl)';

