-- main.compliance.gold_sql_dp_prod_we_bi_db_dbo_bi_db_aml_subentity_categorization (TABLE, 5 columns)
ALTER TABLE main.compliance.gold_sql_dp_prod_we_bi_db_dbo_bi_db_aml_subentity_categorization ALTER COLUMN `CID` COMMENT 'Customer identifier for the position. (Tier 2 -- SP_PositionPnL, DWH_dbo.Dim_Position.CID)';
ALTER TABLE main.compliance.gold_sql_dp_prod_we_bi_db_dbo_bi_db_aml_subentity_categorization ALTER COLUMN `CountryID` COMMENT 'Primary key. 0=Not available (fallback/placeholder for users whose country cannot be determined), 1-250=countries ordered roughly alphabetically by ISO code. Referenced by Dim_Customer, Fact_BillingDeposit, Dim_CountryBin, V_Dim_Customer. (Tier 1 - Dictionary.Country upstream wiki)';
ALTER TABLE main.compliance.gold_sql_dp_prod_we_bi_db_dbo_bi_db_aml_subentity_categorization ALTER COLUMN `RegulationID` COMMENT 'Regulatory entity ID governing users from this country. Loaded from ComplianceStateDB.Compliance.RegulationCountry via Ext_Dim_Country_Regulation staging. Left join - NULL if country not in compliance mapping. References the regulatory framework (e.g., CySEC, FCA, ASIC). (Tier 2 - SP_Dictionaries_Country_DL_To_Synapse via ComplianceStateDB)';
ALTER TABLE main.compliance.gold_sql_dp_prod_we_bi_db_dbo_bi_db_aml_subentity_categorization ALTER COLUMN `GCID` COMMENT 'Group Customer ID - cross-product identity key linking the same person across eToro products/entities. NULL for older accounts predating GCID introduction. (Tier 1 - Customer.CustomerStatic)';
ALTER TABLE main.compliance.gold_sql_dp_prod_we_bi_db_dbo_bi_db_aml_subentity_categorization ALTER COLUMN `VerificationLevelID` COMMENT 'KYC verification level. FK to Dictionary.VerificationLevel. Values: 0=unverified (34.2%), 1=partial (12.4%), 2=intermediate (6.2%), 3=fully verified (47.1%). Default=0. (Tier 1 - BackOffice.Customer)';

-- main.compliance.gold_sql_dp_prod_we_dwh_dbo_fact_regulationtransfer (TABLE, 19 columns)
ALTER TABLE main.compliance.gold_sql_dp_prod_we_dwh_dbo_fact_regulationtransfer ALTER COLUMN `DateID` COMMENT 'Date the correlation was computed for, in YYYYMMDD format. The correlation uses price data from 3 months before this date. (Tier 2 - SP_Dim_Instrument_Correlation_FilterByInstrumentID)';
ALTER TABLE main.compliance.gold_sql_dp_prod_we_dwh_dbo_fact_regulationtransfer ALTER COLUMN `CID` COMMENT 'Customer ID. Grouping key for all PnL aggregations. FK to Dim_Customer (CID = RealCID). HASH distribution key, part of PK. (Tier 2 - SP_Fact_CustomerUnrealized_PnL)';
ALTER TABLE main.compliance.gold_sql_dp_prod_we_dwh_dbo_fact_regulationtransfer ALTER COLUMN `PositionPnLStocksReal` COMMENT 'Unrealized PnL from real (settled) stock positions only (IsSettled = 1 AND InstrumentTypeID IN (5,6) AND NOT futures). Uses PnLInDollars. (Tier 2 - SP_Fact_CustomerUnrealized_PnL)';
ALTER TABLE main.compliance.gold_sql_dp_prod_we_dwh_dbo_fact_regulationtransfer ALTER COLUMN `PositionPnLCryptoReal` COMMENT 'Unrealized PnL from real (settled) crypto positions only (IsSettled = 1 AND InstrumentTypeID = 10 AND NOT futures). Uses PnLInDollars. (Tier 2 - SP_Fact_CustomerUnrealized_PnL)';
ALTER TABLE main.compliance.gold_sql_dp_prod_we_dwh_dbo_fact_regulationtransfer ALTER COLUMN `PositionPnLFuturesReal` COMMENT 'Total unrealized PnL from all futures positions (IsFuture = 1). Uses PnLInDollars. Added 2024-11-10. (Tier 2 - SP_Fact_CustomerUnrealized_PnL)';
ALTER TABLE main.compliance.gold_sql_dp_prod_we_dwh_dbo_fact_regulationtransfer ALTER COLUMN `PositionPnLStocksMargin` COMMENT 'Unrealized PnL from stock margin positions (SettlementTypeID = 5). Uses PnLInDollars. Added 2025-09-25. (Tier 2 - SP_Fact_CustomerUnrealized_PnL)';
ALTER TABLE main.compliance.gold_sql_dp_prod_we_dwh_dbo_fact_regulationtransfer ALTER COLUMN `RealizedEquity` COMMENT 'Total account value. If History.ActiveCredit.RealizedEquity is non-zero, taken directly; otherwise computed as TotalCash + TotalPositionsAmount + InProcessCashouts. Confluence definition: "Unrealized Equity - the total funds in the account, including profit/loss from open positions. The Portfolio value figure represented on the platform is Unrealized equity." (Tier 2 - SP_Fact_SnapshotEquity)';
ALTER TABLE main.compliance.gold_sql_dp_prod_we_dwh_dbo_fact_regulationtransfer ALTER COLUMN `TotalPositionsAmount` COMMENT 'Sum of all open position amounts (NewAmount) for this CID on this date. Includes all asset classes: CFD, stocks, crypto, futures, margin. Source: open positions (Trade.OpenPositionEndOfDay) + same-day closed positions (History.ClosePositionEndOfDay) minus History.Credit CreditTypeID=13 adjustments. (Tier 2 - SP_Fact_SnapshotEquity_TotalPositionAmount)';
ALTER TABLE main.compliance.gold_sql_dp_prod_we_dwh_dbo_fact_regulationtransfer ALTER COLUMN `TotalCash` COMMENT 'Customer''s total cash balance for the day. Computed as: previous day''s TotalCash (from last row in current year) + sum of TotalCashChange from History.ActiveCredit for @dt. This running-balance approach was introduced 2020-06-07 replacing the direct History.Credit.TotalCash read. (Tier 2 - SP_Fact_SnapshotEquity)';
ALTER TABLE main.compliance.gold_sql_dp_prod_we_dwh_dbo_fact_regulationtransfer ALTER COLUMN `InProcessCashouts` COMMENT 'Sum of pending withdrawal amounts for this CID that have not yet been finalized (statuses other than 3=Processed, 4=Cancelled, 5,6). Includes partially processed amounts for split-payment withdrawals plus associated fees. Computed by SP_Fact_SnapshotEquity_InProcessCashouts from Billing.Withdraw, History.WithdrawAction, and History.WithdrawToFundingAction. (Tier 2 - SP_Fact_SnapshotEquity_InProcessCashouts)';
ALTER TABLE main.compliance.gold_sql_dp_prod_we_dwh_dbo_fact_regulationtransfer ALTER COLUMN `TotalMirrorPositionsAmount` COMMENT 'Sum of position amounts where MirrorID > 0 AND ParentPositionID != 0 (copy-trading positions only, excluding the parent/guru''s own positions). Represents the CID''s total investment in copy relationships. (Tier 2 - SP_Fact_SnapshotEquity_TotalPositionAmount)';
ALTER TABLE main.compliance.gold_sql_dp_prod_we_dwh_dbo_fact_regulationtransfer ALTER COLUMN `TotalMirrorCash` COMMENT 'Cash available for copy-trading. Formula: TotalCash - Credit. (Tier 2 - SP_Fact_SnapshotEquity)';
ALTER TABLE main.compliance.gold_sql_dp_prod_we_dwh_dbo_fact_regulationtransfer ALTER COLUMN `TotalStockOrders` COMMENT 'Legacy column, hardcoded to 0. Removed 2019-03-03 (Boris Slutski) - no data in PROD since 2015. Kept for schema compatibility. (Tier 2 - SP_Fact_SnapshotEquity)';
ALTER TABLE main.compliance.gold_sql_dp_prod_we_dwh_dbo_fact_regulationtransfer ALTER COLUMN `TotalMirrorStockOrders` COMMENT 'Legacy column, hardcoded to 0. Removed 2019-03-03 alongside TotalStockOrders. Kept for schema compatibility. (Tier 2 - SP_Fact_SnapshotEquity)';
ALTER TABLE main.compliance.gold_sql_dp_prod_we_dwh_dbo_fact_regulationtransfer ALTER COLUMN `Credit` COMMENT 'Outstanding credit/bonus balance from History.ActiveCredit. Last credit event per CID per day (selected via ROW_NUMBER partition by CID, ordered by Occurred DESC, CreditID DESC). Negative values represent outstanding obligations. (Tier 2 - SP_Fact_SnapshotEquity)';
ALTER TABLE main.compliance.gold_sql_dp_prod_we_dwh_dbo_fact_regulationtransfer ALTER COLUMN `AUM` COMMENT 'Assets Under Management. Formula: TotalMirrorPositionAmount + TotalCash - Credit. For MERGE INSERT: computed as TotalMirrorPositionsAmount + TotalMirrorCash. Confluence: "AUC (or AUM) on PI Dashboard: Total Unrealized Copy Amount of the Copiers." (Tier 2 - SP_Fact_SnapshotEquity)';
ALTER TABLE main.compliance.gold_sql_dp_prod_we_dwh_dbo_fact_regulationtransfer ALTER COLUMN `BonusCredit` COMMENT 'Bonus credit balance from History.ActiveCredit.BonusCredit. Confluence: "History.Credit.CreditTypeID = 5, 7 -> BackOffice.BonusType.BonusTypeID -> History.Credit.BonusTypeID". ISNULL to 0 in ETL. (Tier 2 - SP_Fact_SnapshotEquity)';
ALTER TABLE main.compliance.gold_sql_dp_prod_we_dwh_dbo_fact_regulationtransfer ALTER COLUMN `TotalStockMarginLoanValue` COMMENT 'Loan value for leveraged stock margin positions: InitForexRate × AmountInUnitsDecimal × InitConversionRate - NewAmount. Only computed when SettlementTypeID = 5 AND Leverage <> 1. Formula updated 2025-12-10 to use InitConversionRate. (Tier 2 - SP_Fact_SnapshotEquity_TotalPositionAmount)';
ALTER TABLE main.compliance.gold_sql_dp_prod_we_dwh_dbo_fact_regulationtransfer ALTER COLUMN `ActualNWA` COMMENT 'Non-Withdrawable Amount (credit-capped net worth). CASE WHEN NetEquity > BonusCredit THEN BonusCredit WHEN NetEquity < 0 THEN 0 ELSE NetEquity END. NetEquity = ISNULL(TotalPositionsAmount,0) + ISNULL(TotalCash,0) + ISNULL(TotalStockOrders,0) + ISNULL(PositionPnL,0). Balance = Liabilities + ActualNWA. (Tier 2 - V_Liabilities computed)';

-- main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned (TABLE, 64 columns)
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `HistoryID` COMMENT 'Intended as a unique key but contains duplicates - NOT reliable as a primary/unique identifier. Do not use for JOINs, deduplication, or row identification. Has no practical use for analysts. (Tier 5 - domain expert)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `GCID` COMMENT 'Global Customer ID - the platform-wide unique customer identifier. References `Dim_Customer.GCID`. (Tier 1 - Customer.CustomerStatic)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `RealCID` COMMENT 'Real-account Customer ID. HASH distribution key. References `Dim_Customer.RealCID`. Each customer has one real CID. (Tier 1 - Customer.CustomerStatic)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `DemoCID` COMMENT 'Demo-account Customer ID. Always 0 in this table (real accounts only). (Tier 3 - ETL-assigned)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `Occurred` COMMENT 'UTC timestamp when the action occurred. For position opens: when position was opened. For logins: login time. For credits: when the credit was recorded. (Tier 1 - source-dependent)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `IPNumber` COMMENT 'IP address of the customer as a numeric value. Populated for logins and registrations. (Tier 1 - STS/Billing.Login)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `IsReal` COMMENT 'Account type flag. Always 1 in this table (real accounts only). (Tier 3 - ETL-assigned)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `ActionTypeID` COMMENT 'Event type classifier. References `DWH_dbo.Dim_ActionType.ActionTypeID` - JOIN for Name, Category, CategoryID. See Section 2.1 for full mapping. Key filter column - drives which other columns are populated. (Tier 1 - ETL-derived from CreditTypeID/source)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `PlatformTypeID` COMMENT 'Legacy platform type. 0=default (most rows), 99=STS source. Values 1-9 for specific platforms. (Tier 3 - ETL-assigned)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `InstrumentID` COMMENT 'FK to Trade.Instrument. Financial instrument being traded. (Tier 1 - Trade.PositionTbl)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `Amount` COMMENT 'Position size in currency. Must be >= 0. Stored in dollars (PositionOpen divides by 100 from cents). (Tier 1 - Trade.PositionTbl)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `Leverage` COMMENT 'Leverage multiplier (1, 5, 10, etc.). Determines margin and settlement type. (Tier 1 - Trade.PositionTbl)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `NetProfit` COMMENT 'Realized PnL. 0 when open; set on close. In position currency. (Tier 1 - Trade.PositionTbl)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `Commission` COMMENT 'Open commission in dollars. PositionOpen stores @Commission/100 (cents to dollars). (Tier 1 - Trade.PositionTbl)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `PositionID` COMMENT 'Primary key. Allocated by Internal.GetPositionID_Bigint. Unique per position. (Tier 1 - Trade.PositionTbl)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `CampaignID` COMMENT 'Marketing campaign identifier. 0 if not campaign-related. References `DWH_dbo.Dim_Campaign.CampaignID` - JOIN for Code, Description, StartDate, EndDate, MaxBonusAmount, IsActive. (Tier 5 - domain expert)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `BonusTypeID` COMMENT 'Bonus type for bonus events (ActionTypeID=9). 0 for non-bonus events. References `DWH_dbo.Dim_BonusType.BonusTypeID` - JOIN for Name, IsWithdrawable, IsActive. (Tier 5 - domain expert)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `FundingTypeID` COMMENT 'Payment method used for deposits/withdrawals. 0 for non-deposit events. References `DWH_dbo.Dim_FundingType.FundingTypeID` - JOIN for Name, IsNewStyle, IsSingleFunding, IsCashoutActive. (Tier 5 - domain expert)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `LoginID` COMMENT 'Login session identifier from `Billing.Login`. 0 for non-login events. (Tier 1 - Billing.Login)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `MirrorID` COMMENT 'FK to Trade.Mirror. 0/NULL = manual. Positive = copy-trade position. (Tier 1 - Trade.PositionTbl)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `WithdrawID` COMMENT 'Withdrawal request ID for cashout events. 0 for non-cashout events. (Tier 1 - History.Credit)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `DurationInSeconds` COMMENT 'Duration of a login session in seconds. NULL for non-login events. (Tier 1 - Billing.Login)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `PostID` COMMENT 'Social post/comment GUID for social engagement events (ActionTypeID 21-26). NULL for non-social events. (Tier 1 - Social platform)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `CaseID` COMMENT 'CRM case identifier for ActionTypeID=31 (Open CRM Case). 0 otherwise. (Tier 1 - CRM)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `DateID` COMMENT 'Date of the action as integer YYYYMMDD. Derived from `Occurred`. Part of nonclustered indexes. (Tier 2 - ETL-computed)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `TimeID` COMMENT 'Hour of the action (0-23). Derived from `DATEPART(HOUR, Occurred)`. (Tier 2 - ETL-computed)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `StatusID` COMMENT 'Row status. Nearly always 1 (active). NULL for ~2M rows. (Tier 3 - ETL-assigned)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `PreviousOccurred` COMMENT 'Deprecated/unused column. NULL for most rows - not reliably populated. Do not use. (Tier 5 - domain expert)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `CompensationReasonID` COMMENT 'Compensation reason for compensation events (ActionTypeID=36) and position opens (for airdrop identification). References `BackOffice.CompensationReason`. 0 for non-compensation events. (Tier 1 - History.Credit, updated 2025-12-21)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `WithdrawPaymentID` COMMENT 'Payment processing ID for cashout/withdrawal events. 0 for non-cashout events. Used to deduplicate WithdrawProcessingID rows in the ETL. (Tier 1 - History.Credit)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `CommissionOnClose` COMMENT 'Commission charged on close. DWH note: adjusted by SP_Dim_Position when position is reopened; CommissionOnCloseOrig stores the pre-adjustment value. (Tier 1 - Trade.PositionTbl)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `IsPlug` COMMENT 'Deprecated/unused column. Always NULL. (Tier 5 - domain expert)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `DepositID` COMMENT 'Deposit transaction identifier. NULL for non-deposit events. (Tier 1 - History.Credit)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `PostRootID` COMMENT 'Root post ID for social engagement events. NULL for non-social events. (Tier 1 - Social platform)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `FullCommission` COMMENT 'Full commission including spread. PositionOpen stores @FullCommission/100. (Tier 1 - Trade.PositionTbl)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `FullCommissionOnClose` COMMENT 'Full commission on close. DWH note: adjusted by SP_Dim_Position when position is reopened; FullCommissionOnCloseOrig stores the pre-adjustment value. (Tier 1 - Trade.PositionTbl)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `RedeemID` COMMENT 'Billing.Redeem reference when position closed via redeem. (Tier 1 - Trade.PositionTbl)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `RedeemStatus` COMMENT 'Redemption state. Billing.Redeem integration. (Tier 1 - Trade.PositionTbl)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `SessionID` COMMENT 'STS session identifier for logins and position opens. For manual opens: from login session. For copy opens: from mirror session. NULL for other events. (Tier 1 - STS)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `IsRedeem` COMMENT 'Redeem flag. 0=not a redeem, 1=is a redeem. NULL for non-position events. Same meaning as `Dim_Position.IsRedeem` (via RedeemStatus mapping). (Tier 3 - ETL-derived)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `RegulationIDOnOpen` COMMENT 'Regulatory jurisdiction ID at time of position open. ETL-computed via JOIN to etoro_History_BackOfficeCustomer (customer''s regulation history). ISNULL(..., 0) when no regulation match found. (Tier 2 - SP_Dim_Position_DL_To_Synapse)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `PlatformID` COMMENT 'Product/platform identifier - badly named, actually references `Dim_Product.ProductID` (not a standalone platform enum). Resolves to Product, Platform, and SubPlatform via JOIN to `DWH_dbo.Dim_Product`. Only populated for ActionTypeID=14 (logins) and 41 (registrations). (Tier 5 - domain expert)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `ReopenForPositionID` COMMENT 'When position was reopened: references the erroneously closed PositionID. (Tier 1 - Trade.PositionTbl)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `IsReOpen` COMMENT '1=this position was reopened from ReopenForPositionID. ETL-computed: CASE WHEN ReopenForPositionID IS NOT NULL THEN 1. Default 0. (Tier 2 - SP_Dim_Position_DL_To_Synapse)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `CommissionOnCloseOrig` COMMENT 'Original CommissionOnClose before reopen adjustments. ETL: CASE WHEN ReopenForPositionID IS NOT NULL THEN CommissionOnClose ELSE 0. (Tier 2 - SP_Dim_Position_DL_To_Synapse)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `FullCommissionOnCloseOrig` COMMENT 'Original FullCommissionOnClose before reopen. ETL default 0. (Tier 2 - SP_Dim_Position_DL_To_Synapse)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `OriginalPositionID` COMMENT 'Original position ID for positions split by partial close. (Tier 2 - SP_Dim_Position_DL_To_Synapse)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `IsPartialCloseParent` COMMENT '1=this position was partially closed (is the parent in a partial close event). (Tier 2 - SP_Dim_Position_DL_To_Synapse)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `IsPartialCloseChild` COMMENT '1=this position is the child (remainder) of a partial close event. Generally filter out child positions from most metrics on OPEN when aggregating, but not all (e.g., volume is already pro-rated so excluding these is wrong). NEVER filter these out on CLOSE. (Tier 5 — domain expert, SP_Dim_Position_DL_To_Synapse)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `InitialUnits` COMMENT 'Original unit count at open. Used for partial close ratio. (Tier 1 - Trade.PositionTbl)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `PaymentStatusID` COMMENT 'Payment processing status for deposit/cashout events. NULL for non-payment events. References `DWH_dbo.Dim_PaymentStatus.PaymentStatusID` - JOIN for Name. (Tier 5 - domain expert)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `IsDiscounted` COMMENT '1=position received a discounted rate. DWH note: CAST from bit to int. (Tier 1 - Trade.PositionTbl)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `IsSettled` COMMENT '1 = real asset, 0 = CFD asset. (Tier 5 - Expert Review)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `CommissionByUnits` COMMENT 'Prorated commission for partial close. Formula: (AmountInUnitsDecimal / InitialUnits) * Commission. Used for partial-close PnL. (Tier 1 - Trade.Position)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `FullCommissionByUnits` COMMENT 'Prorated full commission for partial close. Same proration formula as CommissionByUnits applied to FullCommission. (Tier 1 - Trade.Position)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `IsFTD` COMMENT 'First-Time Deposit flag: 1 = this is the customer''s first deposit. NULL for non-deposit events. (Tier 2 - ETL-computed)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `CountryIDByIP` COMMENT 'Country determined by IP geolocation. Populated for logins and registrations. References `DWH_dbo.Dim_Country.CountryID` - JOIN for country name. Also see `DWH_dbo.Dim_CountryIP` for IP-to-country resolution. (Tier 5 - domain expert)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `IsAnonymousIP` COMMENT 'Anonymous IP flag: 1 = connection via anonymous proxy/VPN. NULL for most rows. (Tier 1 - IP geolocation)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `ProxyType` COMMENT 'Proxy classification: DCH=datacenter, VPN=VPN, PUB=public proxy, SES=session proxy, TOR=Tor exit node, WEB=web proxy. NULL for non-proxy connections. (Tier 1 - STS)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `IsFeeDividend` COMMENT 'Fee sub-type for ActionTypeID=35: 1=overnight/weekend fee, 2=dividend, 3=SDRT, 4=ticket fees (OpenTotalFees/CloseTotalFees). NULL for non-fee events. See Section 2.2 and DSM-1463. (Tier 2 - ETL-derived from Description)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `IsAirDrop` COMMENT '1=position was created via an airdrop event (crypto). ETL-computed: JOIN to etoro_Trade_PositionAirdropLog. NULL=not an airdrop. (Tier 2 - SP_Dim_Position_DL_To_Synapse)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `DividendID` COMMENT 'Dividend event identifier for dividend-related fees. NULL for non-dividend events. (Tier 1 - Trade positions)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `MoveMoneyReasonID` COMMENT 'Reason for money movement: 1=Adjustment, 5=InternalTransfer Trade, 6=InternalTransfer, 8=Recurring Deposit, 9=Recurring Investment. References `Dictionary.MoveMoneyReason`. (Tier 1 - History.Credit)';
ALTER TABLE main.compliance_stg.rnd_output_gold_sql_dp_prod_we_dwh_dbo_fact_customeraction_delta_partitionioned ALTER COLUMN `SettlementTypeID` COMMENT 'Modern settlement classification. Dictionary.SettlementTypes: 0=CFD, 1=REAL, 2=TRS, 3=CMT, 4=REAL_FUTURES, 5=MARGIN_TRADE. Replaces IsSettled. (Tier 1 - Trade.PositionTbl)';

-- main.data_rooms.vw_dim_instrument (VIEW, 20 columns)
COMMENT ON COLUMN main.data_rooms.vw_dim_instrument.`InstrumentID` IS 'Primary key identifying the tradeable instrument pair. Allocated by Trade.InstrumentAdd during instrument creation. Ranges from 0 (system placeholder) to ~21 million IDs allocated. Referenced by virtually every trading fact table and the Dim_Currency / Dim_HistorySplitRatio dimension tables. (Tier 1 -- upstream wiki, Trade.Instrument)';
COMMENT ON COLUMN main.data_rooms.vw_dim_instrument.`InstrumentType` IS 'Text label for InstrumentTypeID -- DWH-computed via CASE: 1=Currencies, 2=Commodities, 4=Indices, 5=Stocks, 6=ETF, 10=Crypto Currencies, else=Other. Use InstrumentTypeID for filtering; InstrumentType for display. (Tier 2 -- SP_Dim_Instrument)';
COMMENT ON COLUMN main.data_rooms.vw_dim_instrument.`PipDifferenceThreshold` IS 'Maximum allowed pip difference threshold for price validation. If a new price deviates more than this threshold from the previous price, it may be flagged as suspicious. NULL for some instruments. (Tier 1 -- upstream wiki, Trade.Instrument)';
COMMENT ON COLUMN main.data_rooms.vw_dim_instrument.`IsMajor` IS 'Text version of IsMajorID -- DWH CASE computed: IsMajorID=1->''Yes'', 0->''No''. Use for display. Affects spread calculations and regulatory leverage caps (ESMA allows higher leverage for major forex). (Tier 2 -- SP_Dim_Instrument)';
COMMENT ON COLUMN main.data_rooms.vw_dim_instrument.`InstrumentDisplayName` IS 'User-facing instrument display name from Trade.InstrumentMetaData. More descriptive than Name (e.g., ''Apple Inc.'' vs ''Apple''). NULL for instruments without metadata entries. (Tier 2 -- SP_Dim_Instrument, etoro_Trade_InstrumentMetaData)';
COMMENT ON COLUMN main.data_rooms.vw_dim_instrument.`Industry` IS 'Industry classification string from Trade.InstrumentMetaData. Text description (e.g., ''Internet'', ''Software''). Similar to but may differ from IndustryGroup (Bloomberg). NULL for non-stock instruments or instruments without metadata. (Tier 3 -- live data, etoro_Trade_InstrumentMetaData)';
COMMENT ON COLUMN main.data_rooms.vw_dim_instrument.`CompanyInfo` IS 'Free-text company description from Trade.InstrumentMetaData. May contain multi-sentence business descriptions of the company. NULL for non-company instruments (forex, commodities, indices). (Tier 3 -- live data, etoro_Trade_InstrumentMetaData)';
COMMENT ON COLUMN main.data_rooms.vw_dim_instrument.`Exchange` IS 'Stock exchange name from Trade.InstrumentMetaData (e.g., Nasdaq, NYSE, LSE). NULL for non-stock instruments. (Tier 3 -- live data, etoro_Trade_InstrumentMetaData)';
COMMENT ON COLUMN main.data_rooms.vw_dim_instrument.`Symbol` IS 'Ticker symbol for the instrument (e.g., AAPL, EURUSD, BTCUSD). Used for display, search, and price feed identification. NULL for ID=0 placeholder and some instruments without formal ticker. (Tier 3 -- live data, etoro.Trade.GetInstrument)';
COMMENT ON COLUMN main.data_rooms.vw_dim_instrument.`ReceivedOnPriceServer` IS 'First timestamp when the instrument was observed on the price server (from Ext_Dim_Instrument_ReceivedOnPriceServerStatic). Set once and never updated (static history). NULL for instruments not yet priced or newly added instruments that have not yet appeared in price feeds. (Tier 2 -- SP_Dim_Instrument, post-load UPDATE)';
COMMENT ON COLUMN main.data_rooms.vw_dim_instrument.`BonusCreditUsePercent` IS 'Percentage of bonus credit that can be applied to trading this instrument, from Trade.ProviderToInstrument. Lower values restrict bonus usage for high-risk/volatile instruments. NULL for instruments without ProviderToInstrument mapping. (Tier 3 -- live data, etoro_Trade_ProviderToInstrument)';
COMMENT ON COLUMN main.data_rooms.vw_dim_instrument.`SymbolFull` IS 'Full ticker symbol (may be longer than Symbol), from Trade.InstrumentMetaData. Used for data provider integrations that require fully qualified symbols. NULL for instruments without metadata. (Tier 3 -- live data, etoro_Trade_InstrumentMetaData)';
COMMENT ON COLUMN main.data_rooms.vw_dim_instrument.`CUSIP` IS 'Committee on Uniform Securities Identification Procedures number -- 9-character code for US/Canadian securities. Used for clearing, settlement, and regulatory reporting. NULL for non-US instruments and instruments without CUSIP. (Tier 2 -- SP_Dim_Instrument, etoro_Trade_InstrumentCusip)';
COMMENT ON COLUMN main.data_rooms.vw_dim_instrument.`Precision` IS 'Decimal precision for price display and trading (number of decimal places), from Trade.ProviderToInstrument. Determines how many decimals are shown in the UI and used in calculations. NULL for instruments without ProviderToInstrument mapping. (Tier 3 -- live data, etoro_Trade_ProviderToInstrument)';
COMMENT ON COLUMN main.data_rooms.vw_dim_instrument.`AllowBuy` IS 'Flag indicating if long (buy) positions can currently be opened: 1=allowed, 0=disabled. Cast from bit. NULL for ID=0 placeholder. Instruments may be buy-disabled due to regulatory restrictions, risk management, or market conditions. (Tier 2 -- SP_Dim_Instrument, etoro.Trade.GetInstrument)';
COMMENT ON COLUMN main.data_rooms.vw_dim_instrument.`AllowSell` IS 'Flag indicating if short (sell) positions can currently be opened: 1=allowed, 0=disabled. Cast from bit. NULL for ID=0 placeholder. Many regulated markets prohibit short selling for retail clients. (Tier 2 -- SP_Dim_Instrument, etoro.Trade.GetInstrument)';
COMMENT ON COLUMN main.data_rooms.vw_dim_instrument.`AssetClass` IS 'Bloomberg-style asset class classification from Ext_Dim_Instrument_Classification_Static (e.g., Technology, Consumer Services, Finance). More granular than InstrumentType. NULL for non-stock instruments or instruments not in the classification static table. (Tier 2 -- SP_Dim_Instrument, post-load UPDATE)';
COMMENT ON COLUMN main.data_rooms.vw_dim_instrument.`IndustryGroup` IS 'Bloomberg-style industry group within AssetClass (e.g., Computers, Internet, Banks). Sub-classification of AssetClass. NULL for non-stock instruments or instruments not in the classification table. (Tier 2 -- SP_Dim_Instrument, post-load UPDATE)';
COMMENT ON COLUMN main.data_rooms.vw_dim_instrument.`ADV_Last3Months` IS 'Average Daily Trading Volume over the trailing 3 months (TTM), from Rankings StockInfo MetadataID=8557. In shares/units. NULL for non-stock instruments or instruments without Rankings coverage. Example: Apple ~48M shares/day. (Tier 2 -- SP_Dim_Instrument, Rankings_StockInfo)';
COMMENT ON COLUMN main.data_rooms.vw_dim_instrument.`isfuture` IS 'Derived flag indicating if the instrument is a futures contract: 1=futures, 0=not futures. Computed in SP as CASE WHEN InstrumentID IN (SELECT InstrumentID FROM InstrumentGroups WHERE GroupID=25) THEN 1 ELSE 0. NULL for ID=0 placeholder. (Tier 2 -- SP_Dim_Instrument)';

-- main.data_rooms.vw_fact_customeraction (VIEW, 37 columns)
COMMENT ON COLUMN main.data_rooms.vw_fact_customeraction.`ActionTypeID` IS 'Event type classifier. References `DWH_dbo.Dim_ActionType.ActionTypeID` - JOIN for Name, Category, CategoryID. See Section 2.1 for full mapping. Key filter column - drives which other columns are populated. (Tier 1 - ETL-derived from CreditTypeID/source)';
COMMENT ON COLUMN main.data_rooms.vw_fact_customeraction.`HistoryID` IS 'Intended as a unique key but contains duplicates - NOT reliable as a primary/unique identifier. Do not use for JOINs, deduplication, or row identification. Has no practical use for analysts. (Tier 5 - domain expert)';
COMMENT ON COLUMN main.data_rooms.vw_fact_customeraction.`GCID` IS 'Global Customer ID - the platform-wide unique customer identifier. References `Dim_Customer.GCID`. (Tier 1 - Customer.CustomerStatic)';
COMMENT ON COLUMN main.data_rooms.vw_fact_customeraction.`RealCID` IS 'Real-account Customer ID. HASH distribution key. References `Dim_Customer.RealCID`. Each customer has one real CID. (Tier 1 - Customer.CustomerStatic)';
COMMENT ON COLUMN main.data_rooms.vw_fact_customeraction.`Occurred` IS 'UTC timestamp when the action occurred. For position opens: when position was opened. For logins: login time. For credits: when the credit was recorded. (Tier 1 - source-dependent)';
COMMENT ON COLUMN main.data_rooms.vw_fact_customeraction.`IsReal` IS 'Account type flag. Always 1 in this table (real accounts only). (Tier 3 - ETL-assigned)';
COMMENT ON COLUMN main.data_rooms.vw_fact_customeraction.`PlatformTypeID` IS 'Legacy platform type. 0=default (most rows), 99=STS source. Values 1-9 for specific platforms. (Tier 3 - ETL-assigned)';
COMMENT ON COLUMN main.data_rooms.vw_fact_customeraction.`InstrumentID` IS 'FK to Trade.Instrument. Financial instrument being traded. (Tier 1 - Trade.PositionTbl)';
COMMENT ON COLUMN main.data_rooms.vw_fact_customeraction.`Amount` IS 'Position size in currency. Must be >= 0. Stored in dollars (PositionOpen divides by 100 from cents). (Tier 1 - Trade.PositionTbl)';
COMMENT ON COLUMN main.data_rooms.vw_fact_customeraction.`Leverage` IS 'Leverage multiplier (1, 5, 10, etc.). Determines margin and settlement type. (Tier 1 - Trade.PositionTbl)';
COMMENT ON COLUMN main.data_rooms.vw_fact_customeraction.`NetProfit` IS 'Realized PnL. 0 when open; set on close. In position currency. (Tier 1 - Trade.PositionTbl)';
COMMENT ON COLUMN main.data_rooms.vw_fact_customeraction.`Commission` IS 'Open commission in dollars. PositionOpen stores @Commission/100 (cents to dollars). (Tier 1 - Trade.PositionTbl)';
COMMENT ON COLUMN main.data_rooms.vw_fact_customeraction.`PositionID` IS 'Primary key. Allocated by Internal.GetPositionID_Bigint. Unique per position. (Tier 1 - Trade.PositionTbl)';
COMMENT ON COLUMN main.data_rooms.vw_fact_customeraction.`MirrorID` IS 'FK to Trade.Mirror. 0/NULL = manual. Positive = copy-trade position. (Tier 1 - Trade.PositionTbl)';
COMMENT ON COLUMN main.data_rooms.vw_fact_customeraction.`WithdrawID` IS 'Withdrawal request ID for cashout events. 0 for non-cashout events. (Tier 1 - History.Credit)';
COMMENT ON COLUMN main.data_rooms.vw_fact_customeraction.`DurationInSeconds` IS 'Duration of a login session in seconds. NULL for non-login events. (Tier 1 - Billing.Login)';
COMMENT ON COLUMN main.data_rooms.vw_fact_customeraction.`DateID` IS 'Date of the action as integer YYYYMMDD. Derived from `Occurred`. Part of nonclustered indexes. (Tier 2 - ETL-computed)';
COMMENT ON COLUMN main.data_rooms.vw_fact_customeraction.`TimeID` IS 'Hour of the action (0-23). Derived from `DATEPART(HOUR, Occurred)`. (Tier 2 - ETL-computed)';
COMMENT ON COLUMN main.data_rooms.vw_fact_customeraction.`CompensationReasonID` IS 'Compensation reason for compensation events (ActionTypeID=36) and position opens (for airdrop identification). References `BackOffice.CompensationReason`. 0 for non-compensation events. (Tier 1 - History.Credit, updated 2025-12-21)';
COMMENT ON COLUMN main.data_rooms.vw_fact_customeraction.`WithdrawPaymentID` IS 'Payment processing ID for cashout/withdrawal events. 0 for non-cashout events. Used to deduplicate WithdrawProcessingID rows in the ETL. (Tier 1 - History.Credit)';
COMMENT ON COLUMN main.data_rooms.vw_fact_customeraction.`CommissionOnClose` IS 'Commission charged on close. DWH note: adjusted by SP_Dim_Position when position is reopened; CommissionOnCloseOrig stores the pre-adjustment value. (Tier 1 - Trade.PositionTbl)';
COMMENT ON COLUMN main.data_rooms.vw_fact_customeraction.`DepositID` IS 'Deposit transaction identifier. NULL for non-deposit events. (Tier 1 - History.Credit)';
COMMENT ON COLUMN main.data_rooms.vw_fact_customeraction.`FullCommission` IS 'Full commission including spread. PositionOpen stores @FullCommission/100. (Tier 1 - Trade.PositionTbl)';
COMMENT ON COLUMN main.data_rooms.vw_fact_customeraction.`FullCommissionOnClose` IS 'Full commission on close. DWH note: adjusted by SP_Dim_Position when position is reopened; FullCommissionOnCloseOrig stores the pre-adjustment value. (Tier 1 - Trade.PositionTbl)';
COMMENT ON COLUMN main.data_rooms.vw_fact_customeraction.`RedeemID` IS 'Billing.Redeem reference when position closed via redeem. (Tier 1 - Trade.PositionTbl)';
COMMENT ON COLUMN main.data_rooms.vw_fact_customeraction.`RedeemStatus` IS 'Redemption state. Billing.Redeem integration. (Tier 1 - Trade.PositionTbl)';
COMMENT ON COLUMN main.data_rooms.vw_fact_customeraction.`SessionID` IS 'STS session identifier for logins and position opens. For manual opens: from login session. For copy opens: from mirror session. NULL for other events. (Tier 1 - STS)';
COMMENT ON COLUMN main.data_rooms.vw_fact_customeraction.`IsRedeem` IS 'Redeem flag. 0=not a redeem, 1=is a redeem. NULL for non-position events. Same meaning as `Dim_Position.IsRedeem` (via RedeemStatus mapping). (Tier 3 - ETL-derived)';
COMMENT ON COLUMN main.data_rooms.vw_fact_customeraction.`RegulationIDOnOpen` IS 'Regulatory jurisdiction ID at time of position open. ETL-computed via JOIN to etoro_History_BackOfficeCustomer (customer''s regulation history). ISNULL(..., 0) when no regulation match found. (Tier 2 - SP_Dim_Position_DL_To_Synapse)';
COMMENT ON COLUMN main.data_rooms.vw_fact_customeraction.`PlatformID` IS 'Product/platform identifier - badly named, actually references `Dim_Product.ProductID` (not a standalone platform enum). Resolves to Product, Platform, and SubPlatform via JOIN to `DWH_dbo.Dim_Product`. Only populated for ActionTypeID=14 (logins) and 41 (registrations). (Tier 5 - domain expert)';
COMMENT ON COLUMN main.data_rooms.vw_fact_customeraction.`ReopenForPositionID` IS 'When position was reopened: references the erroneously closed PositionID. (Tier 1 - Trade.PositionTbl)';
COMMENT ON COLUMN main.data_rooms.vw_fact_customeraction.`IsReOpen` IS '1=this position was reopened from ReopenForPositionID. ETL-computed: CASE WHEN ReopenForPositionID IS NOT NULL THEN 1. Default 0. (Tier 2 - SP_Dim_Position_DL_To_Synapse)';
COMMENT ON COLUMN main.data_rooms.vw_fact_customeraction.`IsSettled` IS '1 = real asset, 0 = CFD asset. (Tier 5 - Expert Review)';
COMMENT ON COLUMN main.data_rooms.vw_fact_customeraction.`IsFTD` IS 'First-Time Deposit flag: 1 = this is the customer''s first deposit. NULL for non-deposit events. (Tier 2 - ETL-computed)';
COMMENT ON COLUMN main.data_rooms.vw_fact_customeraction.`IsFeeDividend` IS 'Fee sub-type for ActionTypeID=35: 1=overnight/weekend fee, 2=dividend, 3=SDRT, 4=ticket fees (OpenTotalFees/CloseTotalFees). NULL for non-fee events. See Section 2.2 and DSM-1463. (Tier 2 - ETL-derived from Description)';
COMMENT ON COLUMN main.data_rooms.vw_fact_customeraction.`IsAirDrop` IS '1=position was created via an airdrop event (crypto). ETL-computed: JOIN to etoro_Trade_PositionAirdropLog. NULL=not an airdrop. (Tier 2 - SP_Dim_Position_DL_To_Synapse)';
COMMENT ON COLUMN main.data_rooms.vw_fact_customeraction.`MoveMoneyReasonID` IS 'Reason for money movement: 1=Adjustment, 5=InternalTransfer Trade, 6=InternalTransfer, 8=Recurring Deposit, 9=Recurring Investment. References `Dictionary.MoveMoneyReason`. (Tier 1 - History.Credit)';

