ALTER TABLE main.dealing.bronze_pricelog_history_currencyprice_active ALTER COLUMN `PriceRateID` COMMENT 'Tick-level rate identifier. Key for joining to Dim_Position.OpenMarketPriceRateID and CloseMarketPriceRateID for P&L calculation. (Tier 1 - upstream wiki, Trade.CurrencyPrice)';
ALTER TABLE main.dealing.bronze_pricelog_history_currencyprice_active ALTER COLUMN `ReceivedOnPriceServer` COMMENT 'Timestamp when eToro price server received this tick. Used by SP_Dim_Instrument to detect instrument recency: "last tick received for this instrument". (Tier 2 - SP_Dim_Instrument usage: min(ReceivedOnPriceServer) for instrument last seen)';
ALTER TABLE main.dealing.bronze_pricelog_history_currencyprice_active ALTER COLUMN `LiquidityAccountID` COMMENT 'Liquidity account that provided this price tick. Links to internal liquidity routing configuration. (Tier 4 - inferred from column name)';
