ALTER TABLE main.dealing.bronze_pricelog_history_currencyprice_active ALTER COLUMN `RateLastEx` COMMENT 'Last executed rate at this tick; view vs execution rates can differ when the market moves between quote and fill. (Tier 4 - Confluence, Rates / prices (Buy, Sell, Bid, Ask))';
ALTER TABLE main.dealing.bronze_pricelog_history_currencyprice_active ALTER COLUMN `BidSpreaded` COMMENT 'Customer-facing bid after eToro markup spread applied. Lower than raw market Bid for sell orders. (Tier 2 - DDL + SP_Dim_Position usage context)';
ALTER TABLE main.dealing.bronze_pricelog_history_currencyprice_active ALTER COLUMN `AskSpreaded` COMMENT 'Customer-facing ask after eToro markup spread applied. Higher than raw market Ask for buy orders. (Tier 2 - DDL + SP_Dim_Position usage context)';
