ALTER TABLE main.dealing.bronze_pricelog_history_currencyprice_active ALTER COLUMN `AskMarketPriceRateID` COMMENT 'Market price rate ID specifically for the ask side. (Tier 1 - upstream wiki, Trade.CurrencyPrice)';
