ALTER TABLE main.dealing.bronze_pricelog_history_currencyprice_active ALTER COLUMN `SkewValueBid` COMMENT 'Asymmetric spread skew applied to the bid side for risk management. Adjusts effective bid rate. (Tier 2 - DDL structure)';
ALTER TABLE main.dealing.bronze_pricelog_history_currencyprice_active ALTER COLUMN `SkewValueAsk` COMMENT 'Asymmetric spread skew applied to the ask side. (Tier 2 - DDL structure)';

