ALTER TABLE main.dealing.gold_sql_dp_prod_we_dealing_dbo_v_dealing_duco_eodrecon ALTER COLUMN `eToroUSDAmount` COMMENT 'LP hedge position value converted to USD via FXratetoUSD. (Tier 2 -- SP_DataForDuco, computed: eToroLocalAmount × FXratetoUSD)';
ALTER TABLE main.dealing.gold_sql_dp_prod_we_dealing_dbo_v_dealing_duco_eodrecon ALTER COLUMN `ClientAmount` COMMENT 'Client NOP position value in USD. (Tier 2 -- SP_DataForDuco, BI_DB_dbo.BI_DB_PositionPnL.NOP via FX conversion)';
ALTER TABLE main.dealing.gold_sql_dp_prod_we_dealing_dbo_v_dealing_duco_eodrecon ALTER COLUMN `eToroRate` COMMENT 'Average rate of the eToro hedge holding (LP-side weighted average price). (Tier 2 -- SP_DataForDuco, Dealing_staging.etoro_Hedge_Netting.Rate)';
ALTER TABLE main.dealing.gold_sql_dp_prod_we_dealing_dbo_v_dealing_duco_eodrecon ALTER COLUMN `HedgingPercent` COMMENT 'eToro_Units / ClientUnits - hedge coverage ratio (1.0 = fully hedged). (Tier 2 -- SP_DataForDuco, computed: eToro_Units / NULLIF(ClientUnits, 0))';
ALTER TABLE main.dealing.gold_sql_dp_prod_we_dealing_dbo_v_dealing_duco_eodrecon ALTER COLUMN `Clients_Units_Buy` COMMENT 'Client units on the buy side (long positions). (Tier 2 -- SP_DataForDuco, BI_DB_dbo.BI_DB_PositionPnL where IsBuy=1)';
ALTER TABLE main.dealing.gold_sql_dp_prod_we_dealing_dbo_v_dealing_duco_eodrecon ALTER COLUMN `Clients_Units_Sell` COMMENT 'Client units on the sell side (short positions). (Tier 2 -- SP_DataForDuco, BI_DB_dbo.BI_DB_PositionPnL where IsBuy=0)';
ALTER TABLE main.dealing.gold_sql_dp_prod_we_dealing_dbo_v_dealing_duco_eodrecon ALTER COLUMN `Clients_NOP_Buy` COMMENT 'Client NOP USD value for buy (long) positions. (Tier 2 -- SP_DataForDuco, BI_DB_dbo.BI_DB_PositionPnL NOP buy-side)';
ALTER TABLE main.dealing.gold_sql_dp_prod_we_dealing_dbo_v_dealing_duco_eodrecon ALTER COLUMN `Clients_NOP_Sell` COMMENT 'Client NOP USD value for sell (short) positions. (Tier 2 -- SP_DataForDuco, BI_DB_dbo.BI_DB_PositionPnL NOP sell-side)';
ALTER TABLE main.dealing.gold_sql_dp_prod_we_dealing_dbo_v_dealing_duco_eodrecon ALTER COLUMN `FXratetoUSD` COMMENT 'FX rate from instrument currency to USD for amount conversion. (Tier 2 -- SP_DataForDuco, DWH_dbo.Fact_CurrencyPriceWithSplit)';

-- main.dwh.gold_inc_test_dwh_dbo_fact_billingredeem (TABLE, 11 columns)
ALTER TABLE main.dwh.gold_inc_test_dwh_dbo_fact_billingredeem ALTER COLUMN `CID` COMMENT 'Customer ID. Identifies the eToro customer who initiated the redeem request. References DWH_dbo.Dim_Customer. Primary join key for customer-level redeem analytics. (Tier 2 - SP_Fact_BillingRedeem_DL_To_Synapse)';
ALTER TABLE main.dwh.gold_inc_test_dwh_dbo_fact_billingredeem ALTER COLUMN `RedeemID` COMMENT 'Primary key for the redeem request. Distribution key (HASH). Uniquely identifies each redeem operation across the platform. Non-clustered index key for point lookups. (Tier 2 - SP_Fact_BillingRedeem_DL_To_Synapse)';
ALTER TABLE main.dwh.gold_inc_test_dwh_dbo_fact_billingredeem ALTER COLUMN `PositionID` COMMENT 'Trading position being redeemed. References the copy-trading position that is being closed/liquidated. BIGINT to accommodate the large position ID space. (Tier 2 - SP_Fact_BillingRedeem_DL_To_Synapse)';
ALTER TABLE main.dwh.gold_inc_test_dwh_dbo_fact_billingredeem ALTER COLUMN `RedeemStatusID` COMMENT 'Current processing status of the redeem request. References DWH_dbo.Dim_RedeemStatus (documented in Batch 9). Tracks the lifecycle from submission through approval/rejection/processing. (Tier 2 - SP_Fact_BillingRedeem_DL_To_Synapse)';
ALTER TABLE main.dwh.gold_inc_test_dwh_dbo_fact_billingredeem ALTER COLUMN `RedeemReasonID` COMMENT 'Reason code explaining why the redeem was initiated. References DWH_dbo.Dim_RedeemReason (documented in Batch 9). NULL when no specific reason was recorded. (Tier 2 - SP_Fact_BillingRedeem_DL_To_Synapse)';
ALTER TABLE main.dwh.gold_inc_test_dwh_dbo_fact_billingredeem ALTER COLUMN `AmountOnRequest` COMMENT 'Position value (in base currency) at the time the redeem request was submitted. Represents what the customer expected to receive. May differ from AmountOnClose if market moved during processing. (Tier 2 - SP_Fact_BillingRedeem_DL_To_Synapse)';
ALTER TABLE main.dwh.gold_inc_test_dwh_dbo_fact_billingredeem ALTER COLUMN `AmountOnClose` COMMENT 'Actual position value (in base currency) at close/settlement time. The final amount processed for the redeem. NULL if not yet settled. (Tier 2 - SP_Fact_BillingRedeem_DL_To_Synapse)';
ALTER TABLE main.dwh.gold_inc_test_dwh_dbo_fact_billingredeem ALTER COLUMN `FundingID` COMMENT 'Payment instrument (funding method) used for this redeem payout. References Billing.Funding. Identifies the credit card, bank account, or e-wallet that received the redeemed funds. (Tier 2 - SP_Fact_BillingRedeem_DL_To_Synapse)';
ALTER TABLE main.dwh.gold_inc_test_dwh_dbo_fact_billingredeem ALTER COLUMN `RequestDate` COMMENT 'Datetime when the redeem request was submitted by the customer. Records the initiation time of the redeem lifecycle. No index - use ModificationDateID for range queries. (Tier 2 - SP_Fact_BillingRedeem_DL_To_Synapse)';
ALTER TABLE main.dwh.gold_inc_test_dwh_dbo_fact_billingredeem ALTER COLUMN `LastModificationDate` COMMENT 'Most recent datetime when this redeem record was modified. Used as the source for ModificationDateID. The ETL 7-day rolling window is based on this field. (Tier 2 - SP_Fact_BillingRedeem_DL_To_Synapse)';
ALTER TABLE main.dwh.gold_inc_test_dwh_dbo_fact_billingredeem ALTER COLUMN `ModificationDateID` COMMENT 'Clustered index key. Integer date in YYYYMMDD format derived from `CONVERT(INT, LastModificationDate)`. The ETL rolling 7-day window operates on this column. Use for date-range queries and partitioning in downstream systems. (Tier 2 - SP_Fact_BillingRedeem_DL_To_Synapse)';

-- main.dwh.gold_sql_dp_prod_we_bi_db_dbo_bi_db_cid_monthlypanel_fulldata (TABLE, 7 columns)
ALTER TABLE main.dwh.gold_sql_dp_prod_we_bi_db_dbo_bi_db_cid_monthlypanel_fulldata ALTER COLUMN `Region` COMMENT '`GROUP BY` key preserved from CID grain; same semantics as CID wiki. (Tier 2 -- SP_Client_Balance_New, BI_DB_Client_Balance_CID_Level_New.Region)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_bi_db_dbo_bi_db_cid_monthlypanel_fulldata ALTER COLUMN `Country` COMMENT '`GROUP BY` key preserved from CID grain; same semantics as CID wiki. (Tier 2 -- SP_Client_Balance_New, BI_DB_Client_Balance_CID_Level_New.Country)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_bi_db_dbo_bi_db_cid_monthlypanel_fulldata ALTER COLUMN `CID` COMMENT 'Customer ID. The eToro platform''s primary customer identifier (RealCID from Fact_SnapshotCustomer). HASH distribution key. One or two rows per CID per DateID depending on transfer status. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_bi_db_dbo_bi_db_cid_monthlypanel_fulldata ALTER COLUMN `CountryID` COMMENT 'Country ID from Fact_SnapshotCustomer. FK -> DWH_dbo.Dim_Country. (Tier 2 - SP_DDR_Customer_Daily_Status)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_bi_db_dbo_bi_db_cid_monthlypanel_fulldata ALTER COLUMN `Channel` COMMENT 'Top-level marketing channel (e.g., "Paid", "Organic", "Affiliate"). Inherited from Ext_Dim_SubChannel_UnifyCode. (Tier 2 - SP_Dim_Affiliate)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_bi_db_dbo_bi_db_cid_monthlypanel_fulldata ALTER COLUMN `SubChannel` COMMENT 'Marketing sub-channel name (e.g., "Affiliate Partners", "SEM Brand"). Inherited from Ext_Dim_SubChannel_UnifyCode. (Tier 2 - SP_Dim_Affiliate)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_bi_db_dbo_bi_db_cid_monthlypanel_fulldata ALTER COLUMN `AffiliateID` COMMENT 'Unique affiliate partner identifier from AffWizz system. Primary key. (Tier 2 - Ext_Dim_Channel_Affiliate_UnifyCode)';

-- main.dwh.gold_sql_dp_prod_we_dwh_dbo_dim_countrybin (TABLE, 1 columns)
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_dim_countrybin ALTER COLUMN `CountryID` COMMENT 'Primary key. 0=Not available (fallback/placeholder for users whose country cannot be determined), 1-250=countries ordered roughly alphabetically by ISO code. Referenced by Dim_Customer, Fact_BillingDeposit, Dim_CountryBin, V_Dim_Customer. (Tier 1 - Dictionary.Country upstream wiki)';

-- main.dwh.gold_sql_dp_prod_we_dwh_dbo_dim_countryip (TABLE, 1 columns)
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_dim_countryip ALTER COLUMN `CountryID` COMMENT 'Primary key. 0=Not available (fallback/placeholder for users whose country cannot be determined), 1-250=countries ordered roughly alphabetically by ISO code. Referenced by Dim_Customer, Fact_BillingDeposit, Dim_CountryBin, V_Dim_Customer. (Tier 1 - Dictionary.Country upstream wiki)';

-- main.dwh.gold_sql_dp_prod_we_dwh_dbo_dim_mirrortype (TABLE, 1 columns)
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_dim_mirrortype ALTER COLUMN `MirrorTypeID` COMMENT '1=Regular, 2=CopyMe, 3=Social Index, 4=Fund (Dictionary.MirrorType). Determines mirror behavior. (Tier 1 - Trade.Mirror)';

-- main.dwh.gold_sql_dp_prod_we_dwh_dbo_dim_platformtype (TABLE, 1 columns)
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_dim_platformtype ALTER COLUMN `Platform` COMMENT 'Platform name label: "Undefined", "Web", "IOS", "Android". Used in reporting dashboards and per-platform analytics. Passthrough from production -- same column name. (Tier 1 - upstream wiki, Dictionary.Platform)';

-- main.dwh.gold_sql_dp_prod_we_dwh_dbo_dim_playerstatusreasons (TABLE, 1 columns)
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_dim_playerstatusreasons ALTER COLUMN `Name` COMMENT 'Human-readable restriction state label. Unique per status. Used in BackOffice UI, compliance reports, and monitoring dashboards. Note: some values have trailing spaces in live data -- apply RTRIM() for string comparisons. (Tier 1 - upstream wiki, Dictionary.PlayerStatus)';

-- main.dwh.gold_sql_dp_prod_we_dwh_dbo_dim_range (TABLE, 1 columns)
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_dim_range ALTER COLUMN `DateRangeID` COMMENT 'SCD2 range key: 12-digit bigint = YYYYMMDD (row open date) + MMDDD (year-end MMDD, typically 1231). E.g., 202603101231 = open 2026-03-10, closes 2026-12-31. Join to Dim_Range for FromDateID + ToDateID. See section 2.1. (Tier 2 - SP_Fact_SnapshotCustomer)';

-- main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_billingdeposit (TABLE, 8 columns)
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_billingdeposit ALTER COLUMN `Commission` COMMENT 'Open commission in dollars. PositionOpen stores @Commission/100 (cents to dollars). (Tier 1 - Trade.PositionTbl)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_billingdeposit ALTER COLUMN `DepositID` COMMENT 'Deposit transaction identifier. NULL for non-deposit events. (Tier 1 - History.Credit)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_billingdeposit ALTER COLUMN `PaymentStatusID` COMMENT 'Payment processing status for deposit/cashout events. NULL for non-payment events. References `DWH_dbo.Dim_PaymentStatus.PaymentStatusID` - JOIN for Name. (Tier 5 - domain expert)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_billingdeposit ALTER COLUMN `Amount` COMMENT 'Position size in currency. Must be >= 0. Stored in dollars (PositionOpen divides by 100 from cents). (Tier 1 - Trade.PositionTbl)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_billingdeposit ALTER COLUMN `IsFTD` COMMENT 'First-Time Deposit flag: 1 = this is the customer''s first deposit. NULL for non-deposit events. (Tier 2 - ETL-computed)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_billingdeposit ALTER COLUMN `FundingTypeID` COMMENT 'Payment method used for deposits/withdrawals. 0 for non-deposit events. References `DWH_dbo.Dim_FundingType.FundingTypeID` - JOIN for Name, IsNewStyle, IsSingleFunding, IsCashoutActive. (Tier 5 - domain expert)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_billingdeposit ALTER COLUMN `SessionID` COMMENT 'STS session identifier for logins and position opens. For manual opens: from login session. For copy opens: from mirror session. NULL for other events. (Tier 1 - STS)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_billingdeposit ALTER COLUMN `PlatformID` COMMENT 'Product/platform identifier - badly named, actually references `Dim_Product.ProductID` (not a standalone platform enum). Resolves to Product, Platform, and SubPlatform via JOIN to `DWH_dbo.Dim_Product`. Only populated for ActionTypeID=14 (logins) and 41 (registrations). (Tier 5 - domain expert)';

-- main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_billingwithdraw (TABLE, 1 columns)
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_billingwithdraw ALTER COLUMN `CardCategory` COMMENT 'Card product category (e.g., "STANDARD", "GOLD", "PLATINUM", "BUSINESS"). NULL when not available. Passthrough from staging. (Tier 2 - SP_Dictionaries_DL_To_Synapse passthrough)';

-- main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_customeraction (TABLE, 6 columns)
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_customeraction ALTER COLUMN `GCID` COMMENT 'Global Customer ID - unique cross-platform identifier linking Real and Demo accounts for the same person. Distribution key. (Tier 2 - SP_Fact_CustomerAction_DL_To_Synapse)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_customeraction ALTER COLUMN `RealCID` COMMENT 'Real-money account Customer ID. NULL when the session is Demo-only. (Tier 2 - SP_Fact_CustomerAction_DL_To_Synapse)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_customeraction ALTER COLUMN `DemoCID` COMMENT 'Virtual/demo account Customer ID. NULL when the session is Real-only. (Tier 2 - SP_Fact_CustomerAction_DL_To_Synapse)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_customeraction ALTER COLUMN `DateID` COMMENT 'Date partition key in YYYYMMDD integer format (e.g. `20210901`). Computed in ETL from the `@Yesterday` parameter: `CONVERT(INT, CONVERT(VARCHAR, DATEADD(DAY, DATEDIFF(DAY, 0, @Yesterday), 0), 112))`. Clustered index and partition column. (Tier 2 - SP_Fact_CustomerAction_DL_To_Synapse)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_customeraction ALTER COLUMN `SessionID` COMMENT 'Unique session identifier assigned by the STS service. Monotonically increasing. (Tier 2 - STS_Audit_UserOperationsData)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_customeraction ALTER COLUMN `ProxyType` COMMENT 'Type of proxy detected for the client IP connection (e.g. VPN, TOR). Sparsely populated - NULL in most observed rows. Added after initial table creation. (Tier 3 - data sampling inference)';

-- main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_customerunrealized_pnl (TABLE, 37 columns)
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_customerunrealized_pnl ALTER COLUMN `CID` COMMENT 'Customer ID of the copier - the person allocating funds to copy a Popular Investor. This is the copier''s RealCID, not the guru''s. Distribution key. (Tier 2 - SP_Fact_Guru_Copiers)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_customerunrealized_pnl ALTER COLUMN `PositionPnL` COMMENT 'Total unrealized PnL in USD across all open positions. Uses V1 formula (PnLInDollars). "The difference between Realized Equity and Unrealized Equity is the Position PnL" (Confluence). (Tier 1 - Fact_CustomerUnrealized_PnL.PositionPnL)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_customerunrealized_pnl ALTER COLUMN `CopyPositionPnL` COMMENT 'Unrealized PnL from copy-trading positions only (MirrorID > 0). (Tier 1 - Fact_CustomerUnrealized_PnL.CopyPositionPnL)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_customerunrealized_pnl ALTER COLUMN `StocksPositionPnL` COMMENT 'Unrealized PnL from stock positions (InstrumentTypeID IN (5,6) AND NOT futures). Both real and CFD, manual and copy. (Tier 1 - Fact_CustomerUnrealized_PnL.StocksPositionPnL)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_customerunrealized_pnl ALTER COLUMN `StandardDeviation` COMMENT 'Portfolio risk: standard deviation computed from instrument covariance matrix. Only for dates >= 2012-12-31. (Tier 1 - Fact_CustomerUnrealized_PnL.StandardDeviation)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_customerunrealized_pnl ALTER COLUMN `CommissionOnOpen` COMMENT 'Sum of opening commissions across all open positions for this CID. (Tier 1 - Fact_CustomerUnrealized_PnL.CommissionOnOpen)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_customerunrealized_pnl ALTER COLUMN `MirrorStocksPositionPnL` COMMENT 'Unrealized PnL from copy-trading stock positions (InstrumentTypeID IN (5,6) AND NOT futures AND MirrorID > 0). (Tier 1 - Fact_CustomerUnrealized_PnL.MirrorStocksPositionPnL)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_customerunrealized_pnl ALTER COLUMN `CryptoPositionPnL` COMMENT 'Unrealized PnL from all crypto positions (InstrumentTypeID = 10 AND NOT futures). Includes real, CFD, manual, and copy. (Tier 1 - Fact_CustomerUnrealized_PnL.CryptoPositionPnL)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_customerunrealized_pnl ALTER COLUMN `ManualCryptoPositionPnL` COMMENT 'Unrealized PnL from manually-opened crypto positions (MirrorID = 0). (Tier 1 - Fact_CustomerUnrealized_PnL.ManualCryptoPositionPnL)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_customerunrealized_pnl ALTER COLUMN `CopyCryptoPositionPnL` COMMENT 'Unrealized PnL from copy-trading crypto positions (MirrorID > 0). (Tier 1 - Fact_CustomerUnrealized_PnL.CopyCryptoPositionPnL)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_customerunrealized_pnl ALTER COLUMN `CopyFundPnL` COMMENT 'Unrealized PnL from copy-fund positions (parent CID had AccountTypeID=9). (Tier 1 - Fact_CustomerUnrealized_PnL.CopyFundPnL)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_customerunrealized_pnl ALTER COLUMN `NOP` COMMENT 'Net Open Position - total signed directional USD exposure across all instruments. Positive = net long, negative = net short. (Tier 1 - Fact_CustomerUnrealized_PnL.NOP)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_customerunrealized_pnl ALTER COLUMN `Notional` COMMENT 'Total absolute USD exposure across all instruments. ABS(NOP) per instrument, summed. Always >= 0. (Tier 1 - Fact_CustomerUnrealized_PnL.Notional)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_customerunrealized_pnl ALTER COLUMN `NOP_Crypto` COMMENT 'Net Open Position for crypto instruments only (InstrumentTypeID = 10 AND NOT futures). (Tier 1 - Fact_CustomerUnrealized_PnL.NOP_Crypto)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_customerunrealized_pnl ALTER COLUMN `Notional_Crypto` COMMENT 'Absolute USD exposure for crypto instruments only. (Tier 1 - Fact_CustomerUnrealized_PnL.Notional_Crypto)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_customerunrealized_pnl ALTER COLUMN `NOP_CFD` COMMENT 'Net Open Position for all CFD positions (IsSettled = 0), all asset classes. (Tier 1 - Fact_CustomerUnrealized_PnL.NOP_CFD)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_customerunrealized_pnl ALTER COLUMN `Notional_CFD` COMMENT 'Absolute USD exposure for all CFD positions. (Tier 1 - Fact_CustomerUnrealized_PnL.Notional_CFD)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_customerunrealized_pnl ALTER COLUMN `NOP_Crypto_CFD` COMMENT 'Net Open Position for crypto CFD positions (InstrumentTypeID = 10 AND IsSettled = 0). (Tier 1 - Fact_CustomerUnrealized_PnL.NOP_Crypto_CFD)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_customerunrealized_pnl ALTER COLUMN `Notional_Crypto_CFD` COMMENT 'Absolute USD exposure for crypto CFD positions. (Tier 1 - Fact_CustomerUnrealized_PnL.Notional_Crypto_CFD)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_customerunrealized_pnl ALTER COLUMN `PositionPnLStocksReal` COMMENT 'Unrealized PnL from real (settled) stock positions only (IsSettled = 1 AND InstrumentTypeID IN (5,6) AND NOT futures). (Tier 1 - Fact_CustomerUnrealized_PnL.PositionPnLStocksReal)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_customerunrealized_pnl ALTER COLUMN `PositionPnLCryptoReal` COMMENT 'Unrealized PnL from real (settled) crypto positions only (IsSettled = 1 AND InstrumentTypeID = 10 AND NOT futures). (Tier 1 - Fact_CustomerUnrealized_PnL.PositionPnLCryptoReal)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_customerunrealized_pnl ALTER COLUMN `CommissionByUnitsCrypto_TRS` COMMENT 'Prorated commission for crypto TRS positions (IsSettled = 0 AND InstrumentTypeID = 10 AND SettlementTypeID = 2). (Tier 1 - Fact_CustomerUnrealized_PnL.CommissionByUnitsCrypto_TRS)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_customerunrealized_pnl ALTER COLUMN `CopyCryptoPositionPnL_TRS` COMMENT 'Unrealized PnL from copy-trading crypto TRS positions (InstrumentTypeID = 10 AND MirrorID > 0 AND SettlementTypeID = 2). (Tier 1 - Fact_CustomerUnrealized_PnL.CopyCryptoPositionPnL_TRS)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_customerunrealized_pnl ALTER COLUMN `CryptoPositionPnL_TRS` COMMENT 'Unrealized PnL from all crypto TRS positions (InstrumentTypeID = 10 AND SettlementTypeID = 2). (Tier 1 - Fact_CustomerUnrealized_PnL.CryptoPositionPnL_TRS)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_customerunrealized_pnl ALTER COLUMN `FullCommissionByUnitsCrypto_TRS` COMMENT 'Full prorated commission for crypto TRS positions (before discounts). (Tier 1 - Fact_CustomerUnrealized_PnL.FullCommissionByUnitsCrypto_TRS)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_customerunrealized_pnl ALTER COLUMN `ManualCryptoPositionPnL_TRS` COMMENT 'Unrealized PnL from manually-opened crypto TRS positions (MirrorID = 0 AND SettlementTypeID = 2). (Tier 1 - Fact_CustomerUnrealized_PnL.ManualCryptoPositionPnL_TRS)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_customerunrealized_pnl ALTER COLUMN `NOP_Crypto_TRS` COMMENT 'Net Open Position for crypto TRS positions (InstrumentTypeID = 10 AND IsSettled = 0 AND SettlementTypeID = 2). (Tier 1 - Fact_CustomerUnrealized_PnL.NOP_Crypto_TRS)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_customerunrealized_pnl ALTER COLUMN `Notional_Crypto_TRS` COMMENT 'Absolute USD exposure for crypto TRS positions. (Tier 1 - Fact_CustomerUnrealized_PnL.Notional_Crypto_TRS)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_customerunrealized_pnl ALTER COLUMN `MirrorRealFuturesPositionPnL` COMMENT 'Unrealized PnL from copy-trading futures positions (IsFuture = 1 AND MirrorID > 0). (Tier 1 - Fact_CustomerUnrealized_PnL.MirrorRealFuturesPositionPnL)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_customerunrealized_pnl ALTER COLUMN `ManualRealFuturesPositionPnL` COMMENT 'Unrealized PnL from manually-opened futures positions (IsFuture = 1 AND MirrorID = 0). (Tier 1 - Fact_CustomerUnrealized_PnL.ManualRealFuturesPositionPnL)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_customerunrealized_pnl ALTER COLUMN `NOP_FuturesReal` COMMENT 'Net Open Position for futures instruments (IsFuture = 1). (Tier 1 - Fact_CustomerUnrealized_PnL.NOP_FuturesReal)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_customerunrealized_pnl ALTER COLUMN `Notional_FuturesReal` COMMENT 'Absolute USD exposure for futures instruments. (Tier 1 - Fact_CustomerUnrealized_PnL.Notional_FuturesReal)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_customerunrealized_pnl ALTER COLUMN `PositionPnLFuturesReal` COMMENT 'Total unrealized PnL from all futures positions (IsFuture = 1). (Tier 1 - Fact_CustomerUnrealized_PnL.PositionPnLFuturesReal)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_customerunrealized_pnl ALTER COLUMN `FullCommissionByUnitsFuturesReal` COMMENT 'Full prorated commission for futures positions (before discounts). (Tier 1 - Fact_CustomerUnrealized_PnL.FullCommissionByUnitsFuturesReal)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_customerunrealized_pnl ALTER COLUMN `CommissionByUnitsFuturesReal` COMMENT 'Prorated commission for futures positions (IsFuture = 1). (Tier 1 - Fact_CustomerUnrealized_PnL.CommissionByUnitsFuturesReal)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_customerunrealized_pnl ALTER COLUMN `NOP_StocksMargin` COMMENT 'Net Open Position for stock margin positions (SettlementTypeID = 5). (Tier 1 - Fact_CustomerUnrealized_PnL.NOP_StocksMargin)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_customerunrealized_pnl ALTER COLUMN `PositionPnLStocksMargin` COMMENT 'Unrealized PnL from stock margin positions (SettlementTypeID = 5). (Tier 1 - Fact_CustomerUnrealized_PnL.PositionPnLStocksMargin)';

-- main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_firstcustomeraction (TABLE, 24 columns)
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_firstcustomeraction ALTER COLUMN `GCID` COMMENT 'Global Customer ID - the platform-wide unique customer identifier. References `Dim_Customer.GCID`. (Tier 1 - Customer.CustomerStatic)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_firstcustomeraction ALTER COLUMN `RealCID` COMMENT 'Real-account Customer ID. HASH distribution key. References `Dim_Customer.RealCID`. Each customer has one real CID. (Tier 1 - Customer.CustomerStatic)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_firstcustomeraction ALTER COLUMN `DemoCID` COMMENT 'Demo-account Customer ID. Always 0 in this table (real accounts only). (Tier 3 - ETL-assigned)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_firstcustomeraction ALTER COLUMN `IPNumber` COMMENT 'IP address of the customer as a numeric value. Populated for logins and registrations. (Tier 1 - STS/Billing.Login)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_firstcustomeraction ALTER COLUMN `IsReal` COMMENT 'Account type flag. Always 1 in this table (real accounts only). (Tier 3 - ETL-assigned)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_firstcustomeraction ALTER COLUMN `ActionTypeID` COMMENT 'Event type classifier. References `DWH_dbo.Dim_ActionType.ActionTypeID` - JOIN for Name, Category, CategoryID. See Section 2.1 for full mapping. Key filter column - drives which other columns are populated. (Tier 1 - ETL-derived from CreditTypeID/source)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_firstcustomeraction ALTER COLUMN `PlatformTypeID` COMMENT 'Legacy platform type. 0=default (most rows), 99=STS source. Values 1-9 for specific platforms. (Tier 3 - ETL-assigned)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_firstcustomeraction ALTER COLUMN `InstrumentID` COMMENT 'FK to Trade.Instrument. Financial instrument being traded. (Tier 1 - Trade.PositionTbl)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_firstcustomeraction ALTER COLUMN `Amount` COMMENT 'Position size in currency. Must be >= 0. Stored in dollars (PositionOpen divides by 100 from cents). (Tier 1 - Trade.PositionTbl)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_firstcustomeraction ALTER COLUMN `PositionID` COMMENT 'Primary key. Allocated by Internal.GetPositionID_Bigint. Unique per position. (Tier 1 - Trade.PositionTbl)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_firstcustomeraction ALTER COLUMN `CampaignID` COMMENT 'Marketing campaign identifier. 0 if not campaign-related. References `DWH_dbo.Dim_Campaign.CampaignID` - JOIN for Code, Description, StartDate, EndDate, MaxBonusAmount, IsActive. (Tier 5 - domain expert)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_firstcustomeraction ALTER COLUMN `BonusTypeID` COMMENT 'Bonus type for bonus events (ActionTypeID=9). 0 for non-bonus events. References `DWH_dbo.Dim_BonusType.BonusTypeID` - JOIN for Name, IsWithdrawable, IsActive. (Tier 5 - domain expert)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_firstcustomeraction ALTER COLUMN `FundingTypeID` COMMENT 'Payment method used for deposits/withdrawals. 0 for non-deposit events. References `DWH_dbo.Dim_FundingType.FundingTypeID` - JOIN for Name, IsNewStyle, IsSingleFunding, IsCashoutActive. (Tier 5 - domain expert)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_firstcustomeraction ALTER COLUMN `LoginID` COMMENT 'Login session identifier from `Billing.Login`. 0 for non-login events. (Tier 1 - Billing.Login)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_firstcustomeraction ALTER COLUMN `MirrorID` COMMENT 'FK to Trade.Mirror. 0/NULL = manual. Positive = copy-trade position. (Tier 1 - Trade.PositionTbl)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_firstcustomeraction ALTER COLUMN `WithdrawID` COMMENT 'Withdrawal request ID for cashout events. 0 for non-cashout events. (Tier 1 - History.Credit)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_firstcustomeraction ALTER COLUMN `PostID` COMMENT 'Social post/comment GUID for social engagement events (ActionTypeID 21-26). NULL for non-social events. (Tier 1 - Social platform)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_firstcustomeraction ALTER COLUMN `CaseID` COMMENT 'CRM case identifier for ActionTypeID=31 (Open CRM Case). 0 otherwise. (Tier 1 - CRM)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_firstcustomeraction ALTER COLUMN `DateID` COMMENT 'Date of the action as integer YYYYMMDD. Derived from `Occurred`. Part of nonclustered indexes. (Tier 2 - ETL-computed)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_firstcustomeraction ALTER COLUMN `TimeID` COMMENT 'Hour of the action (0-23). Derived from `DATEPART(HOUR, Occurred)`. (Tier 2 - ETL-computed)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_firstcustomeraction ALTER COLUMN `CompensationReasonID` COMMENT 'Compensation reason for compensation events (ActionTypeID=36) and position opens (for airdrop identification). References `BackOffice.CompensationReason`. 0 for non-compensation events. (Tier 1 - History.Credit, updated 2025-12-21)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_firstcustomeraction ALTER COLUMN `WithdrawPaymentID` COMMENT 'Payment processing ID for cashout/withdrawal events. 0 for non-cashout events. Used to deduplicate WithdrawProcessingID rows in the ETL. (Tier 1 - History.Credit)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_firstcustomeraction ALTER COLUMN `DepositID` COMMENT 'Deposit transaction identifier. NULL for non-deposit events. (Tier 1 - History.Credit)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_fact_firstcustomeraction ALTER COLUMN `HistoryID` COMMENT 'Intended as a unique key but contains duplicates - NOT reliable as a primary/unique identifier. Do not use for JOINs, deduplication, or row identification. Has no practical use for analysts. (Tier 5 - domain expert)';

-- main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_dim_mirror (TABLE, 25 columns)
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_dim_mirror ALTER COLUMN `MirrorID` COMMENT 'Primary key. Allocated by identity on INSERT via Trade.RegisterMirror. Referenced by Trade.Position.MirrorID, History.Mirror. (Tier 1 - Trade.Mirror)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_dim_mirror ALTER COLUMN `CID` COMMENT 'Copier customer ID. The user who allocates money to follow the leader. Trade.ValidateNumOfActiveMirrors counts mirrors per CID. (Tier 1 - Trade.Mirror)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_dim_mirror ALTER COLUMN `ParentCID` COMMENT 'Leader customer ID. The user whose trades are copied. Trade.GetActiveCopiersForParents filters by ParentCID. (Tier 1 - Trade.Mirror)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_dim_mirror ALTER COLUMN `ParentUserName` COMMENT 'Leader username at mirror creation. Denormalized for display; Trade.RegisterMirror passes from caller. (Tier 1 - Trade.Mirror)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_dim_mirror ALTER COLUMN `Amount` COMMENT 'Allocation amount in dollars. Credit allocated to this mirror. Trade.RegisterMirror sets from @AmountInCents/100. (Tier 1 - Trade.Mirror)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_dim_mirror ALTER COLUMN `OpenOccurred` COMMENT 'Datetime the copy relationship was opened (started). From Trade.Mirror.Occurred. Covers back to 2011-06-13 (first CopyTrader launch). (Tier 2 - SP_Dim_Mirror_DL_To_Synapse)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_dim_mirror ALTER COLUMN `OpenDateID` COMMENT 'yyyymmdd integer of OpenOccurred. Clustered index key -- use for efficient date-range filtering. ETL-computed: `convert(int, convert(varchar, dateadd(day, datediff(day, 0, Occurred), 0), 112))`. (Tier 2 - SP_Dim_Mirror_DL_To_Synapse)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_dim_mirror ALTER COLUMN `CloseOccurred` COMMENT 'Datetime the copy relationship was closed. ''1900-01-01 00:00:00'' sentinel = still open (CloseDateID=0). For closed mirrors, this is History.Mirror.ModificationDate at the close event. (Tier 2 - SP_Dim_Mirror_DL_To_Synapse)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_dim_mirror ALTER COLUMN `CloseDateID` COMMENT 'yyyymmdd integer of CloseOccurred. 0 = open mirror (active); > 0 = closed on that date. Primary filter for open/closed status. (Tier 2 - SP_Dim_Mirror_DL_To_Synapse)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_dim_mirror ALTER COLUMN `MirrorTypeID` COMMENT '1=Regular, 2=CopyMe, 3=Social Index, 4=Fund (Dictionary.MirrorType). Determines mirror behavior. (Tier 1 - Trade.Mirror)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_dim_mirror ALTER COLUMN `CloseMirrorActionType` COMMENT 'Why mirror closed: 0=Customer, 1=Stop Loss, 2=BSL, 3=Manual Liquidation, 4=BackOffice, 5=Customer Detach, 6=BackOffice Detach (Dictionary.CloseMirrorActionType). NULL when active. (Tier 1 - Trade.Mirror)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_dim_mirror ALTER COLUMN `IsActive` COMMENT '1=mirror is live (copier follows leader), 0=mirror closed. Trade.ChangeMirrorState, Trade.PostClosePositionActions update. (Tier 1 - Trade.Mirror)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_dim_mirror ALTER COLUMN `IsOpenOpen` COMMENT 'Flag for open-on-open copy behavior. NULL in sample data. Used by copy logic. (Tier 1 - Trade.Mirror)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_dim_mirror ALTER COLUMN `PauseCopy` COMMENT '0=copying, 1=paused. No new positions when paused. Trade.MirrorPauseCopy updates. (Tier 1 - Trade.Mirror)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_dim_mirror ALTER COLUMN `MirrorSL` COMMENT 'Absolute mirror stop-loss threshold in dollars. Trade.RegisterMirror validates against MirrorSLPercentage. (Tier 1 - Trade.Mirror)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_dim_mirror ALTER COLUMN `MirrorSLPercentage` COMMENT 'MSL as percentage. Default 2. Trade.RegisterMirror validates MirrorSL = Amount * (MirrorSLPercentage/100). (Tier 1 - Trade.Mirror)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_dim_mirror ALTER COLUMN `RealizedEquity` COMMENT 'Realized equity for this mirror. Used with MirrorCalculationType=0 for MSL. Updated on position close. (Tier 1 - Trade.Mirror)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_dim_mirror ALTER COLUMN `InitialInvestment` COMMENT 'Initial allocation. Trade.RegisterMirror sets from @AmountInDollars or @InitialInvestment. (Tier 1 - Trade.Mirror)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_dim_mirror ALTER COLUMN `WithdrawalSummary` COMMENT 'Sum of withdrawals from mirror. (Tier 1 - Trade.Mirror)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_dim_mirror ALTER COLUMN `DepositSummary` COMMENT 'Sum of deposits into mirror. Trade.RegisterMirror accepts from caller. (Tier 1 - Trade.Mirror)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_dim_mirror ALTER COLUMN `RealziedPnL` COMMENT 'Net realized profit/loss of the mirror in USD. NOTE: column name has a typo (''Realzied'' not ''Realized'') - use exact spelling in queries. For closed mirrors: final P&L from History.Mirror.NetProfit. For open mirrors: running net profit. Upstream: DWH column RealziedPnL maps to Trade.Mirror.NetProfit. (Tier 1 - Trade.Mirror)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_dim_mirror ALTER COLUMN `GuruTPV` COMMENT 'Guru/leader take-profit value. NULL in sample. Optional override. (Tier 1 - Trade.Mirror)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_dim_mirror ALTER COLUMN `UseCopyDividend` COMMENT '1=copy dividends to copier, 0=do not. Trade.MirrorDividendWithdrawal checks. (Tier 1 - Trade.Mirror)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_dim_mirror ALTER COLUMN `SessionID` COMMENT 'Session identifier from History.Mirror.SessionID at the mirror open event (MirrorOperationID=1). Links the mirror opening to a specific trading session. NULL for older historical mirrors predating SessionID tracking. (Tier 2 - SP_Dim_Mirror_DL_To_Synapse)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_dim_mirror ALTER COLUMN `IsCopyFundMirror` COMMENT '1 if the ParentCID is an eToro Fund account (BackOffice AccountTypeID=9); 0 or NULL for regular customer-to-customer copies. Derived post-load from BackOffice_Customer data. Fund mirrors (IsCopyFundMirror=1) overlap with MirrorTypeID=4. (Tier 2 - SP_Dim_Mirror_DL_To_Synapse)';

-- main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_fact_snapshotequity_fromdateid (TABLE, 27 columns)
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_fact_snapshotequity_fromdateid ALTER COLUMN `FromDateID` COMMENT 'Start date of the range in YYYYMMDD integer format. Derived from DateRangeID: LEFT(DateRangeID, 8). Range: 20070101 to 20260310. (Tier 2 - SP code: SP_Fact_SnapshotEquity)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_fact_snapshotequity_fromdateid ALTER COLUMN `ToDateID` COMMENT 'End date of the range in YYYYMMDD integer format. Derived from DateRangeID: YYYY(From) + MMDD(last 4 chars of DateRangeID). The year of ToDate always equals the year of FromDate. Range: 20070826 to 20261231. (Tier 2 - SP code: SP_Fact_SnapshotEquity)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_fact_snapshotequity_fromdateid ALTER COLUMN `DateRangeID` COMMENT 'Primary key (NOT ENFORCED). 12-digit composite key encoding FromDate and MMDD(ToDate). Formula: CONCAT(YYYYMMDD(From), MMDD(To)). Example: 200701011231 = From:20070101, To:20071231. (Tier 2 - SP code: SP_Fact_SnapshotEquity)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_fact_snapshotequity_fromdateid ALTER COLUMN `CID` COMMENT 'Customer ID. Grouping key for all equity aggregations. FK to Dim_Customer (CID = RealCID). HASH distribution key and part of PK. (Tier 2 - SP_Fact_SnapshotEquity)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_fact_snapshotequity_fromdateid ALTER COLUMN `TotalPositionsAmount` COMMENT 'Sum of all open position amounts (NewAmount) for this CID on this date. Includes all asset classes: CFD, stocks, crypto, futures, margin. Source: open positions (Trade.OpenPositionEndOfDay) + same-day closed positions (History.ClosePositionEndOfDay) minus History.Credit CreditTypeID=13 adjustments. (Tier 2 - SP_Fact_SnapshotEquity_TotalPositionAmount)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_fact_snapshotequity_fromdateid ALTER COLUMN `TotalCash` COMMENT 'Customer''s total cash balance for the day. Computed as: previous day''s TotalCash (from last row in current year) + sum of TotalCashChange from History.ActiveCredit for @dt. This running-balance approach was introduced 2020-06-07 replacing the direct History.Credit.TotalCash read. (Tier 2 - SP_Fact_SnapshotEquity)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_fact_snapshotequity_fromdateid ALTER COLUMN `InProcessCashouts` COMMENT 'Sum of pending withdrawal amounts for this CID that have not yet been finalized (statuses other than 3=Processed, 4=Cancelled, 5,6). Includes partially processed amounts for split-payment withdrawals plus associated fees. Computed by SP_Fact_SnapshotEquity_InProcessCashouts from Billing.Withdraw, History.WithdrawAction, and History.WithdrawToFundingAction. (Tier 2 - SP_Fact_SnapshotEquity_InProcessCashouts)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_fact_snapshotequity_fromdateid ALTER COLUMN `TotalMirrorPositionsAmount` COMMENT 'Sum of position amounts where MirrorID > 0 AND ParentPositionID != 0 (copy-trading positions only, excluding the parent/guru''s own positions). Represents the CID''s total investment in copy relationships. (Tier 2 - SP_Fact_SnapshotEquity_TotalPositionAmount)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_fact_snapshotequity_fromdateid ALTER COLUMN `TotalMirrorCash` COMMENT 'Cash available for copy-trading. Formula: TotalCash - Credit. (Tier 2 - SP_Fact_SnapshotEquity)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_fact_snapshotequity_fromdateid ALTER COLUMN `TotalStockOrders` COMMENT 'Legacy column, hardcoded to 0. Removed 2019-03-03 (Boris Slutski) - no data in PROD since 2015. Kept for schema compatibility. (Tier 2 - SP_Fact_SnapshotEquity)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_fact_snapshotequity_fromdateid ALTER COLUMN `TotalMirrorStockOrders` COMMENT 'Legacy column, hardcoded to 0. Removed 2019-03-03 alongside TotalStockOrders. Kept for schema compatibility. (Tier 2 - SP_Fact_SnapshotEquity)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_fact_snapshotequity_fromdateid ALTER COLUMN `RealizedEquity` COMMENT 'Total account value. If History.ActiveCredit.RealizedEquity is non-zero, taken directly; otherwise computed as TotalCash + TotalPositionsAmount + InProcessCashouts. Confluence definition: "Unrealized Equity - the total funds in the account, including profit/loss from open positions. The Portfolio value figure represented on the platform is Unrealized equity." (Tier 2 - SP_Fact_SnapshotEquity)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_fact_snapshotequity_fromdateid ALTER COLUMN `Credit` COMMENT 'Outstanding credit/bonus balance from History.ActiveCredit. Last credit event per CID per day (selected via ROW_NUMBER partition by CID, ordered by Occurred DESC, CreditID DESC). Negative values represent outstanding obligations. (Tier 2 - SP_Fact_SnapshotEquity)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_fact_snapshotequity_fromdateid ALTER COLUMN `AUM` COMMENT 'Assets Under Management. Formula: TotalMirrorPositionAmount + TotalCash - Credit. For MERGE INSERT: computed as TotalMirrorPositionsAmount + TotalMirrorCash. Confluence: "AUC (or AUM) on PI Dashboard: Total Unrealized Copy Amount of the Copiers." (Tier 2 - SP_Fact_SnapshotEquity)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_fact_snapshotequity_fromdateid ALTER COLUMN `BonusCredit` COMMENT 'Bonus credit balance from History.ActiveCredit.BonusCredit. Confluence: "History.Credit.CreditTypeID = 5, 7 -> BackOffice.BonusType.BonusTypeID -> History.Credit.BonusTypeID". ISNULL to 0 in ETL. (Tier 2 - SP_Fact_SnapshotEquity)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_fact_snapshotequity_fromdateid ALTER COLUMN `CreditID` COMMENT 'Last CreditID for this CID on this date from History.ActiveCredit. Selected as the most recent credit event via ROW_NUMBER(PARTITION BY CID, DateID ORDER BY Occurred DESC, CreditID DESC). Used for auditing which credit record drives the snapshot. (Tier 2 - SP_Fact_SnapshotEquity_DL_To_Synapse)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_fact_snapshotequity_fromdateid ALTER COLUMN `TotalStockPositionAmount` COMMENT 'Sum of position amounts where InstrumentTypeID IN (5,6) AND instrument is NOT a future. Represents CFD and real stock positions (excluding futures that also have InstrumentTypeID 5/6). Added with mutual exclusivity fix (Guy M, 2025-07-29). (Tier 2 - SP_Fact_SnapshotEquity_TotalPositionAmount)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_fact_snapshotequity_fromdateid ALTER COLUMN `TotalMirrorStockPositionAmount` COMMENT 'Mirror (copy-trading) subset of TotalStockPositionAmount. Adds MirrorID > 0 AND ParentPositionID != 0. Same mutual exclusivity fix with futures. (Tier 2 - SP_Fact_SnapshotEquity_TotalPositionAmount)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_fact_snapshotequity_fromdateid ALTER COLUMN `TotalCryptoPositionAmount` COMMENT 'Sum of position amounts where InstrumentTypeID = 10 AND instrument is NOT a future. Represents CFD and real crypto positions. Confluence: "TotalCryptoPositionAmount + TotalStockPositionAmount = TotalPositionsAmount" (approximately, excluding other types). (Tier 2 - SP_Fact_SnapshotEquity_TotalPositionAmount)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_fact_snapshotequity_fromdateid ALTER COLUMN `TotalMirrorCryptoPositionAmount` COMMENT 'Mirror (copy-trading) subset of TotalCryptoPositionAmount. Same conditions plus MirrorID > 0 AND ParentPositionID != 0. (Tier 2 - SP_Fact_SnapshotEquity_TotalPositionAmount)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_fact_snapshotequity_fromdateid ALTER COLUMN `TotalRealStocks` COMMENT 'Sum of position amounts where IsSettled = 1 AND InstrumentTypeID IN (5,6) AND instrument is NOT a future. "Real" means the customer owns the underlying asset (settled/delivered). Updated via IsSettled change tracking from History.PositionChangeLog. (Tier 2 - SP_Fact_SnapshotEquity_TotalPositionAmount)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_fact_snapshotequity_fromdateid ALTER COLUMN `TotalRealCrypto` COMMENT 'Sum of position amounts where IsSettled = 1 AND InstrumentTypeID = 10 AND instrument is NOT a future. Real crypto ownership (settled positions). Updated via IsSettled change tracking. (Tier 2 - SP_Fact_SnapshotEquity_TotalPositionAmount)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_fact_snapshotequity_fromdateid ALTER COLUMN `TotalRealCryptoLoan` COMMENT 'Sum of InitialAmount where IsSettled = 1 AND InstrumentTypeID = 10 AND NOT future AND Leverage = 2. Represents the initial investment in leveraged real crypto positions (the loan portion). Changed from Amount to InitialAmount on 2020-03-25. (Tier 2 - SP_Fact_SnapshotEquity_TotalPositionAmount)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_fact_snapshotequity_fromdateid ALTER COLUMN `TotalCashCalculation` COMMENT 'Parallel computation of TotalCash (same formula: TotalCashPreviousDate + TotalCashChangeAll). Exists as a validation/audit column to cross-check TotalCash. (Tier 2 - SP_Fact_SnapshotEquity)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_fact_snapshotequity_fromdateid ALTER COLUMN `TotalCryptoPositionAmount_TRS` COMMENT 'Sum of crypto position amounts where SettlementTypeID = 2 (TRS - Total Return Swap) AND instrument is NOT a future. Added 2022-01-27 (Inbal BML). TRS positions have different regulatory treatment than settled positions. (Tier 2 - SP_Fact_SnapshotEquity_TotalPositionAmount)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_fact_snapshotequity_fromdateid ALTER COLUMN `TotalMirrorCryptoPositionAmount_TRS` COMMENT 'Mirror (copy-trading) subset of TotalCryptoPositionAmount_TRS. TRS crypto positions in copy relationships. Added 2022-01-27. (Tier 2 - SP_Fact_SnapshotEquity_TotalPositionAmount)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_fact_snapshotequity_fromdateid ALTER COLUMN `Total_TRSCrypto` COMMENT 'Sum of crypto position amounts where IsSettled = 0 AND InstrumentTypeID = 10 AND SettlementTypeID = 2. CFD-style crypto positions under TRS settlement (not yet settled to real ownership). Added 2022-01-27. (Tier 2 - SP_Fact_SnapshotEquity_TotalPositionAmount)';

-- main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities (TABLE, 62 columns)
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `DateID` COMMENT 'Date the correlation was computed for, in YYYYMMDD format. The correlation uses price data from 3 months before this date. (Tier 2 - SP_Dim_Instrument_Correlation_FilterByInstrumentID)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `CID` COMMENT 'Customer ID. Grouping key for all PnL aggregations. FK to Dim_Customer (CID = RealCID). HASH distribution key, part of PK. (Tier 2 - SP_Fact_CustomerUnrealized_PnL)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `PositionPnL` COMMENT 'Total unrealized PnL in USD across all open positions for this CID on this date. Uses V1 formula (PnLInDollars from staging). This is the primary PnL metric. "The difference between Realized Equity and Unrealized Equity is the Position PnL" (Confluence). (Tier 2 - SP_Fact_CustomerUnrealized_PnL)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `CopyPositionPnL` COMMENT 'Unrealized PnL from copy-trading positions only (MirrorID > 0). Includes all asset classes. (Tier 2 - SP_Fact_CustomerUnrealized_PnL)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `StandardDeviation` COMMENT 'Portfolio risk measure: standard deviation of the customer''s weighted portfolio computed from instrument covariance matrix. Only calculated for dates >= 2012-12-31. Formula: √(Σ weight_a × weight_b × covariance). NULL for pre-2013 data. (Tier 2 - SP_Fact_CustomerUnrealized_PnL)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `CommissionOnOpen` COMMENT 'Sum of opening commissions (Commission) across all open positions for this CID. (Tier 2 - SP_Fact_CustomerUnrealized_PnL)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `StocksPositionPnL` COMMENT 'Unrealized PnL from stock positions (InstrumentTypeID IN (5,6) AND NOT futures). Includes both real and CFD stocks, both manual and copy. (Tier 2 - SP_Fact_CustomerUnrealized_PnL)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `MirrorStocksPositionPnL` COMMENT 'Unrealized PnL from copy-trading stock positions (InstrumentTypeID IN (5,6) AND NOT futures AND MirrorID > 0). (Tier 2 - SP_Fact_CustomerUnrealized_PnL)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `CryptoPositionPnL` COMMENT 'Unrealized PnL from all crypto positions (InstrumentTypeID = 10 AND NOT futures). Includes real, CFD, manual, and copy. (Tier 2 - SP_Fact_CustomerUnrealized_PnL)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `ManualCryptoPositionPnL` COMMENT 'Unrealized PnL from manually-opened crypto positions (InstrumentTypeID = 10 AND NOT futures AND MirrorID = 0). (Tier 2 - SP_Fact_CustomerUnrealized_PnL)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `CopyCryptoPositionPnL` COMMENT 'Unrealized PnL from copy-trading crypto positions (InstrumentTypeID = 10 AND NOT futures AND MirrorID > 0). (Tier 2 - SP_Fact_CustomerUnrealized_PnL)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `CopyFundPnL` COMMENT 'Unrealized PnL from positions opened via copy-fund relationships (parent CID had AccountTypeID=9 at the time the copy was opened). Identified via History.BackOfficeCustomer + History.Mirror join. (Tier 2 - SP_Fact_CustomerUnrealized_PnL)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `NOP` COMMENT 'Net Open Position - total signed directional USD exposure across all instruments. Positive = net long, negative = net short. "eToro holding of each instrument" (Confluence). (Tier 2 - SP_Fact_CustomerUnrealized_PnL)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `Notional` COMMENT 'Total absolute USD exposure across all instruments. ABS(NOP) per instrument, then summed. Always >= 0. (Tier 2 - SP_Fact_CustomerUnrealized_PnL)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `NOP_Crypto` COMMENT 'Net Open Position for crypto instruments only (InstrumentTypeID = 10 AND NOT futures). (Tier 2 - SP_Fact_CustomerUnrealized_PnL)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `Notional_Crypto` COMMENT 'Absolute USD exposure for crypto instruments only. (Tier 2 - SP_Fact_CustomerUnrealized_PnL)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `NOP_CFD` COMMENT 'Net Open Position for all CFD positions (IsSettled = 0), all asset classes. (Tier 2 - SP_Fact_CustomerUnrealized_PnL)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `Notional_CFD` COMMENT 'Absolute USD exposure for all CFD positions. (Tier 2 - SP_Fact_CustomerUnrealized_PnL)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `NOP_Crypto_CFD` COMMENT 'Net Open Position for crypto CFD positions (InstrumentTypeID = 10 AND IsSettled = 0). (Tier 2 - SP_Fact_CustomerUnrealized_PnL)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `Notional_Crypto_CFD` COMMENT 'Absolute USD exposure for crypto CFD positions. (Tier 2 - SP_Fact_CustomerUnrealized_PnL)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `PositionPnLStocksReal` COMMENT 'Unrealized PnL from real (settled) stock positions only (IsSettled = 1 AND InstrumentTypeID IN (5,6) AND NOT futures). Uses PnLInDollars. (Tier 2 - SP_Fact_CustomerUnrealized_PnL)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `PositionPnLCryptoReal` COMMENT 'Unrealized PnL from real (settled) crypto positions only (IsSettled = 1 AND InstrumentTypeID = 10 AND NOT futures). Uses PnLInDollars. (Tier 2 - SP_Fact_CustomerUnrealized_PnL)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `CommissionByUnitsCrypto_TRS` COMMENT 'Prorated commission for crypto TRS positions (IsSettled = 0 AND InstrumentTypeID = 10 AND SettlementTypeID = 2). Added 2022-01-27 (Inbal BML). (Tier 2 - SP_Fact_CustomerUnrealized_PnL)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `CopyCryptoPositionPnL_TRS` COMMENT 'Unrealized PnL from copy-trading crypto TRS positions (InstrumentTypeID = 10 AND MirrorID > 0 AND SettlementTypeID = 2). (Tier 2 - SP_Fact_CustomerUnrealized_PnL)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `CryptoPositionPnL_TRS` COMMENT 'Unrealized PnL from all crypto TRS positions (InstrumentTypeID = 10 AND SettlementTypeID = 2). (Tier 2 - SP_Fact_CustomerUnrealized_PnL)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `FullCommissionByUnitsCrypto_TRS` COMMENT 'Full prorated commission for crypto TRS positions (IsSettled = 0 AND InstrumentTypeID = 10 AND SettlementTypeID = 2). (Tier 2 - SP_Fact_CustomerUnrealized_PnL)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `ManualCryptoPositionPnL_TRS` COMMENT 'Unrealized PnL from manually-opened crypto TRS positions (InstrumentTypeID = 10 AND MirrorID = 0 AND SettlementTypeID = 2). (Tier 2 - SP_Fact_CustomerUnrealized_PnL)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `NOP_Crypto_TRS` COMMENT 'Net Open Position for crypto TRS positions (InstrumentTypeID = 10 AND IsSettled = 0 AND SettlementTypeID = 2). (Tier 2 - SP_Fact_CustomerUnrealized_PnL)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `Notional_Crypto_TRS` COMMENT 'Absolute USD exposure for crypto TRS positions. (Tier 2 - SP_Fact_CustomerUnrealized_PnL)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `MirrorRealFuturesPositionPnL` COMMENT 'Unrealized PnL from copy-trading futures positions (IsFuture = 1 AND MirrorID > 0). Uses PnLInDollars. Added 2024-11-10 (Daniel Kaplan). (Tier 2 - SP_Fact_CustomerUnrealized_PnL)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `ManualRealFuturesPositionPnL` COMMENT 'Unrealized PnL from manually-opened futures positions (IsFuture = 1 AND MirrorID = 0). Uses PnLInDollars. Added 2024-11-10. (Tier 2 - SP_Fact_CustomerUnrealized_PnL)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `NOP_FuturesReal` COMMENT 'Net Open Position for futures instruments (IsFuture = 1). Added 2024-11-10. (Tier 2 - SP_Fact_CustomerUnrealized_PnL)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `Notional_FuturesReal` COMMENT 'Absolute USD exposure for futures instruments. Always positive (uses ABS for sell positions). Added 2024-11-10. (Tier 2 - SP_Fact_CustomerUnrealized_PnL)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `PositionPnLFuturesReal` COMMENT 'Total unrealized PnL from all futures positions (IsFuture = 1). Uses PnLInDollars. Added 2024-11-10. (Tier 2 - SP_Fact_CustomerUnrealized_PnL)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `FullCommissionByUnitsFuturesReal` COMMENT 'Full prorated commission for futures positions (IsFuture = 1). Added 2024-11-10. (Tier 2 - SP_Fact_CustomerUnrealized_PnL)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `CommissionByUnitsFuturesReal` COMMENT 'Prorated commission for futures positions (IsFuture = 1). Added 2024-11-10. (Tier 2 - SP_Fact_CustomerUnrealized_PnL)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `NOP_StocksMargin` COMMENT 'Net Open Position for stock margin positions (SettlementTypeID = 5). Added 2025-09-25 (Daniel Kaplan). (Tier 2 - SP_Fact_CustomerUnrealized_PnL)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `PositionPnLStocksMargin` COMMENT 'Unrealized PnL from stock margin positions (SettlementTypeID = 5). Uses PnLInDollars. Added 2025-09-25. (Tier 2 - SP_Fact_CustomerUnrealized_PnL)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `CopyFundAUM` COMMENT 'Total Assets Under Copy: `Cash + Investment + PnL + DetachedPosInvestment + Dit_PnL`. Computed in the SP, not stored at source. This is the headline metric for copy-trading portfolio value. (Tier 2 - SP_Fact_Guru_Copiers)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `RealizedEquity` COMMENT 'Total account value. If History.ActiveCredit.RealizedEquity is non-zero, taken directly; otherwise computed as TotalCash + TotalPositionsAmount + InProcessCashouts. Confluence definition: "Unrealized Equity - the total funds in the account, including profit/loss from open positions. The Portfolio value figure represented on the platform is Unrealized equity." (Tier 2 - SP_Fact_SnapshotEquity)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `TotalPositionsAmount` COMMENT 'Sum of all open position amounts (NewAmount) for this CID on this date. Includes all asset classes: CFD, stocks, crypto, futures, margin. Source: open positions (Trade.OpenPositionEndOfDay) + same-day closed positions (History.ClosePositionEndOfDay) minus History.Credit CreditTypeID=13 adjustments. (Tier 2 - SP_Fact_SnapshotEquity_TotalPositionAmount)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `TotalCash` COMMENT 'Customer''s total cash balance for the day. Computed as: previous day''s TotalCash (from last row in current year) + sum of TotalCashChange from History.ActiveCredit for @dt. This running-balance approach was introduced 2020-06-07 replacing the direct History.Credit.TotalCash read. (Tier 2 - SP_Fact_SnapshotEquity)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `InProcessCashouts` COMMENT 'Sum of pending withdrawal amounts for this CID that have not yet been finalized (statuses other than 3=Processed, 4=Cancelled, 5,6). Includes partially processed amounts for split-payment withdrawals plus associated fees. Computed by SP_Fact_SnapshotEquity_InProcessCashouts from Billing.Withdraw, History.WithdrawAction, and History.WithdrawToFundingAction. (Tier 2 - SP_Fact_SnapshotEquity_InProcessCashouts)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `TotalMirrorPositionsAmount` COMMENT 'Sum of position amounts where MirrorID > 0 AND ParentPositionID != 0 (copy-trading positions only, excluding the parent/guru''s own positions). Represents the CID''s total investment in copy relationships. (Tier 2 - SP_Fact_SnapshotEquity_TotalPositionAmount)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `TotalMirrorCash` COMMENT 'Cash available for copy-trading. Formula: TotalCash - Credit. (Tier 2 - SP_Fact_SnapshotEquity)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `TotalStockOrders` COMMENT 'Legacy column, hardcoded to 0. Removed 2019-03-03 (Boris Slutski) - no data in PROD since 2015. Kept for schema compatibility. (Tier 2 - SP_Fact_SnapshotEquity)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `TotalMirrorStockOrders` COMMENT 'Legacy column, hardcoded to 0. Removed 2019-03-03 alongside TotalStockOrders. Kept for schema compatibility. (Tier 2 - SP_Fact_SnapshotEquity)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `Credit` COMMENT 'Outstanding credit/bonus balance from History.ActiveCredit. Last credit event per CID per day (selected via ROW_NUMBER partition by CID, ordered by Occurred DESC, CreditID DESC). Negative values represent outstanding obligations. (Tier 2 - SP_Fact_SnapshotEquity)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `AUM` COMMENT 'Assets Under Management. Formula: TotalMirrorPositionAmount + TotalCash - Credit. For MERGE INSERT: computed as TotalMirrorPositionsAmount + TotalMirrorCash. Confluence: "AUC (or AUM) on PI Dashboard: Total Unrealized Copy Amount of the Copiers." (Tier 2 - SP_Fact_SnapshotEquity)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `BonusCredit` COMMENT 'Bonus credit balance from History.ActiveCredit.BonusCredit. Confluence: "History.Credit.CreditTypeID = 5, 7 -> BackOffice.BonusType.BonusTypeID -> History.Credit.BonusTypeID". ISNULL to 0 in ETL. (Tier 2 - SP_Fact_SnapshotEquity)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `TotalStockPositionAmount` COMMENT 'Sum of position amounts where InstrumentTypeID IN (5,6) AND instrument is NOT a future. Represents CFD and real stock positions (excluding futures that also have InstrumentTypeID 5/6). Added with mutual exclusivity fix (Guy M, 2025-07-29). (Tier 2 - SP_Fact_SnapshotEquity_TotalPositionAmount)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `TotalMirrorStockPositionAmount` COMMENT 'Mirror (copy-trading) subset of TotalStockPositionAmount. Adds MirrorID > 0 AND ParentPositionID != 0. Same mutual exclusivity fix with futures. (Tier 2 - SP_Fact_SnapshotEquity_TotalPositionAmount)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `TotalCryptoPositionAmount` COMMENT 'Sum of position amounts where InstrumentTypeID = 10 AND instrument is NOT a future. Represents CFD and real crypto positions. Confluence: "TotalCryptoPositionAmount + TotalStockPositionAmount = TotalPositionsAmount" (approximately, excluding other types). (Tier 2 - SP_Fact_SnapshotEquity_TotalPositionAmount)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `TotalRealStocks` COMMENT 'Sum of position amounts where IsSettled = 1 AND InstrumentTypeID IN (5,6) AND instrument is NOT a future. "Real" means the customer owns the underlying asset (settled/delivered). Updated via IsSettled change tracking from History.PositionChangeLog. (Tier 2 - SP_Fact_SnapshotEquity_TotalPositionAmount)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `TotalRealCrypto` COMMENT 'Sum of position amounts where IsSettled = 1 AND InstrumentTypeID = 10 AND instrument is NOT a future. Real crypto ownership (settled positions). Updated via IsSettled change tracking. (Tier 2 - SP_Fact_SnapshotEquity_TotalPositionAmount)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `Total_TRSCrypto` COMMENT 'Sum of crypto position amounts where IsSettled = 0 AND InstrumentTypeID = 10 AND SettlementTypeID = 2. CFD-style crypto positions under TRS settlement (not yet settled to real ownership). Added 2022-01-27. (Tier 2 - SP_Fact_SnapshotEquity_TotalPositionAmount)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `TotalCryptoPositionAmount_TRS` COMMENT 'Sum of crypto position amounts where SettlementTypeID = 2 (TRS - Total Return Swap) AND instrument is NOT a future. Added 2022-01-27 (Inbal BML). TRS positions have different regulatory treatment than settled positions. (Tier 2 - SP_Fact_SnapshotEquity_TotalPositionAmount)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `TotalMirrorRealFuturesPositionAmount` COMMENT 'Sum of futures position amounts where MirrorID > 0. From Dim_Instrument_Snapshot.IsFuture = 1. Added 2024-10-30 (Daniel Kaplan). (Tier 2 - SP_Fact_SnapshotEquity_TotalPositionAmount)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `TotalRealFutures` COMMENT 'Sum of all futures position amounts. Identified via JOIN to Dim_Instrument_Snapshot where IsFuture = 1 for the snapshot DateID. Added 2024-10-30. (Tier 2 - SP_Fact_SnapshotEquity_TotalPositionAmount)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `TotalFuturesProviderMargin` COMMENT 'Sum of provider margin for futures positions: LotCountDecimal × Dim_Instrument_Snapshot.ProviderMarginPerLot. Represents the margin required by the futures provider. Added 2024-10-30. (Tier 2 - SP_Fact_SnapshotEquity_TotalPositionAmount)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `TotalStocksMargin` COMMENT 'Sum of stock margin position amounts where SettlementTypeID = 5. Represents margin-traded stock positions (not fully settled). Added 2025-09-30 (Daniel Kaplan). (Tier 2 - SP_Fact_SnapshotEquity_TotalPositionAmount)';
ALTER TABLE main.dwh.gold_sql_dp_prod_we_dwh_dbo_v_liabilities ALTER COLUMN `TotalStockMarginLoanValue` COMMENT 'Loan value for leveraged stock margin positions: InitForexRate × AmountInUnitsDecimal × InitConversionRate - NewAmount. Only computed when SettlementTypeID = 5 AND Leverage <> 1. Formula updated 2025-12-10 to use InitConversionRate. (Tier 2 - SP_Fact_SnapshotEquity_TotalPositionAmount)';

-- main.emoney.gold_sql_dp_prod_we_emoney_dbo_emoney_customer_risk_assessment (TABLE, 8 columns)
ALTER TABLE main.emoney.gold_sql_dp_prod_we_emoney_dbo_emoney_customer_risk_assessment ALTER COLUMN `GCID` COMMENT 'Global Customer ID. Distribution key and clustered index column. Maps to Dim_Customer.GCID. (Tier 1 - Account.Customer)';
ALTER TABLE main.emoney.gold_sql_dp_prod_we_emoney_dbo_emoney_customer_risk_assessment ALTER COLUMN `IsDepositor` COMMENT 'Whether the customer has ever deposited (1=yes, 0=no). From Dim_Customer.IsDepositor. (Tier 1 - CustomerStatic.IsDepositor)';
ALTER TABLE main.emoney.gold_sql_dp_prod_we_emoney_dbo_emoney_customer_risk_assessment ALTER COLUMN `VerificationLevelID` COMMENT 'KYC verification level. FK to Dictionary.VerificationLevel. Values: 0=unverified (34.2%), 1=partial (12.4%), 2=intermediate (6.2%), 3=fully verified (47.1%). Default=0. (Tier 1 - BackOffice.Customer)';
ALTER TABLE main.emoney.gold_sql_dp_prod_we_emoney_dbo_emoney_customer_risk_assessment ALTER COLUMN `IsValidCustomer` COMMENT 'DWH-computed: 1 when not Popular Investor (PlayerLevelID != 4), not label 30/26, and not CountryID=250. Used in reporting to filter out non-standard customers. (Tier 2 - SP_Dim_Customer)';
ALTER TABLE main.emoney.gold_sql_dp_prod_we_emoney_dbo_emoney_customer_risk_assessment ALTER COLUMN `DocsOK` COMMENT 'Whether required documents are verified. (Tier 2 - SP_Dim_Customer)';
ALTER TABLE main.emoney.gold_sql_dp_prod_we_emoney_dbo_emoney_customer_risk_assessment ALTER COLUMN `IsIDProof` COMMENT 'Whether ID proof document is on file (1/0). (Tier 2 - SP_Dim_Customer)';
ALTER TABLE main.emoney.gold_sql_dp_prod_we_emoney_dbo_emoney_customer_risk_assessment ALTER COLUMN `IsAddressProof` COMMENT 'Whether address proof document is on file (1/0). Updated from BackOffice.CustomerDocument. (Tier 2 - SP_Dim_Customer)';
ALTER TABLE main.emoney.gold_sql_dp_prod_we_emoney_dbo_emoney_customer_risk_assessment ALTER COLUMN `IsPhoneVerified` COMMENT 'Whether phone is verified (VerificationStatusID IN (1,2) -> 1). (Tier 2 - SP_Dim_Customer)';

-- main.emoney.gold_sql_dp_prod_we_emoney_dbo_emoney_customer_risk_assessment_history (TABLE, 8 columns)
ALTER TABLE main.emoney.gold_sql_dp_prod_we_emoney_dbo_emoney_customer_risk_assessment_history ALTER COLUMN `GCID` COMMENT 'Global Customer ID. Distribution key and clustered index column. Maps to Dim_Customer.GCID. (Tier 1 - Account.Customer)';
ALTER TABLE main.emoney.gold_sql_dp_prod_we_emoney_dbo_emoney_customer_risk_assessment_history ALTER COLUMN `IsDepositor` COMMENT 'Whether the customer has ever deposited (1=yes, 0=no). From Dim_Customer.IsDepositor. (Tier 1 - CustomerStatic.IsDepositor)';
ALTER TABLE main.emoney.gold_sql_dp_prod_we_emoney_dbo_emoney_customer_risk_assessment_history ALTER COLUMN `VerificationLevelID` COMMENT 'KYC verification level. FK to Dictionary.VerificationLevel. Values: 0=unverified (34.2%), 1=partial (12.4%), 2=intermediate (6.2%), 3=fully verified (47.1%). Default=0. (Tier 1 - BackOffice.Customer)';
ALTER TABLE main.emoney.gold_sql_dp_prod_we_emoney_dbo_emoney_customer_risk_assessment_history ALTER COLUMN `IsValidCustomer` COMMENT 'DWH-computed: 1 when not Popular Investor (PlayerLevelID != 4), not label 30/26, and not CountryID=250. Used in reporting to filter out non-standard customers. (Tier 2 - SP_Dim_Customer)';
ALTER TABLE main.emoney.gold_sql_dp_prod_we_emoney_dbo_emoney_customer_risk_assessment_history ALTER COLUMN `DocsOK` COMMENT 'Whether required documents are verified. (Tier 2 - SP_Dim_Customer)';
ALTER TABLE main.emoney.gold_sql_dp_prod_we_emoney_dbo_emoney_customer_risk_assessment_history ALTER COLUMN `IsIDProof` COMMENT 'Whether ID proof document is on file (1/0). (Tier 2 - SP_Dim_Customer)';
ALTER TABLE main.emoney.gold_sql_dp_prod_we_emoney_dbo_emoney_customer_risk_assessment_history ALTER COLUMN `IsAddressProof` COMMENT 'Whether address proof document is on file (1/0). Updated from BackOffice.CustomerDocument. (Tier 2 - SP_Dim_Customer)';
ALTER TABLE main.emoney.gold_sql_dp_prod_we_emoney_dbo_emoney_customer_risk_assessment_history ALTER COLUMN `IsPhoneVerified` COMMENT 'Whether phone is verified (VerificationStatusID IN (1,2) -> 1). (Tier 2 - SP_Dim_Customer)';

-- main.etoro_kpi.vg_dealing_clicks_openclose_breakdown (VIEW, 40 columns)
COMMENT ON COLUMN main.etoro_kpi.vg_dealing_clicks_openclose_breakdown.`Date` IS 'Report date. Set to `@Date` SP parameter (typically yesterday). One day''s worth of clicks per load. (Tier 2 - SP_Clicks_OpenClose_Breakdown)';
COMMENT ON COLUMN main.etoro_kpi.vg_dealing_clicks_openclose_breakdown.`DateID` IS 'Date as YYYYMMDD integer. `CAST(CONVERT(VARCHAR(8), @Date, 112) AS INT)`. (Tier 2 - SP_Clicks_OpenClose_Breakdown)';
COMMENT ON COLUMN main.etoro_kpi.vg_dealing_clicks_openclose_breakdown.`SellCurrency` IS 'Text abbreviation of the instrument''s sell-side (denomination) currency. Example: USD, EUR, GBX (GBP pence). DWH-added for query convenience. (Tier 2 - SP_Dim_Instrument)';
COMMENT ON COLUMN main.etoro_kpi.vg_dealing_clicks_openclose_breakdown.`Club` IS 'Player tier name from Dim_PlayerLevel (e.g., Bronze, Silver, Gold, Platinum). Customer''s loyalty/tier level at the snapshot date. (Tier 2 - SP_Clicks_OpenClose_Breakdown)';
COMMENT ON COLUMN main.etoro_kpi.vg_dealing_clicks_openclose_breakdown.`CID` IS 'Customer ID. References Customer.Customer. (Tier 1 - Trade.PositionTbl)';
COMMENT ON COLUMN main.etoro_kpi.vg_dealing_clicks_openclose_breakdown.`IsBuy` IS 'Trade direction. 1=Long (buy), 0=Short (sell). (Tier 1 - Trade.PositionTbl)';
COMMENT ON COLUMN main.etoro_kpi.vg_dealing_clicks_openclose_breakdown.`HeldOnReportDate` IS 'Whether position was still open at end of report date. `CASE WHEN CloseDateID > @DateID OR CloseDateID = 0 THEN 1 ELSE 0 END`. Renamed from IsOpen (SR-325240). Always 0 for close clicks. (Tier 2 - SP_Clicks_OpenClose_Breakdown)';
COMMENT ON COLUMN main.etoro_kpi.vg_dealing_clicks_openclose_breakdown.`HedgeServerID` IS 'Liquidity provider server ID. Identifies which hedge server executed the position. Key servers: 2=JP Morgan legacy, 101=Goldman Sachs, 81=Real Stocks LP. HedgeServerID=35 allows invalid customer inclusion. (Tier 1 - Trade.PositionTbl)';
COMMENT ON COLUMN main.etoro_kpi.vg_dealing_clicks_openclose_breakdown.`InstrumentID` IS 'Instrument identifier. FK to DWH_dbo.Dim_Instrument. (Tier 1 - Trade.PositionTbl)';
COMMENT ON COLUMN main.etoro_kpi.vg_dealing_clicks_openclose_breakdown.`InstrumentDisplayName` IS 'User-facing instrument display name from Trade.InstrumentMetaData. More descriptive than InstrumentName (e.g., ''Apple Inc.'' vs ''Apple''). (Tier 2 - SP_Dim_Instrument, etoro_Trade_InstrumentMetaData)';
COMMENT ON COLUMN main.etoro_kpi.vg_dealing_clicks_openclose_breakdown.`InstrumentName` IS 'Internal instrument name from Trade.Instrument. Renamed from Dim_Instrument.Name. For forex: pair notation (e.g., EUR/USD). For stocks: company name. (Tier 3 - live data, etoro.Trade.GetInstrument)';
COMMENT ON COLUMN main.etoro_kpi.vg_dealing_clicks_openclose_breakdown.`InstrumentTypeID` IS 'Asset class: 1=Currencies, 2=Commodities, 4=Indices, 5=Stocks, 6=ETF, 10=Crypto Currencies. (Tier 2 - SP_Dim_Instrument)';
COMMENT ON COLUMN main.etoro_kpi.vg_dealing_clicks_openclose_breakdown.`InstrumentType` IS 'Text label for InstrumentTypeID. DWH-computed via CASE: 1=Currencies, 2=Commodities, 4=Indices, 5=Stocks, 6=ETF, 10=Crypto Currencies. Use InstrumentTypeID for filtering; InstrumentType for display. (Tier 2 - SP_Dim_Instrument)';
COMMENT ON COLUMN main.etoro_kpi.vg_dealing_clicks_openclose_breakdown.`IsCopy` IS 'Copy-trade flag. `CASE WHEN MirrorID > 0 THEN 1 ELSE 0 END`. 1=position opened via CopyTrader, 0=direct trade. (Tier 2 - SP_Clicks_OpenClose_Breakdown)';
COMMENT ON COLUMN main.etoro_kpi.vg_dealing_clicks_openclose_breakdown.`IsCFD` IS 'CFD vs Real asset flag. `CASE WHEN IsSettled = 1 THEN 0 ELSE 1 END`. 1=CFD (contract for difference), 0=Real stock/crypto ownership. (Tier 2 - SP_Clicks_OpenClose_Breakdown)';
COMMENT ON COLUMN main.etoro_kpi.vg_dealing_clicks_openclose_breakdown.`Symbol` IS 'Ticker symbol for the instrument (e.g., AAPL, EURUSD, BTCUSD). Used for display, search, and price feed identification. (Tier 3 - live data, etoro.Trade.GetInstrument)';
COMMENT ON COLUMN main.etoro_kpi.vg_dealing_clicks_openclose_breakdown.`Leverage` IS 'Position leverage multiplier. 1=unleveraged (real stocks), 2-30=leveraged (CFDs). From Dim_Position.Leverage. (Tier 1 - Trade.PositionTbl)';
COMMENT ON COLUMN main.etoro_kpi.vg_dealing_clicks_openclose_breakdown.`Exchange` IS 'Stock exchange name from Trade.InstrumentMetaData (e.g., Nasdaq, NYSE, LSE). NULL for non-stock instruments. (Tier 3 - live data, etoro_Trade_InstrumentMetaData)';
COMMENT ON COLUMN main.etoro_kpi.vg_dealing_clicks_openclose_breakdown.`CountryID` IS 'Customer''s registered country at snapshot date. FK to Dim_Country. From Fact_SnapshotCustomer via Dim_Country. (Tier 1 - Dictionary.Country upstream wiki)';
COMMENT ON COLUMN main.etoro_kpi.vg_dealing_clicks_openclose_breakdown.`Country` IS 'Country name from Dim_Country.Name. (Tier 1 - Dictionary.Country upstream wiki)';
COMMENT ON COLUMN main.etoro_kpi.vg_dealing_clicks_openclose_breakdown.`Region` IS 'Marketing region manual override. From Dim_Country.MarketingRegionManualName. Examples: Latam, UK, German, CEE, SEA. (Tier 3 - Ext_Dim_Country live data)';
COMMENT ON COLUMN main.etoro_kpi.vg_dealing_clicks_openclose_breakdown.`RegulationID` IS 'Customer''s regulatory jurisdiction at snapshot date. FK to Dim_Regulation. 1=CySEC, 2=FCA, etc. (Tier 2 - SP_Fact_SnapshotCustomer)';
COMMENT ON COLUMN main.etoro_kpi.vg_dealing_clicks_openclose_breakdown.`Regulation` IS 'Regulation name from Dim_Regulation.Name. Examples: CySEC, FCA, ASIC. (Tier 2 - SP_Clicks_OpenClose_Breakdown)';
COMMENT ON COLUMN main.etoro_kpi.vg_dealing_clicks_openclose_breakdown.`IsIslamic` IS 'Islamic (swap-free) account flag. `CASE WHEN WeekendFeePrecentage = 0 THEN 1 ELSE 0 END`. Source: Dim_Customer.WeekendFeePrecentage. (Tier 2 - SP_Clicks_OpenClose_Breakdown)';
COMMENT ON COLUMN main.etoro_kpi.vg_dealing_clicks_openclose_breakdown.`OpenOrClose` IS 'Row type: `''Open Click''` or `''Close Click''`. Literal string set by SP. (Tier 2 - SP_Clicks_OpenClose_Breakdown)';
COMMENT ON COLUMN main.etoro_kpi.vg_dealing_clicks_openclose_breakdown.`OpenOrCloseID` IS 'Row type numeric: 1=Open Click, 0=Close Click. (Tier 2 - SP_Clicks_OpenClose_Breakdown)';
COMMENT ON COLUMN main.etoro_kpi.vg_dealing_clicks_openclose_breakdown.`Click` IS 'Trade event count. `SUM(NumberofPositionsOpened)` for opens (1 per non-partial-close position opened on @Date), `SUM(NumberofPositionsClosed)` for closes. Aggregated in GROUP BY. (Tier 2 - SP_Clicks_OpenClose_Breakdown)';
COMMENT ON COLUMN main.etoro_kpi.vg_dealing_clicks_openclose_breakdown.`Volume` IS 'USD trade volume. For opens: `SUM(CAST(VolumeOpened AS BIGINT))` where VolumeOpened = SUM(Dim_Position.Volume) over OriginalPositionID partition. For closes: `SUM(VolumeClosed)` where VolumeClosed = VolumeOnClose. (Tier 2 - SP_Clicks_OpenClose_Breakdown)';
COMMENT ON COLUMN main.etoro_kpi.vg_dealing_clicks_openclose_breakdown.`Units` IS 'Instrument units traded. For opens: `SUM(InitialUnits)` WHERE OpenDateID=@DateID. For closes: `SUM(AmountInUnitsDecimal)` WHERE CloseDateID=@DateID. (Tier 2 - SP_Clicks_OpenClose_Breakdown)';
COMMENT ON COLUMN main.etoro_kpi.vg_dealing_clicks_openclose_breakdown.`FullCommission` IS 'Commission amount. Opens: `SUM(FullCommissionOnOpenInit)` - accumulated FullCommissionByUnits including partial close children. Closes: `SUM(FullCommissionOnClose)` for same-day opens, `SUM(FullCommissionOnClose - FullCommissionByUnits)` for older positions. (Tier 2 - SP_Clicks_OpenClose_Breakdown)';
COMMENT ON COLUMN main.etoro_kpi.vg_dealing_clicks_openclose_breakdown.`InitialAmountUSDOnOpen` IS 'Initial investment in USD for open clicks only. `SUM(InitialAmountCents/100) WHERE NumberofPositionsOpened=1`. Always 0 for close clicks. (Tier 2 - SP_Clicks_OpenClose_Breakdown)';
COMMENT ON COLUMN main.etoro_kpi.vg_dealing_clicks_openclose_breakdown.`IsPI` IS 'Popular Investor flag. `CASE WHEN GuruStatusID >= 2 THEN 1 ELSE 0 END`. Source: Fact_SnapshotCustomer.GuruStatusID. (Tier 2 - SP_Clicks_OpenClose_Breakdown)';
COMMENT ON COLUMN main.etoro_kpi.vg_dealing_clicks_openclose_breakdown.`IsTicketFee` IS 'Has ticket fee flag. `CASE WHEN Fact_CustomerAction.Amount IS NOT NULL THEN 1 ELSE 0 END`. Ticket fee = ActionTypeID=35 AND IsFeeDividend=4. (Tier 2 - SP_Clicks_OpenClose_Breakdown)';
COMMENT ON COLUMN main.etoro_kpi.vg_dealing_clicks_openclose_breakdown.`TicketFee` IS 'Ticket fee amount. `SUM(Amount)` from Fact_CustomerAction WHERE ActionTypeID=35 AND IsFeeDividend=4 AND DateID=@DateID. Joined on PositionID+OpenOrCloseID. (Tier 2 - SP_Clicks_OpenClose_Breakdown)';
COMMENT ON COLUMN main.etoro_kpi.vg_dealing_clicks_openclose_breakdown.`IsAirDrop` IS 'AirDrop position flag. `CASE WHEN Dim_Position.IsAirDrop = 1 THEN 1 ELSE 0 END`. AirDrop opens are treated separately: zero ticket fees, IsFTDClick always 0. (Tier 2 - SP_Clicks_OpenClose_Breakdown)';
COMMENT ON COLUMN main.etoro_kpi.vg_dealing_clicks_openclose_breakdown.`IsFuture` IS 'Futures instrument flag. Direct from Dim_Instrument.IsFuture. Added SR-308870 (2025-04-07). (Tier 2 - SP_Clicks_OpenClose_Breakdown)';
COMMENT ON COLUMN main.etoro_kpi.vg_dealing_clicks_openclose_breakdown.`HaseMoneyAccount` IS 'Has eMoney account flag (note: intentional typo in column name). `CASE WHEN eMoney_Dim_Account.CID IS NOT NULL THEN 1 ELSE 0 END` WHERE GCID_Unique_Count=1 AND IsValidETM=1. Added SR-346605 (2025-12-07). (Tier 2 - SP_Clicks_OpenClose_Breakdown)';
COMMENT ON COLUMN main.etoro_kpi.vg_dealing_clicks_openclose_breakdown.`IsIBANClick` IS 'IBAN-originated trade flag. Opens: `CASE WHEN BI_DB_Positions_Opened_From_IBAN.PositionID IS NOT NULL THEN 1 ELSE 0 END`. Closes: same with BI_DB_Positions_Closed_To_IBAN. Added SR-346605 (2025-12-07). (Tier 2 - SP_Clicks_OpenClose_Breakdown)';
COMMENT ON COLUMN main.etoro_kpi.vg_dealing_clicks_openclose_breakdown.`IsFTDClick` IS 'First Trade after Deposit flag. `CASE WHEN dp.PositionID = dc.PositionID THEN 1 ELSE 0 END`. dc.PositionID = first non-airdrop position opened after customer''s first deposit date (ROW_NUMBER=1). Always 0 for close clicks and AirDrop opens. Added SR-346605. (Tier 2 - SP_Clicks_OpenClose_Breakdown)';
COMMENT ON COLUMN main.etoro_kpi.vg_dealing_clicks_openclose_breakdown.`IsLowTouch` IS 'Low-touch instrument flag. From Dim_Instrument.OperationMode. Indicates instruments with simplified execution flow. Added SR-346605 (2025-12-07). (Tier 2 - SP_Clicks_OpenClose_Breakdown)';

-- main.etoro_kpi_prep.gold_de_user_dim_ddr_customer_dailystatus_scd (TABLE, 1 columns)
ALTER TABLE main.etoro_kpi_prep.gold_de_user_dim_ddr_customer_dailystatus_scd ALTER COLUMN `RealCID` COMMENT 'Customer ID - platform-internal primary key. Assigned at registration. Unique within etoro DB. Used as the universal customer identifier across all tables. (Tier 1 - Customer.CustomerStatic)';

-- main.etoro_kpi_prep.v_dim_instrument_enriched (VIEW, 45 columns)
COMMENT ON COLUMN main.etoro_kpi_prep.v_dim_instrument_enriched.`InstrumentID` IS 'Primary key identifying the tradeable instrument pair. Allocated by Trade.InstrumentAdd during instrument creation. Ranges from 0 (system placeholder) to ~21 million IDs allocated. Referenced by virtually every trading fact table and the Dim_Currency / Dim_HistorySplitRatio dimension tables. (Tier 1 -- upstream wiki, Trade.Instrument)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_dim_instrument_enriched.`InstrumentTypeID` IS 'Instrument type category: 1=Currencies (forex), 2=Commodities, 4=Indices, 5=Stocks, 6=ETF, 10=Crypto Currencies. Note TypeIDs 3, 7, 8, 9 are unused gaps. Distribution: Stocks 82%, ETF 8%, Crypto 4%, Commodities 3%, Indices 2%, Currencies 1%. (Tier 2 -- SP_Dim_Instrument)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_dim_instrument_enriched.`InstrumentType` IS 'Text label for InstrumentTypeID -- DWH-computed via CASE: 1=Currencies, 2=Commodities, 4=Indices, 5=Stocks, 6=ETF, 10=Crypto Currencies, else=Other. Use InstrumentTypeID for filtering; InstrumentType for display. (Tier 2 -- SP_Dim_Instrument)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_dim_instrument_enriched.`Name` IS 'Instrument name as defined in Trade.Instrument. For forex: pair notation (e.g., EUR/USD). For stocks: company name (e.g., Apple, Alphabet). For crypto: token name. This is the internal instrument name, not necessarily the display name shown to users (see InstrumentDisplayName). (Tier 3 -- live data, etoro.Trade.GetInstrument)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_dim_instrument_enriched.`DWHInstrumentID` IS 'Always equal to InstrumentID -- redundant copy following the DWH DWH{X}ID pattern. Use InstrumentID for all JOINs. (Tier 2 -- SP_Dim_Instrument)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_dim_instrument_enriched.`StatusID` IS 'Hardcoded to 1 for all real rows by SP_Dim_Instrument. NULL only for ID=0 placeholder. Conveys no business information. (Tier 2 -- SP_Dim_Instrument)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_dim_instrument_enriched.`BuyCurrencyID` IS 'The buy-side asset of the instrument pair. FK to DWH_dbo.Dim_Currency(CurrencyID). For forex: the base currency. For stocks/ETFs/crypto: the asset''s own CurrencyID in Dim_Currency (BuyCurrencyID = InstrumentID for stocks). (Tier 1 -- upstream wiki, Trade.Instrument)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_dim_instrument_enriched.`SellCurrencyID` IS 'The sell-side (denomination) currency. FK to DWH_dbo.Dim_Currency(CurrencyID). For forex: the quote currency (e.g., USD in EUR/USD). For stocks: the trading denomination currency (USD, EUR, GBX). Only 67 distinct values since many assets share the same denomination. (Tier 1 -- upstream wiki, Trade.Instrument)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_dim_instrument_enriched.`BuyCurrency` IS 'Text abbreviation of BuyCurrencyID -- denormalized from Dictionary.Currency.Abbreviation via SP JOIN. Example: EUR, AAPL, BTC. DWH-added for query convenience. (Tier 2 -- SP_Dim_Instrument)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_dim_instrument_enriched.`SellCurrency` IS 'Text abbreviation of SellCurrencyID -- denormalized from Dictionary.Currency.Abbreviation. Example: USD, EUR, GBX (GBP pence). DWH-added for query convenience. (Tier 2 -- SP_Dim_Instrument)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_dim_instrument_enriched.`TradeRange` IS 'Allowed trade range in pips for pending orders. Determines how far from market price a limit/stop order can be placed. Set during instrument creation. (Tier 1 -- upstream wiki, Trade.Instrument)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_dim_instrument_enriched.`DollarRatio` IS 'Price scaling factor for USD normalization. Most instruments = 1. JPY pairs = 100 (because JPY is quoted at 100x the numeric value of other currencies). Used in P&L and conversion rate calculations across the platform. (Tier 1 -- upstream wiki, Trade.Instrument)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_dim_instrument_enriched.`PipDifferenceThreshold` IS 'Maximum allowed pip difference threshold for price validation. If a new price deviates more than this threshold from the previous price, it may be flagged as suspicious. NULL for some instruments. (Tier 1 -- upstream wiki, Trade.Instrument)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_dim_instrument_enriched.`IsMajorID` IS 'Integer representation of the production IsMajor flag (0 or 1). 1=major instrument (6,963 instruments -- all major forex pairs and many popular stocks). 0=non-major (8,743 instruments). Renamed from production IsMajor to distinguish from the text version. Use for filtering. (Tier 2 -- SP_Dim_Instrument)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_dim_instrument_enriched.`IsMajor` IS 'Text version of IsMajorID -- DWH CASE computed: IsMajorID=1->''Yes'', 0->''No''. Use for display. Affects spread calculations and regulatory leverage caps (ESMA allows higher leverage for major forex). (Tier 2 -- SP_Dim_Instrument)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_dim_instrument_enriched.`InstrumentDisplayName` IS 'User-facing instrument display name from Trade.InstrumentMetaData. More descriptive than Name (e.g., ''Apple Inc.'' vs ''Apple''). NULL for instruments without metadata entries. (Tier 2 -- SP_Dim_Instrument, etoro_Trade_InstrumentMetaData)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_dim_instrument_enriched.`Industry` IS 'Industry classification string from Trade.InstrumentMetaData. Text description (e.g., ''Internet'', ''Software''). Similar to but may differ from IndustryGroup (Bloomberg). NULL for non-stock instruments or instruments without metadata. (Tier 3 -- live data, etoro_Trade_InstrumentMetaData)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_dim_instrument_enriched.`CompanyInfo` IS 'Free-text company description from Trade.InstrumentMetaData. May contain multi-sentence business descriptions of the company. NULL for non-company instruments (forex, commodities, indices). (Tier 3 -- live data, etoro_Trade_InstrumentMetaData)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_dim_instrument_enriched.`Exchange` IS 'Stock exchange name from Trade.InstrumentMetaData (e.g., Nasdaq, NYSE, LSE). NULL for non-stock instruments. (Tier 3 -- live data, etoro_Trade_InstrumentMetaData)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_dim_instrument_enriched.`ISINCode` IS 'International Securities Identification Number -- 12-character alphanumeric code standardized by ISO 6166 (e.g., US0378331005 for Apple). NULL for forex, commodities, and instruments without ISIN. Country prefix + national code + check digit. (Tier 2 -- SP_Dim_Instrument, etoro_Trade_InstrumentMetaData)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_dim_instrument_enriched.`ISINCountryCode` IS 'Country code prefix from the ISIN (first 2 characters). Indicates the country of registration (e.g., US, DE, GB). NULL when ISINCode is NULL. (Tier 2 -- SP_Dim_Instrument, etoro_Trade_InstrumentMetaData)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_dim_instrument_enriched.`Tradable` IS 'Flag indicating if the instrument is currently tradable: 1=tradable, 0=not tradable. CAST from production bit. NULL for ID=0 placeholder. An instrument may exist but be non-tradable due to regulatory, market, or operational reasons. (Tier 2 -- SP_Dim_Instrument, etoro.Trade.GetInstrument)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_dim_instrument_enriched.`Symbol` IS 'Ticker symbol for the instrument (e.g., AAPL, EURUSD, BTCUSD). Used for display, search, and price feed identification. NULL for ID=0 placeholder and some instruments without formal ticker. (Tier 3 -- live data, etoro.Trade.GetInstrument)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_dim_instrument_enriched.`ReceivedOnPriceServer` IS 'First timestamp when the instrument was observed on the price server (from Ext_Dim_Instrument_ReceivedOnPriceServerStatic). Set once and never updated (static history). NULL for instruments not yet priced or newly added instruments that have not yet appeared in price feeds. (Tier 2 -- SP_Dim_Instrument, post-load UPDATE)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_dim_instrument_enriched.`BonusCreditUsePercent` IS 'Percentage of bonus credit that can be applied to trading this instrument, from Trade.ProviderToInstrument. Lower values restrict bonus usage for high-risk/volatile instruments. NULL for instruments without ProviderToInstrument mapping. (Tier 3 -- live data, etoro_Trade_ProviderToInstrument)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_dim_instrument_enriched.`SymbolFull` IS 'Full ticker symbol (may be longer than Symbol), from Trade.InstrumentMetaData. Used for data provider integrations that require fully qualified symbols. NULL for instruments without metadata. (Tier 3 -- live data, etoro_Trade_InstrumentMetaData)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_dim_instrument_enriched.`CUSIP` IS 'Committee on Uniform Securities Identification Procedures number -- 9-character code for US/Canadian securities. Used for clearing, settlement, and regulatory reporting. NULL for non-US instruments and instruments without CUSIP. (Tier 2 -- SP_Dim_Instrument, etoro_Trade_InstrumentCusip)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_dim_instrument_enriched.`Precision` IS 'Decimal precision for price display and trading (number of decimal places), from Trade.ProviderToInstrument. Determines how many decimals are shown in the UI and used in calculations. NULL for instruments without ProviderToInstrument mapping. (Tier 3 -- live data, etoro_Trade_ProviderToInstrument)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_dim_instrument_enriched.`AllowBuy` IS 'Flag indicating if long (buy) positions can currently be opened: 1=allowed, 0=disabled. Cast from bit. NULL for ID=0 placeholder. Instruments may be buy-disabled due to regulatory restrictions, risk management, or market conditions. (Tier 2 -- SP_Dim_Instrument, etoro.Trade.GetInstrument)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_dim_instrument_enriched.`AllowSell` IS 'Flag indicating if short (sell) positions can currently be opened: 1=allowed, 0=disabled. Cast from bit. NULL for ID=0 placeholder. Many regulated markets prohibit short selling for retail clients. (Tier 2 -- SP_Dim_Instrument, etoro.Trade.GetInstrument)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_dim_instrument_enriched.`AssetClass` IS 'Bloomberg-style asset class classification from Ext_Dim_Instrument_Classification_Static (e.g., Technology, Consumer Services, Finance). More granular than InstrumentType. NULL for non-stock instruments or instruments not in the classification static table. (Tier 2 -- SP_Dim_Instrument, post-load UPDATE)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_dim_instrument_enriched.`IndustryGroup` IS 'Bloomberg-style industry group within AssetClass (e.g., Computers, Internet, Banks). Sub-classification of AssetClass. NULL for non-stock instruments or instruments not in the classification table. (Tier 2 -- SP_Dim_Instrument, post-load UPDATE)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_dim_instrument_enriched.`ADV_Last3Months` IS 'Average Daily Trading Volume over the trailing 3 months (TTM), from Rankings StockInfo MetadataID=8557. In shares/units. NULL for non-stock instruments or instruments without Rankings coverage. Example: Apple ~48M shares/day. (Tier 2 -- SP_Dim_Instrument, Rankings_StockInfo)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_dim_instrument_enriched.`MKTcap` IS 'Market capitalization in USD from Rankings StockInfo (MetadataID=8735 for equities; fallback MetadataID=9315 CryptoMarketCap for crypto). NULL for forex, commodities, and indices. Example: Apple ~3.8T USD. (Tier 2 -- SP_Dim_Instrument, Rankings_StockInfo)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_dim_instrument_enriched.`SharesOutStanding` IS 'Total shares outstanding in units from Rankings StockInfo MetadataID=8444. Annual figure. NULL for non-equity instruments. Example: Apple ~14.7B shares. (Tier 2 -- SP_Dim_Instrument, Rankings_StockInfo)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_dim_instrument_enriched.`VisibleInternallyOnly` IS 'Flag (0/1) indicating if the instrument is visible only to internal eToro users (not shown to retail customers). Cast from bit. Used for instruments under development, testing, or institutional-only. NULL for ID=0 placeholder. (Tier 3 -- live data, etoro.Trade.GetInstrument)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_dim_instrument_enriched.`PlatformSector` IS 'eToro platform sector classification from Rankings StockInfo MetadataID=8436. May differ from Bloomberg AssetClass. NULL for non-equity instruments or instruments without Rankings coverage. (Tier 2 -- SP_Dim_Instrument, Rankings_StockInfo)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_dim_instrument_enriched.`PlatformIndustry` IS 'eToro platform industry classification from Rankings StockInfo MetadataID=8280. More granular than PlatformSector. NULL for non-equity instruments or instruments without Rankings coverage. (Tier 2 -- SP_Dim_Instrument, Rankings_StockInfo)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_dim_instrument_enriched.`IsFuture` IS 'Derived flag indicating if the instrument is a futures contract: 1=futures, 0=not futures. Computed in SP as CASE WHEN InstrumentID IN (SELECT InstrumentID FROM InstrumentGroups WHERE GroupID=25) THEN 1 ELSE 0. NULL for ID=0 placeholder. (Tier 2 -- SP_Dim_Instrument)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_dim_instrument_enriched.`Multiplier` IS 'Futures contract size multiplier from Trade.FuturesMetaData. Determines how many units of the underlying asset one contract represents. NULL for non-futures instruments. (Tier 2 -- SP_Dim_Instrument, etoro_Trade_FuturesMetaData)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_dim_instrument_enriched.`ProviderID` IS 'Liquidity provider identifier from Trade.ProviderToInstrument. Identifies which external market maker or broker provides pricing/liquidity for this instrument. NULL for instruments without a provider mapping. (Tier 3 -- live data, etoro_Trade_ProviderToInstrument)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_dim_instrument_enriched.`ProviderMarginPerLot` IS 'Initial margin requirement per lot in the provider''s terms, from Trade.FuturesInstrumentsInitialMarginByProviderMapping. Primarily relevant for futures instruments. NULL for non-futures or instruments without provider margin data. (Tier 3 -- live data, FuturesInstrumentsInitialMarginByProviderMapping)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_dim_instrument_enriched.`eToroMarginPerLot` IS 'eToro''s own margin requirement per lot in asset currency (InitialMarginInAssetCurrency from Trade.ProviderToInstrument). eToro''s internal margin may differ from the provider''s margin. NULL for instruments without ProviderToInstrument mapping. (Tier 3 -- live data, etoro_Trade_ProviderToInstrument)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_dim_instrument_enriched.`SettlementTime` IS 'Daily or periodic settlement time for the instrument, from Trade.ProviderToInstrument, formatted as TIME via SP DATEPART conversion. Primarily relevant for futures and CFD instruments with defined settlement windows. NULL for instruments without settlement time defined. (Tier 3 -- live data, etoro_Trade_ProviderToInstrument)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_dim_instrument_enriched.`OperationMode` IS 'Trading operation mode: 0=Standard mode (default, ~15,600 instruments), 1=Alternate mode (~83 instruments, primarily European stock CFDs traded in non-USD denomination currencies). Controls how the trading engine processes orders. (Tier 1 -- upstream wiki, Trade.Instrument)';

-- main.etoro_kpi_prep.v_fact_customeraction (VIEW, 70 columns)
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`HistoryID` IS 'Intended as a unique key but contains duplicates - NOT reliable as a primary/unique identifier. Do not use for JOINs, deduplication, or row identification. Has no practical use for analysts. (Tier 5 - domain expert)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`GCID` IS 'Global Customer ID - the platform-wide unique customer identifier. References `Dim_Customer.GCID`. (Tier 1 - Customer.CustomerStatic)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`RealCID` IS 'Real-account Customer ID. HASH distribution key. References `Dim_Customer.RealCID`. Each customer has one real CID. (Tier 1 - Customer.CustomerStatic)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`DemoCID` IS 'Demo-account Customer ID. Always 0 in this table (real accounts only). (Tier 3 - ETL-assigned)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`Occurred` IS 'UTC timestamp when the action occurred. For position opens: when position was opened. For logins: login time. For credits: when the credit was recorded. (Tier 1 - source-dependent)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`IPNumber` IS 'IP address of the customer as a numeric value. Populated for logins and registrations. (Tier 1 - STS/Billing.Login)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`IsReal` IS 'Account type flag. Always 1 in this table (real accounts only). (Tier 3 - ETL-assigned)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`ActionTypeID` IS 'Event type classifier. References `DWH_dbo.Dim_ActionType.ActionTypeID` - JOIN for Name, Category, CategoryID. See Section 2.1 for full mapping. Key filter column - drives which other columns are populated. (Tier 1 - ETL-derived from CreditTypeID/source)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`PlatformTypeID` IS 'Legacy platform type. 0=default (most rows), 99=STS source. Values 1-9 for specific platforms. (Tier 3 - ETL-assigned)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`InstrumentID` IS 'FK to Trade.Instrument. Financial instrument being traded. (Tier 1 - Trade.PositionTbl)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`Amount` IS 'Position size in currency. Must be >= 0. Stored in dollars (PositionOpen divides by 100 from cents). (Tier 1 - Trade.PositionTbl)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`Leverage` IS 'Leverage multiplier (1, 5, 10, etc.). Determines margin and settlement type. (Tier 1 - Trade.PositionTbl)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`NetProfit` IS 'Realized PnL. 0 when open; set on close. In position currency. (Tier 1 - Trade.PositionTbl)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`Commission` IS 'Open commission in dollars. PositionOpen stores @Commission/100 (cents to dollars). (Tier 1 - Trade.PositionTbl)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`PositionID` IS 'Primary key. Allocated by Internal.GetPositionID_Bigint. Unique per position. (Tier 1 - Trade.PositionTbl)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`CampaignID` IS 'Marketing campaign identifier. 0 if not campaign-related. References `DWH_dbo.Dim_Campaign.CampaignID` - JOIN for Code, Description, StartDate, EndDate, MaxBonusAmount, IsActive. (Tier 5 - domain expert)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`BonusTypeID` IS 'Bonus type for bonus events (ActionTypeID=9). 0 for non-bonus events. References `DWH_dbo.Dim_BonusType.BonusTypeID` - JOIN for Name, IsWithdrawable, IsActive. (Tier 5 - domain expert)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`FundingTypeID` IS 'Payment method used for deposits/withdrawals. 0 for non-deposit events. References `DWH_dbo.Dim_FundingType.FundingTypeID` - JOIN for Name, IsNewStyle, IsSingleFunding, IsCashoutActive. (Tier 5 - domain expert)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`LoginID` IS 'Login session identifier from `Billing.Login`. 0 for non-login events. (Tier 1 - Billing.Login)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`MirrorID` IS 'FK to Trade.Mirror. 0/NULL = manual. Positive = copy-trade position. (Tier 1 - Trade.PositionTbl)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`WithdrawID` IS 'Withdrawal request ID for cashout events. 0 for non-cashout events. (Tier 1 - History.Credit)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`DurationInSeconds` IS 'Duration of a login session in seconds. NULL for non-login events. (Tier 1 - Billing.Login)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`PostID` IS 'Social post/comment GUID for social engagement events (ActionTypeID 21-26). NULL for non-social events. (Tier 1 - Social platform)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`CaseID` IS 'CRM case identifier for ActionTypeID=31 (Open CRM Case). 0 otherwise. (Tier 1 - CRM)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`DateID` IS 'Date of the action as integer YYYYMMDD. Derived from `Occurred`. Part of nonclustered indexes. (Tier 2 - ETL-computed)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`TimeID` IS 'Hour of the action (0-23). Derived from `DATEPART(HOUR, Occurred)`. (Tier 2 - ETL-computed)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`StatusID` IS 'Row status. Nearly always 1 (active). NULL for ~2M rows. (Tier 3 - ETL-assigned)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`PreviousOccurred` IS 'Deprecated/unused column. NULL for most rows - not reliably populated. Do not use. (Tier 5 - domain expert)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`CompensationReasonID` IS 'Compensation reason for compensation events (ActionTypeID=36) and position opens (for airdrop identification). References `BackOffice.CompensationReason`. 0 for non-compensation events. (Tier 1 - History.Credit, updated 2025-12-21)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`WithdrawPaymentID` IS 'Payment processing ID for cashout/withdrawal events. 0 for non-cashout events. Used to deduplicate WithdrawProcessingID rows in the ETL. (Tier 1 - History.Credit)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`CommissionOnClose` IS 'Commission charged on close. DWH note: adjusted by SP_Dim_Position when position is reopened; CommissionOnCloseOrig stores the pre-adjustment value. (Tier 1 - Trade.PositionTbl)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`IsPlug` IS 'Deprecated/unused column. Always NULL. (Tier 5 - domain expert)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`DepositID` IS 'Deposit transaction identifier. NULL for non-deposit events. (Tier 1 - History.Credit)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`PostRootID` IS 'Root post ID for social engagement events. NULL for non-social events. (Tier 1 - Social platform)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`FullCommission` IS 'Full commission including spread. PositionOpen stores @FullCommission/100. (Tier 1 - Trade.PositionTbl)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`FullCommissionOnClose` IS 'Full commission on close. DWH note: adjusted by SP_Dim_Position when position is reopened; FullCommissionOnCloseOrig stores the pre-adjustment value. (Tier 1 - Trade.PositionTbl)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`RedeemID` IS 'Billing.Redeem reference when position closed via redeem. (Tier 1 - Trade.PositionTbl)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`RedeemStatus` IS 'Redemption state. Billing.Redeem integration. (Tier 1 - Trade.PositionTbl)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`SessionID` IS 'STS session identifier for logins and position opens. For manual opens: from login session. For copy opens: from mirror session. NULL for other events. (Tier 1 - STS)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`IsRedeem` IS 'Redeem flag. 0=not a redeem, 1=is a redeem. NULL for non-position events. Same meaning as `Dim_Position.IsRedeem` (via RedeemStatus mapping). (Tier 3 - ETL-derived)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`RegulationIDOnOpen` IS 'Regulatory jurisdiction ID at time of position open. ETL-computed via JOIN to etoro_History_BackOfficeCustomer (customer''s regulation history). ISNULL(..., 0) when no regulation match found. (Tier 2 - SP_Dim_Position_DL_To_Synapse)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`PlatformID` IS 'Product/platform identifier - badly named, actually references `Dim_Product.ProductID` (not a standalone platform enum). Resolves to Product, Platform, and SubPlatform via JOIN to `DWH_dbo.Dim_Product`. Only populated for ActionTypeID=14 (logins) and 41 (registrations). (Tier 5 - domain expert)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`ReopenForPositionID` IS 'When position was reopened: references the erroneously closed PositionID. (Tier 1 - Trade.PositionTbl)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`IsReOpen` IS '1=this position was reopened from ReopenForPositionID. ETL-computed: CASE WHEN ReopenForPositionID IS NOT NULL THEN 1. Default 0. (Tier 2 - SP_Dim_Position_DL_To_Synapse)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`CommissionOnCloseOrig` IS 'Original CommissionOnClose before reopen adjustments. ETL: CASE WHEN ReopenForPositionID IS NOT NULL THEN CommissionOnClose ELSE 0. (Tier 2 - SP_Dim_Position_DL_To_Synapse)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`FullCommissionOnCloseOrig` IS 'Original FullCommissionOnClose before reopen. ETL default 0. (Tier 2 - SP_Dim_Position_DL_To_Synapse)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`OriginalPositionID` IS 'Original position ID for positions split by partial close. (Tier 2 - SP_Dim_Position_DL_To_Synapse)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`IsPartialCloseParent` IS '1=this position was partially closed (is the parent in a partial close event). (Tier 2 - SP_Dim_Position_DL_To_Synapse)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`IsPartialCloseChild` IS '1=this position is the child (remainder) of a partial close event. Generally filter out child positions from most metrics on OPEN when aggregating, but not all (e.g., volume is already pro-rated so excluding these is wrong). NEVER filter these out on CLOSE. (Tier 5 — domain expert, SP_Dim_Position_DL_To_Synapse)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`InitialUnits` IS 'Original unit count at open. Used for partial close ratio. (Tier 1 - Trade.PositionTbl)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`PaymentStatusID` IS 'Payment processing status for deposit/cashout events. NULL for non-payment events. References `DWH_dbo.Dim_PaymentStatus.PaymentStatusID` - JOIN for Name. (Tier 5 - domain expert)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`IsDiscounted` IS '1=position received a discounted rate. DWH note: CAST from bit to int. (Tier 1 - Trade.PositionTbl)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`IsSettled` IS '1 = real asset, 0 = CFD asset. (Tier 5 - Expert Review)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`CommissionByUnits` IS 'Prorated commission for partial close. Formula: (AmountInUnitsDecimal / InitialUnits) * Commission. Used for partial-close PnL. (Tier 1 - Trade.Position)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`FullCommissionByUnits` IS 'Prorated full commission for partial close. Same proration formula as CommissionByUnits applied to FullCommission. (Tier 1 - Trade.Position)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`IsFTD` IS 'First-Time Deposit flag: 1 = this is the customer''s first deposit. NULL for non-deposit events. (Tier 2 - ETL-computed)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`CountryIDByIP` IS 'Country determined by IP geolocation. Populated for logins and registrations. References `DWH_dbo.Dim_Country.CountryID` - JOIN for country name. Also see `DWH_dbo.Dim_CountryIP` for IP-to-country resolution. (Tier 5 - domain expert)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`IsAnonymousIP` IS 'Anonymous IP flag: 1 = connection via anonymous proxy/VPN. NULL for most rows. (Tier 1 - IP geolocation)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`ProxyType` IS 'Proxy classification: DCH=datacenter, VPN=VPN, PUB=public proxy, SES=session proxy, TOR=Tor exit node, WEB=web proxy. NULL for non-proxy connections. (Tier 1 - STS)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`IsFeeDividend` IS 'Fee sub-type for ActionTypeID=35: 1=overnight/weekend fee, 2=dividend, 3=SDRT, 4=ticket fees (OpenTotalFees/CloseTotalFees). NULL for non-fee events. See Section 2.2 and DSM-1463. (Tier 2 - ETL-derived from Description)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`IsAirDrop` IS '1=position was created via an airdrop event (crypto). ETL-computed: JOIN to etoro_Trade_PositionAirdropLog. NULL=not an airdrop. (Tier 2 - SP_Dim_Position_DL_To_Synapse)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`DividendID` IS 'Dividend event identifier for dividend-related fees. NULL for non-dividend events. (Tier 1 - Trade positions)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`MoveMoneyReasonID` IS 'Reason for money movement: 1=Adjustment, 5=InternalTransfer Trade, 6=InternalTransfer, 8=Recurring Deposit, 9=Recurring Investment. References `Dictionary.MoveMoneyReason`. (Tier 1 - History.Credit)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`SettlementTypeID` IS 'Modern settlement classification. Dictionary.SettlementTypes: 0=CFD, 1=REAL, 2=TRS, 3=CMT, 4=REAL_FUTURES, 5=MARGIN_TRADE. Replaces IsSettled. (Tier 1 - Trade.PositionTbl)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`DLTOpen` IS 'DLT flag at open. Added 2024-06-02 (Ofir A). (Tier 2 - SP_Dim_Position_DL_To_Synapse)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`DLTClose` IS 'DLT flag at close. Added 2024-06-02. NULL for open positions and older positions. (Tier 2 - SP_Dim_Position_DL_To_Synapse)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`OpenMarkupByUnits` IS 'Prorated open markup for partial close. Formula: OpenMarkup * AmountInUnitsDecimal / InitialUnits. (Tier 1 - Trade.Position)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`Description` IS 'Human-readable description. Populated mainly for ActionTypeID=35 (fees): "Over night fee", "Payment caused by dividend", "Weekend fee", "OpenTotalFees", "CloseTotalFees", "SDRT Charge". For ActionTypeID=32: "edit stop loss by customer". For deposits: "Processed By eToro.Payments.Deposit", etc. (Tier 1 - History.Credit, added 2024-08)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`IsBuy` IS '1 = Long/Buy (profit when price rises), 0 = Short/Sell. (Tier 1 - Trade.PositionTbl)';
COMMENT ON COLUMN main.etoro_kpi_prep.v_fact_customeraction.`CreditID` IS 'Reference to the source `History.Credit.CreditID`. Enables join back to credit history for audit. (Tier 1 - History.Credit, added 2025-07)';

