ALTER TABLE main.trading.gold_sql_dp_prod_we_dealing_dbo_dealing_employees_report ALTER COLUMN `InitForexRate` COMMENT 'Open rate; split-adjusted in SP when position spans a split. (Tier 2 -- SP_PositionPnL, DWH_dbo.Dim_Position.InitForexRate / split logic)';
ALTER TABLE main.trading.gold_sql_dp_prod_we_dealing_dbo_dealing_employees_report ALTER COLUMN `Price` COMMENT 'Per-unit price-move expression × USD conversion factor from `#Pre_UnrealizedPnL` (bid/ask vs InitForexRate and instrument FX chain). (Tier 2 -- SP_PositionPnL, computed from #OpenPositions + Dim_Instrument + #Prices)';
ALTER TABLE main.trading.gold_sql_dp_prod_we_dealing_dbo_dealing_employees_report ALTER COLUMN `RateBid` COMMENT 'EOD bid from latest `Fact_CurrencyPriceWithSplit` row before `@ReportDate`, split-adjusted; uses `BidLastWithoutSpread` when discounted. (Tier 2 -- SP_PositionPnL, DWH_dbo.Fact_CurrencyPriceWithSplit + split)';
ALTER TABLE main.trading.gold_sql_dp_prod_we_dealing_dbo_dealing_employees_report ALTER COLUMN `RateAsk` COMMENT 'EOD ask from same price row, split-adjusted. (Tier 2 -- SP_PositionPnL, DWH_dbo.Fact_CurrencyPriceWithSplit + split)';
ALTER TABLE main.trading.gold_sql_dp_prod_we_dealing_dbo_dealing_employees_report ALTER COLUMN `CountryID` COMMENT 'Country of residence. FK to Dictionary.Country. Determines regulatory framework, available instruments, and leverage limits. Default=0. (Tier 1 - Customer.CustomerStatic)';
ALTER TABLE main.trading.gold_sql_dp_prod_we_dealing_dbo_dealing_employees_report ALTER COLUMN `InstrumentType` COMMENT 'Text label for InstrumentTypeID -- DWH-computed via CASE: 1=Currencies, 2=Commodities, 4=Indices, 5=Stocks, 6=ETF, 10=Crypto Currencies, else=Other. Use InstrumentTypeID for filtering; InstrumentType for display. (Tier 2 -- SP_Dim_Instrument)';
ALTER TABLE main.trading.gold_sql_dp_prod_we_dealing_dbo_dealing_employees_report ALTER COLUMN `Symbol` COMMENT 'Ticker symbol for the instrument (e.g., AAPL, EURUSD, BTCUSD). Used for display, search, and price feed identification. NULL for ID=0 placeholder and some instruments without formal ticker. (Tier 3 -- live data, etoro.Trade.GetInstrument)';
ALTER TABLE main.trading.gold_sql_dp_prod_we_dealing_dbo_dealing_employees_report ALTER COLUMN `Exchange` COMMENT 'Stock exchange name from Trade.InstrumentMetaData (e.g., Nasdaq, NYSE, LSE). NULL for non-stock instruments. (Tier 3 -- live data, etoro_Trade_InstrumentMetaData)';
ALTER TABLE main.trading.gold_sql_dp_prod_we_dealing_dbo_dealing_employees_report ALTER COLUMN `CopyPositionPnL` COMMENT 'Unrealized PnL from copy-trading positions only (MirrorID > 0). Includes all asset classes. (Tier 2 - SP_Fact_CustomerUnrealized_PnL)';
ALTER TABLE main.trading.gold_sql_dp_prod_we_dealing_dbo_dealing_employees_report ALTER COLUMN `BonusCredit` COMMENT 'Bonus credit balance from History.ActiveCredit.BonusCredit. Confluence: "History.Credit.CreditTypeID = 5, 7 -> BackOffice.BonusType.BonusTypeID -> History.Credit.BonusTypeID". ISNULL to 0 in ETL. (Tier 2 - SP_Fact_SnapshotEquity)';
ALTER TABLE main.trading.gold_sql_dp_prod_we_dealing_dbo_dealing_employees_report ALTER COLUMN `RealizedEquity` COMMENT 'Total account value. If History.ActiveCredit.RealizedEquity is non-zero, taken directly; otherwise computed as TotalCash + TotalPositionsAmount + InProcessCashouts. Confluence definition: "Unrealized Equity - the total funds in the account, including profit/loss from open positions. The Portfolio value figure represented on the platform is Unrealized equity." (Tier 2 - SP_Fact_SnapshotEquity)';
ALTER TABLE main.trading.gold_sql_dp_prod_we_dealing_dbo_dealing_employees_report ALTER COLUMN `TotalPositionsAmount` COMMENT 'Sum of all open position amounts (NewAmount) for this CID on this date. Includes all asset classes: CFD, stocks, crypto, futures, margin. Source: open positions (Trade.OpenPositionEndOfDay) + same-day closed positions (History.ClosePositionEndOfDay) minus History.Credit CreditTypeID=13 adjustments. (Tier 2 - SP_Fact_SnapshotEquity_TotalPositionAmount)';
ALTER TABLE main.trading.gold_sql_dp_prod_we_dealing_dbo_dealing_employees_report ALTER COLUMN `TotalCash` COMMENT 'Customer''s total cash balance for the day. Computed as: previous day''s TotalCash (from last row in current year) + sum of TotalCashChange from History.ActiveCredit for @dt. This running-balance approach was introduced 2020-06-07 replacing the direct History.Credit.TotalCash read. (Tier 2 - SP_Fact_SnapshotEquity)';
ALTER TABLE main.trading.gold_sql_dp_prod_we_dealing_dbo_dealing_employees_report ALTER COLUMN `TotalMirrorPositionsAmount` COMMENT 'Sum of position amounts where MirrorID > 0 AND ParentPositionID != 0 (copy-trading positions only, excluding the parent/guru''s own positions). Represents the CID''s total investment in copy relationships. (Tier 2 - SP_Fact_SnapshotEquity_TotalPositionAmount)';
ALTER TABLE main.trading.gold_sql_dp_prod_we_dealing_dbo_dealing_employees_report ALTER COLUMN `TotalMirrorCash` COMMENT 'Cash available for copy-trading. Formula: TotalCash - Credit. (Tier 2 - SP_Fact_SnapshotEquity)';
ALTER TABLE main.trading.gold_sql_dp_prod_we_dealing_dbo_dealing_employees_report ALTER COLUMN `Credit` COMMENT 'Outstanding credit/bonus balance from History.ActiveCredit. Last credit event per CID per day (selected via ROW_NUMBER partition by CID, ordered by Occurred DESC, CreditID DESC). Negative values represent outstanding obligations. (Tier 2 - SP_Fact_SnapshotEquity)';
